import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { discoveryApi } from "../discovery/api";
import { Button, Card, CardContent, CardHeader, CardTitle, Badge, Separator, Skeleton } from "@/shared/components/ui";
import { ArrowLeft, Calendar, DollarSign, Monitor, User, Check, X } from "lucide-react";
import { useToast } from "@/shared/hooks/use-toast";
import { KYCBlocker, useKYCStatus } from "@/shared/components/custom/KYCBlocker";

export const InvitationDetailsPage = () => {
    const { id } = useParams<{ id: string }>(); // Invitation ID
    const navigate = useNavigate();
    const { toast } = useToast();
    
    const [invitation, setInvitation] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [kycStatus, setKycStatus] = useState<string | null>(null);
    const { checkKycStatus } = useKYCStatus();

    useEffect(() => {
        checkKycStatus().then(setKycStatus);
        
        const loadInvitation = async () => {
             try {
                // Since we don't have a direct GET /invitation/:id, we fetch all and find.
                // Improvement: Add specific endpoint.
                const all = await discoveryApi.getMyInvitations();
                const found = all.find((i: any) => i.id === id);
                if (found) {
                    setInvitation(found);
                } else {
                    // Handle not found
                }
             } catch (e) {
                 console.error(e);
             } finally {
                 setIsLoading(false);
             }
        };
        loadInvitation();
    }, [id]);

    const handleRespond = async (status: 'ACCEPTED' | 'REJECTED') => {
        if (!invitation) return;
        
        // Check KYC before accepting
        if (status === 'ACCEPTED' && kycStatus !== 'APPROVED') {
            toast({
                title: "KYC Verification Required",
                description: "Please complete KYC verification to accept invitations.",
                variant: "destructive",
            });
            return;
        }
        
        try {
            await discoveryApi.respondToInvitation(invitation.id, status);
            toast({
                title: status === 'ACCEPTED' ? "Invitation Accepted" : "Invitation Denied",
                description: status === 'ACCEPTED' ? "You have joined the project negotiation." : "Invitation has been removed.",
                variant: status === 'ACCEPTED' ? "default" : "destructive",
            });
            navigate('/dashboard/invitations');
        } catch (error) {
            toast({
                title: "Error",
                description: "Failed to update invitation status.",
                variant: "destructive",
            });
        }
    };

    if (isLoading) return <div className="container p-10 space-y-4"><Skeleton className="h-8 w-1/3" /><Skeleton className="h-64 w-full" /></div>;
    
    // Show KYC blocker if not approved
    if (kycStatus && kycStatus !== 'APPROVED') {
        return (
            <KYCBlocker 
                kycStatus={kycStatus} 
                role="freelancer" 
                action="accept project invitations"
            />
        );
    }
    
    if (!invitation) return <div className="container p-10">Invitation not found.</div>;

    const { request } = invitation;

    return (
        <div className="container mx-auto p-6 max-w-4xl space-y-6">
            <Button variant="ghost" onClick={() => navigate('/dashboard/invitations')} className="gap-2 pl-0">
                <ArrowLeft className="w-4 h-4" /> Back to Invitations
            </Button>

            <div className="flex flex-col md:flex-row gap-6">
                <div className="flex-1 space-y-6">
                    <Card>
                        <CardHeader>
                            <div className="flex justify-between items-start">
                                <div>
                                    <CardTitle className="text-2xl">{request.title}</CardTitle>
                                    <div className="flex items-center gap-2 mt-2 text-muted-foreground">
                                        <Badge variant="secondary">{request.status.replace("_", " ")}</Badge>
                                        <span className="text-sm border-l pl-2 ml-2">Posted {new Date(request.createdAt).toLocaleDateString()}</span>
                                    </div>
                                </div>
                            </div>
                        </CardHeader>
                        <CardContent className="space-y-6">
                             <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <span className="text-sm text-muted-foreground flex items-center gap-2">
                                        <DollarSign className="w-4 h-4" /> Budget
                                    </span>
                                    <p className="font-medium">{request.budgetRange}</p>
                                </div>
                                <div className="space-y-1">
                                    <span className="text-sm text-muted-foreground flex items-center gap-2">
                                        <Calendar className="w-4 h-4" /> Timeline
                                    </span>
                                    <p className="font-medium">{request.intendedTimeline}</p>
                                </div>
                                <div className="space-y-1 col-span-2">
                                    <span className="text-sm text-muted-foreground flex items-center gap-2">
                                        <Monitor className="w-4 h-4" /> Tech Stack
                                    </span>
                                    <p className="font-medium">{request.techPreferences}</p>
                                </div>
                             </div>

                             <Separator />

                             <div>
                                <h3 className="font-semibold mb-2">Description</h3>
                                <p className="text-muted-foreground leading-relaxed whitespace-pre-wrap">{request.description}</p>
                             </div>

                             {invitation.coverLetter && (
                                <div className="bg-muted/30 p-4 rounded-lg border">
                                    <h3 className="font-semibold text-sm mb-1 flex items-center gap-2">
                                        <MailIcon className="w-4 h-4" /> Message from Client
                                    </h3>
                                    <p className="text-sm italic text-muted-foreground">"{invitation.coverLetter}"</p>
                                </div>
                             )}
                        </CardContent>
                    </Card>
                </div>

                <div className="md:w-80 space-y-6">
                    <Card>
                        <CardHeader>
                            <CardTitle className="text-lg">Action Required</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-3">
                            <p className="text-sm text-muted-foreground">
                                You have been invited to apply for this project. Accepting will move you to the candidate list.
                            </p>
                            <Button className="w-full bg-green-600 hover:bg-green-700 gap-2" onClick={() => handleRespond('ACCEPTED')}>
                                <Check className="w-4 h-4" /> Accept Invitation
                            </Button>
                            <Button variant="outline" className="w-full text-destructive hover:bg-destructive/10 border-destructive/20 gap-2" onClick={() => handleRespond('REJECTED')}>
                                <X className="w-4 h-4" /> Deny
                            </Button>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardContent className="p-6">
                            <div className="flex items-center gap-4">
                                <div className="h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xl">
                                    {request.client?.fullName.substring(0,1)}
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Client</p>
                                    <p className="font-semibold">{request.client?.fullName}</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
};

function MailIcon(props: any) {
    return (
      <svg
        {...props}
        xmlns="http://www.w3.org/2000/svg"
        width="24"
        height="24"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <rect width="20" height="16" x="2" y="4" rx="2" />
        <path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7" />
      </svg>
    )
}

import { useState, useEffect } from "react";
import { discoveryApi } from "../discovery/api";
import { InvitationCard } from "./components/InvitationCard";
import { Button, Card, CardContent } from "@/shared/components/ui";
import { Loader2 } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { KYCBlocker, useKYCStatus } from "@/shared/components/custom/KYCBlocker";

export const MyInvitationsPage = () => {
    const [invitations, setInvitations] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [kycStatus, setKycStatus] = useState<string | null>(null);
    const navigate = useNavigate();
    const { checkKycStatus } = useKYCStatus();

    const fetchInvitations = async () => {
        try {
            const data = await discoveryApi.getMyInvitations();
            setInvitations(data);
        } catch (error) {
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchInvitations();
        checkKycStatus().then(setKycStatus);
    }, []);

    const handleRespond = async (id: string, status: 'ACCEPTED' | 'REJECTED') => {
        // Check KYC before accepting
        if (status === 'ACCEPTED' && kycStatus !== 'APPROVED') {
            toast.error("KYC Verification Required", {
                description: "Please complete KYC verification to accept invitations."
            });
            return;
        }
        
        try {
            await discoveryApi.respondToInvitation(id, status);
            if (status === 'ACCEPTED') {
                toast.success("Invitation Accepted", {
                    description: "You have joined the project negotiation."
                });
            } else {
                toast.info("Invitation Denied", {
                    description: "Invitation has been removed."
                });
            }
            // Refresh list
            fetchInvitations();
        } catch (error) {
            toast.error("Error", {
                description: "Failed to update invitation status."
            });
        }
    };

    if (isLoading) return <div className="p-10 flex justify-center"><Loader2 className="animate-spin w-8 h-8" /></div>;

    // Show KYC blocker if not approved
    if (kycStatus && kycStatus !== 'APPROVED') {
        return (
            <KYCBlocker 
                kycStatus={kycStatus} 
                role="freelancer" 
                action="accept project invitations"
            />
        );
    }

    return (
        <div className="container mx-auto p-6 max-w-5xl space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold">My Invitations</h1>
            </div>

            {invitations.length === 0 ? (
                <Card>
                    <CardContent className="p-10 text-center space-y-4">
                        <div className="text-muted-foreground">You have no pending invitations.</div>
                        <Button variant="outline" onClick={() => navigate('/client/discovery')}>
                            Browse Marketplace
                        </Button>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-4">
                    {invitations.map((invitation) => (
                        <InvitationCard 
                            key={invitation.id} 
                            invitation={invitation} 
                            onAccept={() => handleRespond(invitation.id, 'ACCEPTED')}
                            onReject={() => handleRespond(invitation.id, 'REJECTED')}
                        />
                    ))}
                </div>
            )}
        </div>
    );
};

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  Eye,
  Ban,
  CheckCircle,
  Search,
  Loader2,
  AlertTriangle,
  Clock,
  SlidersHorizontal,
  X,
  Sparkles,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { DisputeComplexityBadge } from "./DisputeComplexityBadge";
import {
  DisputeCategory,
  DisputePriority,
  DisputeStatus,
  UserRole,
} from "../../../staff/types/staff.types";
import {
  acceptDispute,
  completeDisputePreview,
  escalateDispute,
  getDisputeComplexities,
  getDisputes,
  invalidateDisputesCache,
  rejectDispute,
  requestDisputeInfo,
} from "../../api";
import type {
  DisputeComplexity,
  DisputeSummary,
  PaginatedDisputesResponse,
} from "../../types/dispute.types";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/shared/components/ui/dialog";
import { useStaffDashboardRealtime } from "@/features/staff/hooks/useStaffDashboardRealtime";
import { STORAGE_KEYS } from "@/constants";
import { getStoredJson } from "@/shared/utils/storage";

interface StaffDisputeBoardProps {
  mode?: "queue" | "caseload";
}

export const StaffDisputeBoard = ({
  mode = "queue",
}: StaffDisputeBoardProps) => {
  const navigate = useNavigate();
  const currentUser = useMemo(() => {
    return getStoredJson<{ id?: string; role?: UserRole }>(STORAGE_KEYS.USER);
  }, []);
  const isStaffUser = currentUser?.role === UserRole.STAFF;
  const [disputes, setDisputes] = useState<DisputeSummary[]>([]);
  const [meta, setMeta] = useState<PaginatedDisputesResponse["meta"] | null>(
    null,
  );
  const [stats, setStats] = useState<PaginatedDisputesResponse["stats"] | null>(
    null,
  );
  const [loading, setLoading] = useState(false);
  const [searchValue, setSearchValue] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  type ViewFilter =
    | "ACTIVE"
    | "PENDING_REVIEW"
    | "APPEALS"
    | "RESOLVED"
    | "ALL";
  const [viewFilter, setViewFilter] = useState<ViewFilter>("ACTIVE");
  const [priorityFilter, setPriorityFilter] = useState<DisputePriority | "ALL">(
    "ALL",
  );
  const [categoryFilter, setCategoryFilter] = useState<DisputeCategory | "ALL">(
    "ALL",
  );
  const [weekFilter, setWeekFilter] = useState<
    "ANY" | "THIS_WEEK" | "NEXT_WEEK" | "OVERDUE"
  >("ANY");
  const [page, setPage] = useState(1);
  const [complexityById, setComplexityById] = useState<
    Record<string, DisputeComplexity>
  >({});
  const [complexityFailedIds, setComplexityFailedIds] = useState<Set<string>>(
    new Set(),
  );
  // Refs to read current state inside useEffect without adding to deps
  const complexityByIdRef = useRef(complexityById);
  complexityByIdRef.current = complexityById;
  const complexityFailedIdsRef = useRef(complexityFailedIds);
  complexityFailedIdsRef.current = complexityFailedIds;
  const fetchingComplexityIdsRef = useRef(new Set<string>());
  const [complexityFilter, setComplexityFilter] = useState<
    DisputeComplexity["level"] | "ALL"
  >("ALL");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [dialogType, setDialogType] = useState<
    "reject" | "request-info" | null
  >(null);
  const [dialogReason, setDialogReason] = useState("");
  const [dialogTarget, setDialogTarget] = useState<DisputeSummary | null>(null);
  const [dialogLoading, setDialogLoading] = useState(false);
  const [rowActionLoadingId, setRowActionLoadingId] = useState<string | null>(
    null,
  );
  const [showAdvancedFilters, setShowAdvancedFilters] = useState(false);

  const statusIn = useMemo(() => {
    if (mode === "queue") {
      switch (viewFilter) {
        case "ACTIVE":
          return [DisputeStatus.TRIAGE_PENDING, DisputeStatus.OPEN];
        case "PENDING_REVIEW":
          return [DisputeStatus.PREVIEW, DisputeStatus.PENDING_REVIEW];
        case "RESOLVED":
          return [DisputeStatus.RESOLVED, DisputeStatus.REJECTED];
        default:
          // Queue "All"  Escoped to queue-relevant statuses only
          // (NOT same as caseload  Equeue only sees triage pipeline)
          return [
            DisputeStatus.TRIAGE_PENDING,
            DisputeStatus.OPEN,
            DisputeStatus.PREVIEW,
            DisputeStatus.PENDING_REVIEW,
            DisputeStatus.REJECTED,
            DisputeStatus.REJECTION_APPEALED,
          ];
      }
    }
    // Caseload mode  Escoped to staff's assigned disputes (via assignedStaffId)
    switch (viewFilter) {
      case "ACTIVE":
        return [
          DisputeStatus.PREVIEW,
          DisputeStatus.PENDING_REVIEW,
          DisputeStatus.IN_MEDIATION,
          DisputeStatus.INFO_REQUESTED,
        ];
      case "APPEALS":
        return [DisputeStatus.APPEALED, DisputeStatus.REJECTION_APPEALED];
      case "RESOLVED":
        return [DisputeStatus.RESOLVED, DisputeStatus.REJECTED];
      default:
        // Caseload "All"  Eall statuses but filtered by assignedStaffId
        return undefined;
    }
  }, [viewFilter, mode]);

  // Tab definitions differ per mode
  const statusTabs = useMemo(() => {
    if (mode === "queue") {
      return [
        {
          value: "ACTIVE" as ViewFilter,
          label: "Pending",
          statuses: [DisputeStatus.TRIAGE_PENDING, DisputeStatus.OPEN],
        },
        {
          value: "PENDING_REVIEW" as ViewFilter,
          label: "Preview",
          statuses: [DisputeStatus.PREVIEW, DisputeStatus.PENDING_REVIEW],
        },
        {
          value: "RESOLVED" as ViewFilter,
          label: "Closed",
          statuses: [DisputeStatus.RESOLVED, DisputeStatus.REJECTED],
        },
        {
          value: "ALL" as ViewFilter,
          label: "All",
          // Queue "All" scoped to queue-relevant statuses
          statuses: [
            DisputeStatus.TRIAGE_PENDING,
            DisputeStatus.OPEN,
            DisputeStatus.PREVIEW,
            DisputeStatus.PENDING_REVIEW,
            DisputeStatus.REJECTED,
            DisputeStatus.REJECTION_APPEALED,
          ],
        },
      ];
    }
    return [
      {
        value: "ACTIVE" as ViewFilter,
        label: "In Progress",
        statuses: [
          DisputeStatus.PREVIEW,
          DisputeStatus.PENDING_REVIEW,
          DisputeStatus.IN_MEDIATION,
          DisputeStatus.INFO_REQUESTED,
        ],
      },
      {
        value: "APPEALS" as ViewFilter,
        label: "Appeals",
        statuses: [DisputeStatus.APPEALED, DisputeStatus.REJECTION_APPEALED],
      },
      {
        value: "RESOLVED" as ViewFilter,
        label: "Closed",
        statuses: [DisputeStatus.RESOLVED, DisputeStatus.REJECTED],
      },
      {
        value: "ALL" as ViewFilter,
        label: "All",
        statuses: [],
      },
    ];
  }, [mode]);

  /** Compute per-tab count from stats.byStatus */
  const getTabCount = useCallback(
    (tab: (typeof statusTabs)[number]) => {
      if (!stats?.byStatus) return null;
      if (tab.statuses.length === 0) {
        // "All" tab  Esum all statuses
        return Object.values(stats.byStatus).reduce(
          (sum, n) => sum + (n ?? 0),
          0,
        );
      }
      return tab.statuses.reduce((sum, s) => sum + (stats.byStatus[s] ?? 0), 0);
    },
    [stats?.byStatus],
  );

  const activeFilterCount = useMemo(() => {
    let count = 0;
    if (weekFilter !== "ANY") count++;
    if (categoryFilter !== "ALL") count++;
    if (priorityFilter !== "ALL") count++;
    if (complexityFilter !== "ALL") count++;
    return count;
  }, [weekFilter, categoryFilter, priorityFilter, complexityFilter]);

  const clearAdvancedFilters = useCallback(() => {
    setWeekFilter("ANY");
    setCategoryFilter("ALL");
    setPriorityFilter("ALL");
    setComplexityFilter("ALL");
  }, []);

  const deadlineRange = useMemo(() => {
    if (weekFilter === "OVERDUE") {
      return { overdueOnly: true };
    }

    if (weekFilter === "THIS_WEEK" || weekFilter === "NEXT_WEEK") {
      const today = new Date();
      const startOfWeek = new Date(today);
      const dayIndex = (startOfWeek.getDay() + 6) % 7;
      startOfWeek.setDate(startOfWeek.getDate() - dayIndex);
      startOfWeek.setHours(0, 0, 0, 0);

      if (weekFilter === "NEXT_WEEK") {
        startOfWeek.setDate(startOfWeek.getDate() + 7);
      }

      const endOfWeek = new Date(startOfWeek);
      endOfWeek.setDate(endOfWeek.getDate() + 6);
      endOfWeek.setHours(23, 59, 59, 999);

      return {
        deadlineFrom: startOfWeek.toISOString(),
        deadlineTo: endOfWeek.toISOString(),
      };
    }

    return {};
  }, [weekFilter]);

  const queryFilters = useMemo(
    () => ({
      page,
      limit: 20,
      sortBy: "urgency",
      sortOrder: "DESC" as const,
      statusIn,
      priority: priorityFilter === "ALL" ? undefined : priorityFilter,
      category: categoryFilter === "ALL" ? undefined : categoryFilter,
      search: debouncedSearch ? debouncedSearch : undefined,
      // Queue: don't filter by assignedStaffId  Eshow all unassigned disputes
      // Caseload: filter by current staff's assigned disputes
      assignedStaffId:
        mode === "caseload" && isStaffUser ? currentUser?.id : undefined,
      ...deadlineRange,
    }),
    [
      page,
      statusIn,
      priorityFilter,
      categoryFilter,
      debouncedSearch,
      isStaffUser,
      currentUser?.id,
      deadlineRange,
      mode,
    ],
  );

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchValue.trim());
    }, 300);
    return () => clearTimeout(timer);
  }, [searchValue]);

  useEffect(() => {
    setPage(1);
  }, [viewFilter, priorityFilter, categoryFilter, weekFilter, debouncedSearch]);

  const fetchDisputes = useCallback(
    async (options?: { preferCache?: boolean }) => {
      try {
        setLoading(true);
        const data = await getDisputes(queryFilters, {
          preferCache: options?.preferCache,
          ttlMs: 30_000,
        });
        setDisputes(data.data ?? []);
        setMeta(data.meta);
        setStats(data.stats ?? null);
      } catch (error) {
        console.error("Failed to load disputes:", error);
        toast.error("Could not load dispute queue");
      } finally {
        setLoading(false);
      }
    },
    [queryFilters],
  );

  useEffect(() => {
    fetchDisputes({ preferCache: true });
  }, [fetchDisputes]);

  const handleRealtimeRefresh = useCallback(() => {
    fetchDisputes({ preferCache: false });
  }, [fetchDisputes]);

  useStaffDashboardRealtime({
    onDisputeCreated: handleRealtimeRefresh,
    onHearingEnded: handleRealtimeRefresh,
    onVerdictIssued: handleRealtimeRefresh,
  });

  useEffect(() => {
    if (!disputes.length) return;

    // Read current state via refs to avoid dependency-triggered re-runs
    const currentComplexity = complexityByIdRef.current;
    const currentFailed = complexityFailedIdsRef.current;
    const fetching = fetchingComplexityIdsRef.current;

    const toFetch = disputes
      .map((d) => d.id)
      .filter(
        (id) =>
          !currentComplexity[id] && !currentFailed.has(id) && !fetching.has(id),
      );
    if (!toFetch.length) return;

    // Mark as in-flight immediately to prevent duplicate requests
    toFetch.forEach((id) => fetching.add(id));

    let cancelled = false;
    getDisputeComplexities(toFetch, { preferCache: true })
      .then(({ data: resultMap, failedIds }) => {
        if (cancelled) return;
        if (Object.keys(resultMap).length) {
          setComplexityById((prev) => ({ ...prev, ...resultMap }));
        }

        // Mark failed IDs (explicit errors + orphans not in resultMap)
        const allFailed = [...failedIds];
        toFetch.forEach((id) => {
          if (!resultMap[id] && !failedIds.includes(id)) {
            allFailed.push(id);
          }
        });
        if (allFailed.length) {
          setComplexityFailedIds((prev) => {
            const next = new Set(prev);
            allFailed.forEach((id) => next.add(id));
            return next;
          });
        }
      })
      .catch((error) => {
        if (cancelled) return;
        console.error("Failed to load dispute complexity batch:", error);
        setComplexityFailedIds((prev) => {
          const next = new Set(prev);
          toFetch.forEach((id) => next.add(id));
          return next;
        });
      })
      .finally(() => {
        toFetch.forEach((id) => fetching.delete(id));
      });

    return () => {
      cancelled = true;
      toFetch.forEach((id) => fetching.delete(id));
    };
  }, [disputes]);

  const openDialog = (
    type: "reject" | "request-info",
    target: DisputeSummary,
  ) => {
    setDialogType(type);
    setDialogTarget(target);
    setDialogReason("");
    setDialogOpen(true);
  };

  const handleDialogSubmit = async () => {
    if (!dialogTarget || !dialogType) return;
    if (!dialogReason.trim()) {
      toast.error("Please provide a reason.");
      return;
    }

    try {
      setDialogLoading(true);
      if (dialogType === "reject") {
        await rejectDispute(dialogTarget.id, dialogReason.trim());
        toast.success("Dispute rejected.");
      } else {
        await requestDisputeInfo(dialogTarget.id, dialogReason.trim());
        toast.success("Info request sent.");
      }
      setDialogOpen(false);
      invalidateDisputesCache();
      await fetchDisputes({ preferCache: false });
    } catch (error) {
      console.error("Failed to process action:", error);
      toast.error("Action failed. Please try again.");
    } finally {
      setDialogLoading(false);
    }
  };

  const handleEscalate = async (dispute: DisputeSummary) => {
    try {
      setRowActionLoadingId(dispute.id);
      if (
        [DisputeStatus.PREVIEW, DisputeStatus.PENDING_REVIEW].includes(
          dispute.status,
        )
      ) {
        await completeDisputePreview(dispute.id);
        toast.success("Preview completed and mediation schedule triggered.");
      } else {
        await escalateDispute(dispute.id);
        toast.success("Dispute escalated to mediation.");
      }
      invalidateDisputesCache();
      await fetchDisputes({ preferCache: false });
    } catch (error) {
      console.error("Failed to escalate dispute:", error);
      toast.error("Could not escalate dispute.");
    } finally {
      setRowActionLoadingId(null);
    }
  };

  const handleAccept = async (dispute: DisputeSummary) => {
    try {
      setRowActionLoadingId(dispute.id);
      await acceptDispute(dispute.id);
      toast.success("Dispute accepted into caseload.");
      invalidateDisputesCache();
      await fetchDisputes({ preferCache: false });
    } catch (error) {
      console.error("Failed to accept dispute:", error);
      toast.error("Could not accept dispute.");
    } finally {
      setRowActionLoadingId(null);
    }
  };

  const currencyFormatter = useMemo(
    () =>
      new Intl.NumberFormat("en-US", {
        style: "currency",
        currency: "USD",
        maximumFractionDigits: 0,
      }),
    [],
  );

  const statusPill = (status: DisputeStatus) => {
    switch (status) {
      case DisputeStatus.TRIAGE_PENDING:
        return "bg-violet-50 text-violet-700 border-violet-200";
      case DisputeStatus.PREVIEW:
        return "bg-sky-50 text-sky-700 border-sky-200";
      case DisputeStatus.PENDING_REVIEW:
        return "bg-amber-50 text-amber-700 border-amber-200";
      case DisputeStatus.INFO_REQUESTED:
        return "bg-blue-50 text-blue-700 border-blue-200";
      case DisputeStatus.IN_MEDIATION:
        return "bg-emerald-50 text-emerald-700 border-emerald-200";
      case DisputeStatus.REJECTED:
        return "bg-red-50 text-red-700 border-red-200";
      case DisputeStatus.RESOLVED:
        return "bg-slate-100 text-slate-600 border-slate-200";
      default:
        return "bg-gray-100 text-gray-600 border-gray-200";
    }
  };

  const categoryPill = (category: DisputeCategory) => {
    if (category === DisputeCategory.FRAUD) {
      return "bg-red-50 text-red-700 border-red-100";
    }
    if (category === DisputeCategory.PAYMENT) {
      return "bg-emerald-50 text-emerald-700 border-emerald-100";
    }
    return "bg-slate-100 text-slate-700 border-slate-200";
  };

  const visibleDisputes = useMemo(() => {
    if (complexityFilter === "ALL") return disputes;
    return disputes.filter(
      (dispute) => complexityById[dispute.id]?.level === complexityFilter,
    );
  }, [disputes, complexityById, complexityFilter]);

  const totalLabel =
    complexityFilter === "ALL"
      ? (meta?.total ?? disputes.length)
      : `${visibleDisputes.length}/${meta?.total ?? disputes.length}`;

  const emptyState = !loading && visibleDisputes.length === 0;

  const boardTitle =
    mode === "caseload" ? "My Caseload" : "Dispute Queue (Triage)";

  const canModerate = true; // actions available in both queue and caseload modes

  // ── Helpers for per-row badges ──
  const NEW_THRESHOLD_MS = 24 * 60 * 60 * 1000; // 24 hours
  const nowMs = Date.now();

  const priorityDot = (priority: DisputePriority) => {
    switch (priority) {
      case DisputePriority.CRITICAL:
        return "bg-red-500";
      case DisputePriority.HIGH:
        return "bg-orange-400";
      case DisputePriority.MEDIUM:
        return "bg-yellow-400";
      case DisputePriority.LOW:
        return "bg-emerald-400";
      default:
        return "bg-gray-300";
    }
  };

  const formatDeadline = (dispute: DisputeSummary) => {
    const hours = dispute.hoursUntilDeadline;
    if (hours == null) return null;

    if (dispute.isOverdue) {
      return {
        label: "Overdue",
        cls: "bg-red-50 text-red-600 border-red-100",
        icon: AlertTriangle,
      };
    }
    if (hours <= 48) {
      const display =
        hours < 1
          ? "< 1h left"
          : hours < 24
            ? `${Math.round(hours)}h left`
            : `${Math.round(hours / 24)}d left`;
      return {
        label: display,
        cls: "bg-amber-50 text-amber-600 border-amber-100",
        icon: Clock,
      };
    }
    const days = Math.round(hours / 24);
    return {
      label: `${days}d left`,
      cls: "bg-gray-50 text-gray-500 border-gray-100",
      icon: Clock,
    };
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-full">
      {/* Toolbar */}
      <div className="border-b border-gray-200">
        {/* Row 1: Title + Stats + Search */}
        <div className="px-4 pt-4 pb-3 flex items-center justify-between gap-4">
          <div className="flex items-center gap-3 min-w-0">
            <h3 className="text-lg font-semibold text-slate-900 whitespace-nowrap">
              {boardTitle}
            </h3>
            <span className="px-2 py-0.5 bg-gray-100 text-gray-600 rounded-full text-xs font-medium">
              {totalLabel}
            </span>
            {(stats?.urgent ?? 0) > 0 && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 bg-red-50 text-red-600 border border-red-100 rounded-full text-xs font-medium whitespace-nowrap">
                <AlertTriangle className="w-3 h-3" />
                {stats!.urgent} urgent
              </span>
            )}
            {(stats?.overdue ?? 0) > 0 && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 bg-amber-50 text-amber-600 border border-amber-100 rounded-full text-xs font-medium whitespace-nowrap">
                <Clock className="w-3 h-3" />
                {stats!.overdue} overdue
              </span>
            )}
          </div>
          <div className="relative shrink-0">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Search IDs or users..."
              className="pl-9 pr-3 py-1.5 text-sm border border-gray-300 rounded-lg focus:ring-teal-500 focus:border-teal-500 w-64"
              value={searchValue}
              onChange={(event) => setSearchValue(event.target.value)}
            />
          </div>
        </div>

        {/* Row 2: Status tabs + Filters toggle */}
        <div className="px-4 pb-3 flex items-center justify-between gap-4">
          <div className="flex items-center gap-1">
            {statusTabs.map((tab) => {
              const count = getTabCount(tab);
              return (
                <button
                  key={tab.value}
                  onClick={() => setViewFilter(tab.value)}
                  className={cn(
                    "px-3 py-1.5 text-sm font-medium rounded-lg transition-colors inline-flex items-center gap-1.5",
                    viewFilter === tab.value
                      ? "bg-teal-50 text-teal-700 border border-teal-200"
                      : "text-gray-500 hover:text-gray-700 hover:bg-gray-50 border border-transparent",
                  )}
                >
                  {tab.label}
                  {count != null && (
                    <span
                      className={cn(
                        "text-[10px] font-semibold leading-none rounded-full px-1.5 py-0.5",
                        viewFilter === tab.value
                          ? "bg-teal-100 text-teal-700"
                          : "bg-gray-100 text-gray-500",
                      )}
                    >
                      {count}
                    </span>
                  )}
                </button>
              );
            })}
          </div>
          <button
            onClick={() => setShowAdvancedFilters((prev) => !prev)}
            className={cn(
              "inline-flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium rounded-lg transition-colors border shrink-0",
              showAdvancedFilters
                ? "bg-teal-50 text-teal-700 border-teal-200"
                : "text-gray-500 hover:text-gray-700 hover:bg-gray-50 border-gray-300",
            )}
          >
            <SlidersHorizontal className="w-4 h-4" />
            Filters
            {activeFilterCount > 0 && (
              <span className="px-1.5 py-0.5 bg-teal-100 text-teal-700 rounded-full text-xs font-semibold leading-none">
                {activeFilterCount}
              </span>
            )}
          </button>
        </div>

        {/* Row 3: Advanced filters (collapsible) */}
        {showAdvancedFilters && (
          <div className="px-4 pb-3 pt-2 border-t border-gray-100 flex flex-wrap items-center gap-3">
            <select
              value={weekFilter}
              onChange={(event) =>
                setWeekFilter(
                  event.target.value as
                    | "ANY"
                    | "THIS_WEEK"
                    | "NEXT_WEEK"
                    | "OVERDUE",
                )
              }
              className="border border-gray-300 rounded-lg px-3 py-1.5 text-sm text-gray-600 bg-white"
            >
              <option value="ANY">Any deadline</option>
              <option value="THIS_WEEK">This week</option>
              <option value="NEXT_WEEK">Next week</option>
              <option value="OVERDUE">Overdue</option>
            </select>
            <select
              value={categoryFilter}
              onChange={(event) =>
                setCategoryFilter(event.target.value as DisputeCategory | "ALL")
              }
              className="border border-gray-300 rounded-lg px-3 py-1.5 text-sm text-gray-600 bg-white"
            >
              <option value="ALL">All categories</option>
              {Object.values(DisputeCategory).map((category) => (
                <option key={category} value={category}>
                  {category.replace("_", " ")}
                </option>
              ))}
            </select>
            <select
              value={priorityFilter}
              onChange={(event) =>
                setPriorityFilter(event.target.value as DisputePriority | "ALL")
              }
              className="border border-gray-300 rounded-lg px-3 py-1.5 text-sm text-gray-600 bg-white"
            >
              <option value="ALL">All priorities</option>
              {Object.values(DisputePriority).map((priority) => (
                <option key={priority} value={priority}>
                  {priority}
                </option>
              ))}
            </select>
            <select
              value={complexityFilter}
              onChange={(event) =>
                setComplexityFilter(
                  event.target.value as DisputeComplexity["level"] | "ALL",
                )
              }
              className="border border-gray-300 rounded-lg px-3 py-1.5 text-sm text-gray-600 bg-white"
            >
              <option value="ALL">All complexity</option>
              <option value="LOW">Low</option>
              <option value="MEDIUM">Medium</option>
              <option value="HIGH">High</option>
              <option value="CRITICAL">Critical</option>
            </select>
            {activeFilterCount > 0 && (
              <button
                onClick={clearAdvancedFilters}
                className="inline-flex items-center gap-1 px-2.5 py-1.5 text-sm text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
              >
                <X className="w-3.5 h-3.5" />
                Clear
              </button>
            )}
          </div>
        )}
      </div>

      {/* Table */}
      <div className="overflow-x-auto min-h-[400px] relative">
        {loading && (
          <div className="absolute inset-0 bg-white/60 z-10 flex items-center justify-center">
            <Loader2 className="w-6 h-6 text-teal-600 animate-spin" />
          </div>
        )}
        <table className="w-full text-left text-sm">
          <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
            <tr>
              <th className="px-4 py-3">Dispute ID / Project</th>
              <th className="px-4 py-3">Raiser</th>
              <th className="px-4 py-3">Category</th>
              <th className="px-4 py-3">Deadline</th>
              <th className="px-4 py-3">Complexity (Est.)</th>
              <th className="px-4 py-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {visibleDisputes.map((dispute) => {
              const complexity = complexityById[dispute.id];
              const projectTitle =
                dispute.project?.title ||
                dispute.projectId ||
                "Unknown project";
              const raiserLabel =
                dispute.raiser?.fullName ||
                dispute.raiser?.email ||
                dispute.raisedById;
              const amountLabel = dispute.disputedAmount
                ? currencyFormatter.format(dispute.disputedAmount)
                : "N/A";
              const canReview = [
                DisputeStatus.TRIAGE_PENDING,
                DisputeStatus.OPEN,
                DisputeStatus.PREVIEW,
                DisputeStatus.PENDING_REVIEW,
                DisputeStatus.INFO_REQUESTED,
              ].includes(dispute.status);

              const isNew =
                dispute.createdAt &&
                nowMs - new Date(dispute.createdAt).getTime() <
                  NEW_THRESHOLD_MS;
              const deadline = formatDeadline(dispute);

              return (
                <tr
                  key={dispute.id}
                  className="hover:bg-gray-50 group transition-colors"
                >
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-1.5">
                      {/* Priority dot */}
                      <span
                        className={cn(
                          "w-2 h-2 rounded-full shrink-0",
                          priorityDot(dispute.priority),
                        )}
                        title={`Priority: ${dispute.priority}`}
                      />
                      <span className="font-medium text-slate-900">
                        {dispute.id}
                      </span>
                      {isNew && (
                        <span className="inline-flex items-center gap-0.5 px-1.5 py-0.5 bg-teal-50 text-teal-600 border border-teal-100 rounded-full text-[10px] font-semibold leading-none">
                          <Sparkles className="w-2.5 h-2.5" />
                          New
                        </span>
                      )}
                    </div>
                    <div className="text-xs text-gray-500 truncate max-w-[200px] ml-3.5">
                      {projectTitle}
                    </div>
                    <span
                      className={`inline-flex mt-1 ml-3.5 px-2 py-0.5 rounded text-xs font-medium border ${statusPill(
                        dispute.status,
                      )}`}
                    >
                      {dispute.status.replace("_", " ")}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-slate-700">
                    {raiserLabel}
                    <div className="text-xs text-slate-400">
                      {amountLabel} in Escrow
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    <span
                      className={`inline-flex px-2 py-0.5 rounded text-xs font-medium border
                                        ${categoryPill(dispute.category)}
                                    `}
                    >
                      {dispute.category}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    {deadline ? (
                      <span
                        className={cn(
                          "inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-medium border",
                          deadline.cls,
                        )}
                      >
                        <deadline.icon className="w-3 h-3" />
                        {deadline.label}
                      </span>
                    ) : (
                      <span className="text-xs text-gray-400">--</span>
                    )}
                  </td>
                  <td className="px-4 py-3">
                    {complexity?.level &&
                    complexity?.timeEstimation?.recommendedMinutes != null ? (
                      <DisputeComplexityBadge
                        level={complexity.level}
                        estMinutes={
                          complexity.timeEstimation.recommendedMinutes
                        }
                        confidence={complexity.confidence}
                      />
                    ) : complexityFailedIds.has(dispute.id) ? (
                      <span className="text-xs text-red-400">Unavailable</span>
                    ) : (
                      <span className="text-xs text-gray-400">
                        Estimating...
                      </span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-right">
                    <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button
                        className="p-1.5 text-teal-600 hover:bg-teal-50 rounded-md"
                        title="Quick Look"
                        onClick={() =>
                          navigate(`/staff/caseload?disputeId=${dispute.id}`, {
                            state: { dispute },
                          })
                        }
                      >
                        <Eye className="w-4 h-4" />
                      </button>
                      {canModerate && canReview ? (
                        <>
                          {/* Queue mode: Accept / Reject for OPEN disputes */}
                          {mode === "queue" &&
                            [
                              DisputeStatus.OPEN,
                              DisputeStatus.TRIAGE_PENDING,
                            ].includes(dispute.status) && (
                              <>
                                <button
                                  className="p-1.5 text-red-600 hover:bg-red-50 rounded-md"
                                  title="Reject as Invalid"
                                  onClick={() => openDialog("reject", dispute)}
                                >
                                  <Ban className="w-4 h-4" />
                                </button>
                                <button
                                  className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-md"
                                  title="Accept to Caseload"
                                  onClick={() => handleAccept(dispute)}
                                  disabled={rowActionLoadingId === dispute.id}
                                >
                                  {rowActionLoadingId === dispute.id ? (
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                  ) : (
                                    <CheckCircle className="w-4 h-4" />
                                  )}
                                </button>
                              </>
                            )}

                          {/* Caseload mode: Escalate / Request Info for PENDING_REVIEW disputes */}
                          {mode === "caseload" &&
                            [
                              DisputeStatus.PENDING_REVIEW,
                              DisputeStatus.PREVIEW,
                            ].includes(dispute.status) && (
                              <>
                                <button
                                  className="p-1.5 text-orange-600 hover:bg-orange-50 rounded-md"
                                  title="Escalate to Mediation"
                                  onClick={() => handleEscalate(dispute)}
                                  disabled={rowActionLoadingId === dispute.id}
                                >
                                  {rowActionLoadingId === dispute.id ? (
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                  ) : (
                                    <AlertTriangle className="w-4 h-4" />
                                  )}
                                </button>
                                <button
                                  className="px-2 py-1 text-xs text-slate-600 border border-gray-200 rounded-md hover:bg-gray-50"
                                  onClick={() =>
                                    openDialog("request-info", dispute)
                                  }
                                >
                                  Request Info
                                </button>
                              </>
                            )}
                        </>
                      ) : null}
                    </div>
                  </td>
                </tr>
              );
            })}
            {emptyState && (
              <tr>
                <td
                  colSpan={6}
                  className="px-4 py-12 text-center text-sm text-gray-500"
                >
                  No disputes found for the current filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      <div className="flex items-center justify-between px-4 py-3 border-t border-gray-200 text-sm text-gray-500">
        <div>
          Page {meta?.page ?? page} of {meta?.totalPages ?? 1}
        </div>
        <div className="flex items-center gap-2">
          <button
            className="px-3 py-1 rounded border border-gray-200 text-gray-600 disabled:opacity-50"
            disabled={!meta?.hasPrevPage}
            onClick={() => setPage((prev) => Math.max(1, prev - 1))}
          >
            Previous
          </button>
          <button
            className="px-3 py-1 rounded border border-gray-200 text-gray-600 disabled:opacity-50"
            disabled={!meta?.hasNextPage}
            onClick={() => setPage((prev) => prev + 1)}
          >
            Next
          </button>
        </div>
      </div>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>
              {dialogType === "reject"
                ? "Reject dispute"
                : "Request additional info"}
            </DialogTitle>
            <DialogDescription>
              Provide a clear reason so all parties understand the decision.
            </DialogDescription>
          </DialogHeader>
          <div>
            <textarea
              rows={4}
              value={dialogReason}
              onChange={(event) => setDialogReason(event.target.value)}
              placeholder="Write a concise reason..."
              className="w-full border border-gray-200 rounded-lg p-3 text-sm focus:ring-teal-500 focus:border-teal-500"
            />
          </div>
          <DialogFooter>
            <button
              className="px-4 py-2 rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-50"
              onClick={() => setDialogOpen(false)}
              disabled={dialogLoading}
            >
              Cancel
            </button>
            <button
              className="px-4 py-2 rounded-lg bg-slate-900 text-white hover:bg-slate-800 disabled:opacity-50"
              onClick={handleDialogSubmit}
              disabled={dialogLoading}
            >
              {dialogLoading ? "Submitting..." : "Confirm"}
            </button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { ProjectRequestsTable } from './components/ProjectRequestsTable';
import { projectRequestsApi } from './api';
import type { ProjectRequest } from './types';
import { Loader2 } from 'lucide-react';
import { KYCBlocker, useKYCStatus } from '@/shared/components/custom/KYCBlocker';
import { STORAGE_KEYS } from '@/constants';
import { getStoredJson } from '@/shared/utils/storage';

export const BrokerProjectsPage: React.FC = () => {
  const [requests, setRequests] = useState<ProjectRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [assigningId, setAssigningId] = useState<string | null>(null);
  const [user, setUser] = useState<any>(null);
  const [kycStatus, setKycStatus] = useState<string | null>(null);
  const { checkKycStatus } = useKYCStatus();

  useEffect(() => {
    setUser(getStoredJson(STORAGE_KEYS.USER));

    // Check KYC status
    checkKycStatus().then(setKycStatus);
  }, []);

  const fetchRequests = async () => {
    try {
      setLoading(true);
      const data = await projectRequestsApi.getAll();
      setRequests(data);
    } catch (error) {
      console.error('Failed to fetch requests:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  // Filter for My Projects (Assigned OR Accepted Proposal)
  const myProjects = requests.filter(r => 
      // 1. Assigned directly
      r.brokerId === user?.id 
      || 
      // 2. Has ACCEPTED proposal (Meaning invited and accepted)
      r.brokerProposals?.some((p: any) => p.brokerId === user?.id && p.status === 'ACCEPTED')
  );

  const handleAssign = async (requestId: string) => {
    // Re-implementation of assign logic if needed locally, although usually "My Projects" are already assigned/accepted.
    // Keeping it here just in case status changes or needed.
     if (!confirm('Are you sure you want to assign this request to yourself?')) return;
    
    try {
      setAssigningId(requestId);
      await projectRequestsApi.assignBroker(requestId);
      await fetchRequests();
      alert('Request assigned successfully!');
    } catch (error: any) {
      console.error('Failed to assign request:', error);
      alert(error.response?.data?.message || 'Failed to assign request');
    } finally {
      setAssigningId(null);
    }
  };

  const handleApply = async (requestId: string, coverLetter: string) => {
     // Re-implement apply if they can re-apply or apply to others here? Unlikely but good to have signature match.
     try {
        await projectRequestsApi.applyToRequest(requestId, coverLetter);
        alert("Application submitted successfully!");
        fetchRequests();
     } catch (error: any) {
        console.error(error);
        alert(error.response?.data?.message || "Failed to apply");
     }
  };

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-teal-600" />
      </div>
    );
  }

  // Block access if KYC not approved
  if (kycStatus && kycStatus !== 'APPROVED') {
    return (
      <KYCBlocker 
        kycStatus={kycStatus} 
        role="broker" 
        action="manage project requests"
      />
    );
  }

  return (
    <div className="container mx-auto py-10">
      <div className="mb-8 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">My Projects</h1>
          <p className="text-muted-foreground">
             Projects where you are the Assigned Broker or have an Accepted Invitation.
          </p>
        </div>
      </div>
      
      <div className="rounded-md bg-white p-4 shadow-sm">
         {myProjects.length === 0 ? (
             <div className="text-center py-10 text-muted-foreground">
                 You don't have any active projects yet. Check the Marketplace to find work!
             </div>
         ) : (
            <ProjectRequestsTable 
                requests={myProjects} 
                onAssign={handleAssign}
                onApply={handleApply}
                assigningId={assigningId}
                currentUserId={user?.id}
            />
         )}
      </div>
    </div>
  );
};

﻿import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { format } from "date-fns";
import {
  ArrowLeft,
  Mail,
  User,
  Calendar,
  DollarSign,
  Monitor,
  FileText,
  UserPlus,
  FileSignature,
  CheckCircle2,
  Check, 
  Clock, 
  AlertCircle
} from "lucide-react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/shared/components/ui/tabs";
import { UserRole } from "@/shared/types/user.types";
import { STORAGE_KEYS } from "@/constants";

import type { ProjectRequest, RequestStatus } from "./types";
import { projectRequestsApi } from "./api";
import { Button } from "@/shared/components/custom/Button";
import { Badge } from "@/shared/components/ui/badge";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/shared/components/ui/Card";
import { Separator } from "@/shared/components/ui/separator";
import { Skeleton } from "@/shared/components/ui/skeleton";
import { getStoredJson } from "@/shared/utils/storage";

// Helper to determine active phase for Broker (mirrors Client logic but simpler)
const getBrokerPhase = (status: string) => {
    if (status === 'SPEC_APPROVED') return 'phase3'; // Hiring
    if (status === 'CONTRACT_PENDING') return 'phase4'; // Contract
    if (status === 'PROCESSING') return 'phase2'; // Specs
    return 'phase1'; // Default
};

export default function ProjectRequestDetailsPage() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [request, setRequest] = useState<ProjectRequest | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    setUser(getStoredJson(STORAGE_KEYS.USER));
  }, []);

  const isAdmin = user?.role === "ADMIN";

  // Helper moved to top level

  const handleBack = () => {
    if (isAdmin) {
      navigate("/admin/specs"); 
    } else if (user?.role === "BROKER") {
      // If assigned to me, go to My Requests, otherwise Marketplace
      if (request?.brokerId === user?.id) {
          navigate("/broker/my-requests");
      } else {
          navigate("/broker/marketplace");
      }
    } else {
      navigate("/client/my-requests");
    }
  };

  const fetchRequest = async () => {
    if (!id) return;
    try {
      setIsLoading(true);
      const response = await projectRequestsApi.getById(id);
      setRequest(response);
    } catch (err: unknown) {
      console.error("Failed to fetch request:", err);
      setError("Failed to load project request details.");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchRequest();
  }, [id]);

  if (isLoading) {
    return (
      <div className="container mx-auto py-8 space-y-6">
        <Skeleton className="h-8 w-48" />
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <Skeleton className="h-[400px] col-span-2" />
          <Skeleton className="h-[200px]" />
        </div>
      </div>
    );
  }

  if (error || !request) {
    return (
      <div className="container mx-auto py-8">
        <Card className="border-red-200 bg-red-50">
          <CardContent className="pt-6 text-center">
            <h3 className="text-lg font-semibold text-red-800 mb-2">
              Error Loading Request
            </h3>
            <p className="text-gray-600 mb-4">
              {error || "Could not load the project request details."}
            </p>
            <Button
              variant="outline"
              onClick={() => navigate("/project-requests")}
            >
              Back to List
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  const getStatusColor = (status: RequestStatus) => {
    switch (status) {
      case "PENDING":
        return "bg-yellow-100 text-yellow-800 hover:bg-yellow-100";
      case "PROCESSING":
        return "bg-blue-100 text-blue-800 hover:bg-blue-100";
      case "COMPLETED":
        return "bg-green-100 text-green-800 hover:bg-green-100";
      case "CANCELLED":
        return "bg-red-100 text-red-800 hover:bg-red-100";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const handleAssign = async () => {
    if (!request || !request.id) return;
    if (!confirm("Are you sure you want to assign this request to yourself?"))
      return;

    try {
      // Optimistically update UI or show loading
      await projectRequestsApi.assignBroker(request.id);

      // Refresh data from server to get correct brokerId and status
      await fetchRequest();
      alert("Request assigned successfully!");
      // Navigate back or refresh? For now just stay.
    } catch (err: unknown) {
      console.error("Failed to assign request:", err);
      alert("Failed to assign request");
    }
  };



  return (
    <div className="container mx-auto py-8 space-y-6">
      <div className="flex items-center gap-4">
        <Button variant="outline" onClick={handleBack}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <h1 className="text-2xl font-bold tracking-tight">Request Details</h1>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Content Area */}
        <div className="lg:col-span-2 space-y-6">
           
           <Tabs defaultValue="overview" className="w-full">
            <TabsList className="mb-4 w-full justify-start">
               <TabsTrigger value="overview">Overview & Status</TabsTrigger>
               <TabsTrigger value="phases">Workflow Phases</TabsTrigger>
            </TabsList>

            <TabsContent value="overview" className="space-y-6">
                <Card>
                    <CardHeader>
                    <div className="flex justify-between items-start">
                        <div className="space-y-1">
                        <CardTitle className="text-xl">{request.title}</CardTitle>
                        <CardDescription>
                            Created on {format(new Date(request.createdAt), "PPP")}
                        </CardDescription>
                        </div>
                        <Badge className={getStatusColor(request.status)}>
                        {request.status}
                        </Badge>
                    </div>
                    </CardHeader>
                    <CardContent className="space-y-6">
                    <div>
                        <h3 className="text-sm font-medium text-muted-foreground mb-2">
                        Description
                        </h3>
                        <p className="text-sm leading-relaxed whitespace-pre-wrap">
                        {request.description}
                        </p>
                    </div>
                    <Separator />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-1">
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <DollarSign className="h-4 w-4" />
                            <span>Budget Range</span>
                        </div>
                        <p className="font-medium text-sm">
                            {request.budgetRange || "Not specified"}
                        </p>
                        </div>
                        <div className="space-y-1">
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <Calendar className="h-4 w-4" />
                            <span>Intended Timeline</span>
                        </div>
                        <p className="font-medium text-sm">
                            {request.intendedTimeline || "Not specified"}
                        </p>
                        </div>
                        <div className="col-span-1 md:col-span-2 space-y-1">
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <Monitor className="h-4 w-4" />
                            <span>Tech Preferences</span>
                        </div>
                        <p className="font-medium text-sm">
                            {request.techPreferences || "None specified"}
                        </p>
                        </div>
                    </div>
                    </CardContent>
                </Card>

                {request.answers && request.answers.length > 0 && (
                 <Card>
                   <CardHeader>
                     <CardTitle className="text-lg">Additional Information</CardTitle>
                   </CardHeader>
                   <CardContent>
                     <div className="space-y-4">
                       {request.answers.map((answer) => (
                         <div key={answer.id} className="p-4 bg-muted/50 rounded-lg space-y-2">
                           <p className="text-sm font-medium">{answer.question?.label || "Unknown Question"}</p>
                           <p className="text-sm text-muted-foreground">{answer.option?.label || answer.valueText || "No Answer"}</p>
                         </div>
                       ))}
                     </div>
                   </CardContent>
                 </Card>
                )}
            </TabsContent>

            <TabsContent value="phases" className="space-y-6">
                {/* Phase 2: Specs */}
                <Card className={request.status === 'PROCESSING' ? "border-2 border-primary" : ""}>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                             <div className="bg-blue-100 p-2 rounded-full"><FileText className="w-5 h-5 text-blue-600"/></div>
                             Phase 2: Requirement Specifications
                             {request.spec && <Badge variant="outline" className="ml-2">Submitted</Badge>}
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        {(!request.spec && (request.status === 'PROCESSING' || request.status === 'BROKER_ASSIGNED')) ? (
                            <div className="bg-blue-50 p-4 rounded-lg flex justify-between items-center">
                                <div>
                                    <p className="font-medium text-blue-900">Action Required</p>
                                    <p className="text-sm text-blue-700">Create and submit detailed specs for client approval.</p>
                                </div>
                                <Button onClick={() => navigate(`/broker/project-requests/${request.id}/create-spec`)}>Create Spec</Button>
                            </div>
                        ) : request.spec ? (
                            <div className="space-y-2">
                                <div className="flex justify-between text-sm">
                                    <span>Spec Status:</span>
                                    <Badge>{request.spec.status}</Badge>
                                </div>
                                <p className="text-sm text-muted-foreground">Waiting for Client Approval.</p>
                            </div>
                        ) : (
                             <p className="text-sm text-muted-foreground">Pending prerequisite phases.</p>
                        )}
                    </CardContent>
                </Card>

                {/* Phase 3: Hiring */}
                <Card className={request.status === 'SPEC_APPROVED' ? "border-2 border-primary" : ""}>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                             <div className="bg-orange-100 p-2 rounded-full"><UserPlus className="w-5 h-5 text-orange-600"/></div>
                             Phase 3: Freelancer Recruitment
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        {request.status === 'SPEC_APPROVED' ? (
                             <div className="bg-orange-50 p-4 rounded-lg">
                                  <p className="mb-4 text-sm text-orange-800">Specs Approved! Now you must recruit freelancers.</p>
                                  <div className="flex gap-2">
                                      <Button variant="outline" onClick={() => navigate(`/client/discovery?role=${UserRole.FREELANCER}`)}>Search Market</Button>
                                      <Button onClick={() => alert("Shortcut to Freelancer Suggestion Tool (Coming Soon)")}>Suggest Team</Button>
                                  </div>
                             </div>
                        ) : (
                             <p className="text-sm text-muted-foreground">Locked until Specs are Approved.</p>
                        )}
                    </CardContent>
                </Card>

                 {/* Phase 4: Contract */}
                <Card className={request.status === 'CONTRACT_PENDING' ? "border-2 border-primary" : ""}>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                             <div className="bg-green-100 p-2 rounded-full"><FileSignature className="w-5 h-5 text-green-600"/></div>
                             Phase 4: Contract
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                         {request.status === 'SPEC_APPROVED' || request.status === 'HIRING' ? (
                             <Button 
                                className="w-full" 
                                onClick={async () => {
                                    if(!confirm("Ready to draft contract?")) return;
                                     // Logic to trigger contract draft
                                     alert("Drafting contract...");
                                }}
                             >
                                Draft Contract
                             </Button>
                         ) : (
                            <p className="text-sm text-muted-foreground">Locked until Team is assembled.</p>
                         )}
                    </CardContent>
                </Card>
            </TabsContent>
           </Tabs>

        </div>

        {/* Right Sidebar Info */}
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg flex items-center gap-2">
                <User className="h-5 w-5" />
                Client Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {request.client ? (
                <div className="flex items-start gap-3">
                  <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold">
                    {request.client.fullName.charAt(0).toUpperCase()}
                  </div>
                  <div className="space-y-1">
                    <p className="text-sm font-medium leading-none">
                      {request.client.fullName}
                    </p>
                    <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                      <Mail className="h-3.5 w-3.5" />
                      <span>{request.client.email}</span>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="text-sm text-muted-foreground">
                  Client information unavailable
                </div>
              )}
            </CardContent>
          </Card>
          
           {/* Current Action / Status Card */}
           <Card className="bg-slate-50 border-slate-200">
               <CardHeader><CardTitle className="text-sm uppercase tracking-wider text-muted-foreground">Current Status</CardTitle></CardHeader>
               <CardContent>
                   <div className="flex items-center gap-2 mb-4">
                       <CheckCircle2 className="w-6 h-6 text-green-600" />
                       <span className="font-bold text-lg">{request.status}</span>
                   </div>
                   {request.status === 'PENDING' && (
                       <Button className="w-full" onClick={handleAssign}>Assign to Me</Button>
                   )}
               </CardContent>
           </Card>
        </div>
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { ProjectRequestsTable } from './components/ProjectRequestsTable';
import { projectRequestsApi } from './api';
import type { ProjectRequest } from './types';
import { Loader2 } from 'lucide-react';
import { KYCBlocker, useKYCStatus } from '@/shared/components/custom/KYCBlocker';
import { STORAGE_KEYS } from '@/constants';
import { getStoredJson } from '@/shared/utils/storage';

export const ProjectRequestsPage: React.FC = () => {
  const [requests, setRequests] = useState<ProjectRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [assigningId, setAssigningId] = useState<string | null>(null);
  const [user, setUser] = useState<any>(null);
  const [kycStatus, setKycStatus] = useState<string | null>(null);
  const { checkKycStatus } = useKYCStatus();

  useEffect(() => {
    setUser(getStoredJson(STORAGE_KEYS.USER));

    // Check KYC status
    checkKycStatus().then(setKycStatus);
  }, []);

  const myProjects = requests.filter(r => 
      // 1. Assigned directly
      r.brokerId === user?.id 
      || 
      // 2. Has ACCEPTED proposal (Meaning invited and accepted)
      r.brokerProposals?.some((p: any) => p.brokerId === user?.id && p.status === 'ACCEPTED')
  );

  // TODO: Get this from real Auth Context
  // const MOCK_BROKER_ID = 'b0eebc99-9c0b-4ef8-bb6d-6bb9bd380b22';

  const fetchRequests = async () => {
    try {
      setLoading(true);
      const data = await projectRequestsApi.getAll();
      setRequests(data);
    } catch (error) {
      console.error('Failed to fetch requests:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleAssign = async (requestId: string) => {
    if (!confirm('Are you sure you want to assign this request to yourself?')) return;
    
    try {
      setAssigningId(requestId);
      await projectRequestsApi.assignBroker(requestId);
      // Refresh list after successful assignment
      await fetchRequests();
      alert('Request assigned successfully!');
    } catch (error: any) {
      console.error('Failed to assign request:', error);
      alert(error.response?.data?.message || 'Failed to assign request');
    } finally {
      setAssigningId(null);
    }
  };

  const handleApply = async (requestId: string, coverLetter: string) => {
     try {
        await projectRequestsApi.applyToRequest(requestId, coverLetter);
        alert("Application submitted successfully!");
        fetchRequests();
     } catch (error: any) {
        console.error(error);
        alert(error.response?.data?.message || "Failed to apply");
     }
  };

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-teal-600" />
      </div>
    );
  }

  // Block access if KYC not approved
  if (kycStatus && kycStatus !== 'APPROVED') {
    return (
      <KYCBlocker 
        kycStatus={kycStatus} 
        role="broker" 
        action="apply to project requests"
      />
    );
  }

  return (
    <div className="container mx-auto py-10">
      <div className="mb-8 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Marketplace Requests</h1>
          <p className="text-muted-foreground">
            Browse and apply to public project requests from clients.
          </p>
        </div>
      </div>
      
      <div className="rounded-md bg-white p-4 shadow-sm">
        <ProjectRequestsTable 
            requests={requests.filter(r => r.status === 'PUBLIC_DRAFT' && !r.brokerId)} 
            onAssign={handleAssign}
            onApply={handleApply}
            assigningId={assigningId}
            currentUserId={user?.id}
        />
      </div>
    </div>
  );
};

﻿import { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';
import { Button } from '@/shared/components/custom/Button';
import { CreateProjectSpecForm } from './components/CreateProjectSpecForm';
import { projectRequestsApi } from '../project-requests/api';
import { projectSpecsApi } from './api';
import type { ProjectRequest } from '../project-requests/types';
import type { CreateProjectSpecDTO } from './types';
import Spinner from '@/shared/components/ui/Spinner';
import { Alert, AlertDescription, AlertTitle } from '@/shared/components/ui/alert';

export default function CreateProjectSpecPage() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [request, setRequest] = useState<ProjectRequest | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    console.log('[CreateProjectSpecPage] URL param id:', id, 'type:', typeof id);
    if (!id) {
      console.error('[CreateProjectSpecPage] No id from URL params!');
      return;
    }
    const fetchRequest = async () => {
      try {
        setIsLoading(true);
        const data = await projectRequestsApi.getById(id);
        console.log('[CreateProjectSpecPage] Fetched request:', data);
        setRequest(data);
      } catch (err) {
        console.error('Failed to fetch request:', err);
        setError('Could not load project request details.');
      } finally {
        setIsLoading(false);
      }
    };
    fetchRequest();
  }, [id]);

  const handleSubmit = async (data: CreateProjectSpecDTO) => {
    try {
      setIsSubmitting(true);
      setSubmitError(null);
      const newSpec = await projectSpecsApi.createSpec(data);
      console.log('Spec created:', newSpec);
      // Redirect to request details or the new spec details (when we have a page for it)
      // For now back to request details
      alert('Project Specification created successfully!');
      navigate(`/project-requests/${id}`);
    } catch (err) {
      console.error('Failed to create spec:', err);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const message = (err as any).response?.data?.message || 'Failed to create project specification.';
      setSubmitError(message);
      setIsSubmitting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex h-[50vh] items-center justify-center">
        <Spinner size="lg" />
      </div>
    );
  }

  if (!request) {
    return (
      <div className="container mx-auto py-8">
        <Alert variant="destructive">
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>{error || 'Request not found'}</AlertDescription>
        </Alert>
        <Button variant="outline" className="mt-4" onClick={() => navigate('/project-requests')}>
          <ArrowLeft className="w-4 h-4 mr-2" /> Back to Requests
        </Button>
      </div>
    );
  }

  return (
    <div className="container mx-auto py-8 max-w-4xl space-y-6">
       <div className="flex items-center gap-4">
        <Button variant="outline" className="h-9 w-9 p-0" onClick={() => navigate(`/project-requests/${id}`)}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Create Specification</h1>
          <p className="text-muted-foreground">For request: {request.title}</p>
        </div>
      </div>

      {submitError && (
         <Alert variant="destructive">
            <AlertTitle>Submission Error</AlertTitle>
            <AlertDescription>{submitError}</AlertDescription>
         </Alert>
      )}

      <CreateProjectSpecForm 
        requestId={id!} // Validated by useEffect
        projectRequest={request}
        onSubmit={handleSubmit}
        isSubmitting={isSubmitting}
      />
    </div>
  );
}

