const safeFormatDate = (dateStr: any, fmt: string) => {
    try {
        if (!dateStr) return "N/A";
        const d = new Date(dateStr);
        if (isNaN(d.getTime())) return "Invalid Date";
        return format(d, fmt);
    } catch (e) {
        return "N/A";
    }
};

