                                        <span className="flex items-center text-green-600"><Check className="w-4 h-4 mr-1"/> Freelancer Signed</span>
                                    </div>
                                    <Button size="lg" className="bg-gradient-to-r from-green-600 to-emerald-600" onClick={() => wizardService.convertToProject(request.id).then(() => { toast.success("Project Started!"); navigate(ROUTES.CLIENT_DASHBOARD); })}>
                                        Sign & Start Project
                                    </Button>
                                </div>
                             </div>
                        )}
                    </CardContent>
                </Card>
            </TabsContent>
          </Tabs>
        </>
        )}

        {viewMode === 'details' && (
            <>
                <Card className="mb-6 border-indigo-100 bg-indigo-50/30">
                    <CardHeader>
                        <div className="flex justify-between items-center">
                            <h2 className="text-xl font-semibold flex items-center gap-2">
                                <Users className="w-5 h-5 text-indigo-600" /> Project Team
                            </h2>
                            <Button variant="outline" size="sm" onClick={() => navigate(`/client/discovery?role=${UserRole.FREELANCER}`)}>
                                <UserPlus className="w-4 h-4 mr-2" /> Add Member
                            </Button>
