                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold border-2 border-indigo-200">
                                    {request.broker ? request.broker.fullName.charAt(0) : "B"}
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h3 className="font-semibold text-lg">{request.broker?.fullName || "No Broker Assigned"}</h3>
                                        {request.broker && <Badge variant="secondary" className="bg-indigo-100 text-indigo-700">Broker</Badge>}
                                    </div>
                                    <p className="text-sm text-muted-foreground">{request.broker?.email || "Assign a broker to lead this project."}</p>
                                </div>
                            </div>
                            {request.broker ? (
                                <Button variant="ghost" size="sm">View Profile</Button>
                            ) : (
                                <Button size="sm" onClick={() => setActiveTab('phase1')}>Find Broker</Button>
                            )}
                        </div>

                        {/* Freelancer/Team Members Section */}
                        {/* Logic: Show freelancers who have ACCEPTED invitations or are formally hired (future logic) */}
                        <div className="space-y-2">
                            <h4 className="text-sm font-medium text-muted-foreground uppercase tracking-wider">Freelancers & Candidates</h4>
                            {(!request.brokerProposals && !request.freelancerProposals) || 
                             (request.brokerProposals?.filter((p:any) => p.status === 'ACCEPTED').length === 0) ? (
                                <div className="text-center py-4 text-muted-foreground text-sm italic">
                                    No team members yet.
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                     {/* Show ACCEPTED candidates */}
                                     {request.brokerProposals?.filter((p:any) => p.status === 'ACCEPTED' && p.brokerId !== request.brokerId).map((p:any) => (
                                         <div key={p.id} className="flex items-center gap-3 p-3 bg-white rounded border">
                                             <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center font-bold text-gray-600">
                                                 {p.broker?.fullName.charAt(0)}
                                             </div>
                                             <div className="overflow-hidden">
                                                 <p className="font-medium truncate">{p.broker?.fullName}</p>
                                                 <Badge variant="outline" className="text-[10px] h-5">Candidate (Accepted)</Badge>
                                             </div>
                                         </div>
                                     ))}
                                </div>
                            )}
                        </div>
                    </CardContent>
                </Card>

              <Card>
                <CardHeader>
                  <h2 className="text-xl font-semibold">Project Details</h2>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <h3 className="text-sm font-medium text-muted-foreground">
                        Budget Range
                      </h3>
                      <p className="font-semibold text-lg">
                        {request.budgetRange || "Not specified"}
                      </p>
                    </div>
                    <div>
                      <h3 className="text-sm font-medium text-muted-foreground">
                        Timeline
                      </h3>
                      <p className="font-semibold text-lg">
                        {request.intendedTimeline || "Not specified"}
                      </p>
                    </div>
                    <div className="col-span-full">
                      <h3 className="text-sm font-medium text-muted-foreground mb-2">
                        Description
                      </h3>
                      <div className="bg-muted/30 p-4 rounded-lg">
                        <p className="whitespace-pre-wrap leading-relaxed">
                          {request.description}
                        </p>
                      </div>
                    </div>
                    <div className="col-span-full">
                      <h3 className="text-sm font-medium text-muted-foreground mb-2">
                        Tech Preferences & Features
                      </h3>
                      <div className="flex gap-2 flex-wrap">
                        {request.techPreferences ? (
                          request.techPreferences
                            .split(",")
                            .map((t: string) => (
                              <Badge
                                key={t}
                                variant="secondary"
                                className="px-3 py-1"
                              >
                                {t.trim()}
                              </Badge>
                            ))
                        ) : (
                          <span className="text-sm text-muted-foreground italic">
                            No specific preferences listed
                          </span>
                        )}
                      </div>
                    </div>

                    <div className="col-span-full border-t pt-6 mt-4">
                        <div className="flex items-center gap-2 mb-4">
                            <div className="p-2 bg-primary/10 rounded-lg">
                                <FileText className="w-5 h-5 text-primary" />
                            </div>
                            <div>
                                <h3 className="text-lg font-semibold">Initial Client Brief</h3>
                                <p className="text-sm text-muted-foreground">
                                    Preliminary requirements and scope as defined by the client.
                                </p>
                            </div>
                        </div>
                        
                        <div className="bg-muted/30 rounded-xl p-6 border space-y-6">
                            {request.answers?.map((ans: any) => (
                                <div key={ans.id} className="grid grid-cols-1 md:grid-cols-12 gap-2 md:gap-4 border-b border-border/50 pb-4 last:border-0 last:pb-0">
                                    <div className="md:col-span-4 lg:col-span-3">
                                        <h4 className="text-sm font-medium text-muted-foreground">
                                            {ans.question?.text || "Requirement"}
                                        </h4>
                                    </div>
                                    <div className="md:col-span-8 lg:col-span-9">
                                        <p className="font-medium text-base text-foreground leading-relaxed">
                                            {ans.option?.label || ans.valueText || "N/A"}
                                        </p>
                                    </div>
                                </div>
                            ))}
                            {(!request.answers || request.answers.length === 0) && (
                                <div className="text-center py-8 text-muted-foreground italic">
                                    No initial specification data provided in the wizard.
                                </div>
                            )}
                        </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </>
        )}
        </div>

        {/* Right Sidebar: Comments */}
        <div className="lg:col-span-1">
          <div className="sticky top-6">
            <CommentsSection />
          </div>
        </div>
      </div>

      {inviteModalData && (
        <InviteModal 
            isOpen={isInviteModalOpen}
            onClose={() => setIsInviteModalOpen(false)}
            partnerId={inviteModalData.id}
            partnerName={inviteModalData.name}
            partnerRole={inviteModalData.role}
            defaultRequestId={request?.id}
            onInviteSuccess={() => id && fetchData(id)}
        />
      )}
    </div>
  );
}

import { useState } from "react";
import { Button, Card, CardContent, CardHeader } from "@/shared/components/ui";
import { Textarea } from "@/shared/components/ui/textarea";
import { Avatar, AvatarFallback } from "@/shared/components/ui/avatar";
import { Send } from "lucide-react";

interface Comment {
  id: string;
  user: string;
  avatar?: string;
  text: string;
  timestamp: Date;
  isMe: boolean;
}

export function CommentsSection() {
  const [comments, setComments] = useState<Comment[]>([
    {
      id: "1",
      user: "System",
      text: "Request created. Waiting for a broker to be assigned.",
      timestamp: new Date(Date.now() - 86400000),
      isMe: false,
    },
  ]);
  const [newComment, setNewComment] = useState("");

  const handleSend = () => {
    if (!newComment.trim()) return;

    const comment: Comment = {
      id: Date.now().toString(),
      user: "You",
      text: newComment,
      timestamp: new Date(),
      isMe: true,
    };

    setComments([...comments, comment]);
    setNewComment("");
  };

  return (
    <Card className="h-full flex flex-col">
      <CardHeader className="pb-3 border-b">
        <h3 className="font-semibold">Project Discussion</h3>
      </CardHeader>
      <CardContent className="flex-1 flex flex-col pt-4 gap-4 h-[400px]">
        <div className="flex-1 overflow-y-auto space-y-4 pr-2">
          {comments.map((comment) => (
            <div
              key={comment.id}
              className={`flex gap-3 ${comment.isMe ? "flex-row-reverse" : ""}`}
            >
              <Avatar className="w-8 h-8">
                <AvatarFallback>{comment.user.charAt(0)}</AvatarFallback>
              </Avatar>
              <div
                className={`max-w-[80%] rounded-lg p-3 text-sm ${
                  comment.isMe
                    ? "bg-primary text-primary-foreground"
                    : "bg-muted"
                }`}
              >
                <p>{comment.text}</p>
                <span className="text-[10px] opacity-70 block mt-1 text-right">
                  {comment.timestamp.toLocaleTimeString([], {
                    hour: "2-digit",
                    minute: "2-digit",
                  })}
                </span>
              </div>
            </div>
          ))}
        </div>

        <div className="flex gap-2 mt-2 pt-2 border-t">
          <Textarea
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
            placeholder="Type a message..."
            className="min-h-[40px] max-h-[100px] resize-none"
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
          />
          <Button
            size="icon"
            onClick={handleSend}
            disabled={!newComment.trim()}
          >
            <Send className="w-4 h-4" />
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useEffect, useState } from "react";
import { Outlet, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { StaffSidebar } from "./StaffSidebar";
import { StaffHeader } from "./StaffHeader";
import { ROUTES, STORAGE_KEYS } from "@/constants";
import { getStoredItem } from "@/shared/utils/storage";

export const StaffLayout = () => {
  const [collapsed, setCollapsed] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const userJson = getStoredItem(STORAGE_KEYS.USER);
    if (!userJson) {
      navigate(ROUTES.LOGIN);
      return;
    }

    try {
      const user = JSON.parse(userJson);
      // Strict Role Check
      if (user.role !== "STAFF" && user.role !== "ADMIN") {
        // Admin can access too typically
        toast.error("Access Denied: Staff only area");
        navigate("/client"); // Send back to client dashboard or home
      }
    } catch (e) {
      navigate(ROUTES.LOGIN);
    }
  }, [navigate]);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Sidebar Component */}
      <StaffSidebar
        collapsed={collapsed}
        onToggle={() => setCollapsed(!collapsed)}
      />

      {/* Main Content Area */}
      <div
        className={`transition-all duration-300 min-h-screen flex flex-col
          ${collapsed ? "ml-20" : "ml-64"}
        `}
      >
        {/* Header Component */}
        <StaffHeader collapsed={collapsed} />

        {/* Page Content */}
        <main className="flex-1 p-6 mt-16 overflow-x-hidden">
          <div className="w-full max-w-[1440px] mx-auto">
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
};

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Button, Card, CardContent, CardFooter, CardHeader, Progress, Spinner } from "@/shared/components/ui";
import { StepB1 } from "./components/StepB1";
import { StepB2 } from "./components/StepB2";
import { StepB3 } from "./components/StepB3";
import { StepB4 } from "./components/StepB4";
import { StepB5 } from "./components/StepB5";
import { wizardService } from "./services/wizardService";
import type { WizardQuestion, CreateProjectRequestDto } from "./services/wizardService";
import { ROUTES, API_CONFIG } from "@/constants";
import { ArrowLeft, ArrowRight, Check, AlertCircle } from "lucide-react";
import { toast } from "sonner";
import { KYCBlocker } from "@/shared/components/custom/KYCBlocker";

export default function WizardPage() {
  const navigate = useNavigate();
  
  const [currentStep, setCurrentStep] = useState(1);
  const [questions, setQuestions] = useState<WizardQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [kycStatus, setKycStatus] = useState<string | null>(null);

  const [requestId, setRequestId] = useState<string | null>(null);
  
  // Form State
  const [productType, setProductType] = useState<string>("");
  const [industry, setIndustry] = useState<string>("");
  const [budget, setBudget] = useState<string>("");
  const [timeline, setTimeline] = useState<string>("");
  const [features, setFeatures] = useState<string[]>([]);
  const [title, setTitle] = useState<string>("");
  const [description, setDescription] = useState<string>("");
  const [fileUrl, setFileUrl] = useState<string>("");

  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const data = await wizardService.getQuestions();
        setQuestions(data);
      } catch (error) {
        toast.error("Lỗi tải dữ liệu", {
            description: "Không thể tải danh sách câu hỏi. Vui lòng thử lại sau.",
        });
      } finally {
        setLoading(false);
      }
    };

    const checkKycStatus = async () => {
      try {
        const response = await fetch(`${API_CONFIG.BASE_URL}/kyc/me`, {
          credentials: 'include', // Send httpOnly cookies
        });
        const data = await response.json();
        setKycStatus(data.status || 'NOT_STARTED');
      } catch (error) {
        console.error('Error checking KYC:', error);
      }
    };

    fetchQuestions();
    checkKycStatus();
  }, []);

  const totalSteps = 5;
  const progress = (currentStep / totalSteps) * 100;

  const handleNext = () => {
    if (currentStep < totalSteps) setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const handleSubmit = async (mode: 'draft' | 'marketplace' | 'invite') => {
     try {
        const isDraftMode = mode === 'draft';
        setSubmitting(true);

        // Check KYC before submitting project (if not draft)
        if (!isDraftMode && kycStatus !== 'APPROVED') {
          if (kycStatus === 'NOT_STARTED' || kycStatus === 'REJECTED') {
            toast.error('KYC verification required', {
              description: 'Please complete KYC verification before posting a project.',
            });
            setTimeout(() => {
              navigate('/kyc');
            }, 2000);
            return;
          }
          
          if (kycStatus === 'PENDING') {
            toast.warning('KYC verification pending', {
              description: 'Your KYC is being reviewed. You can save as draft or wait for approval.',
            });
            return;
          }
        }
        
        // Map questions to answers
        const payload: CreateProjectRequestDto = {
            title: title || (isDraftMode ? "Draft Project Request" : "New Project Request"),
            description: description + (fileUrl ? `\n\nAttachments: ${fileUrl}` : ""),
            budgetRange: budget,
            intendedTimeline: timeline,
            isDraft: isDraftMode,
            answers: []
        };
        // Find IDs for questions
        const typeQ = questions.find(q => q.code === 'PRODUCT_TYPE');
        const industryQ = questions.find(q => q.code === 'INDUSTRY');
        const featureQ = questions.find(q => q.code === 'FEATURES');

        // B1
        if (typeQ && productType) {
            payload.answers.push({
                questionId: typeQ.id,
                valueText: productType
            });
        }
        // B2
        if (industryQ && industry) {
            payload.answers.push({
                questionId: industryQ.id,
                valueText: industry
            });
        }
        // B4 - Multi select
        if (featureQ && features.length > 0) {
            features.forEach(feat => {
                payload.answers.push({
                    questionId: featureQ.id,
                    valueText: feat
                });
            });
        }

        let savedRequest;
        if (requestId) {
            // Update existing
            savedRequest = await wizardService.updateRequest(requestId, payload);
        } else {
            // Create new
            savedRequest = await wizardService.submitRequest(payload);
            setRequestId(savedRequest.id);
        }
        
        if (mode === 'draft') {
            toast.success("Saved as Draft!", {
                description: "You can continue editing later.",
            });
            // Stay on page or navigate to drafts?
            // navigate(ROUTES.CLIENT_DASHBOARD);
        } else if (mode === 'marketplace') {
             toast.success("Posted to Marketplace!", {
                description: "Your request is now visible to brokers.",
             });
             navigate(ROUTES.CLIENT_DASHBOARD);
        } else if (mode === 'invite') {
             toast.success("Project Created!", {
                description: "Redirecting to find brokers...",
             });
             // Redirect to detail page with recruitment tab active and 'find' action
             navigate(`/client/requests/${savedRequest.id}?tab=recruitment&action=find`);
        } 

     } catch (error) {
        toast.error("Submission Failed", {
            description: "An error occurred. Please try again.",
        });
     } finally {
        setSubmitting(false);
     }
  };

  // Helper to get question object
  const getQuestion = (code: string) => questions.find(q => q.code === code);

  if (loading) {
      return <div className="min-h-screen flex items-center justify-center"><Spinner size="lg" /></div>;
  }

  // Block access if KYC not approved
  if (kycStatus && kycStatus !== 'APPROVED') {
    return (
      <div className="min-h-screen bg-background">
        <KYCBlocker 
          kycStatus={kycStatus} 
          role="client" 
          action="create project requests"
        />
      </div>
    );
  }



  return (
    <div className="min-h-screen bg-background flex flex-col items-center pt-10 pb-10 px-4">
      
      <div className="w-full max-w-4xl mb-8 space-y-2">
        <div className="flex justify-between text-sm font-medium text-muted-foreground">
            <span>Step {currentStep} of {totalSteps}</span>
            <span>{Math.round(progress)}%</span>
        </div>
        <Progress value={progress} className="h-2" />
      </div>

      {/* KYC Warning Banner */}
      {kycStatus && kycStatus !== 'APPROVED' && (
        <div className={`w-full max-w-4xl rounded-lg border p-4 mb-6 ${
          kycStatus === 'PENDING' 
            ? 'bg-yellow-50 border-yellow-200' 
            : 'bg-blue-50 border-blue-200'
        }`}>
          <div className="flex items-start gap-3">
            <AlertCircle className={`w-5 h-5 mt-0.5 ${
              kycStatus === 'PENDING' ? 'text-yellow-600' : 'text-blue-600'
            }`} />
            <div className="flex-1">
              <h3 className={`font-semibold ${
                kycStatus === 'PENDING' ? 'text-yellow-800' : 'text-blue-800'
              }`}>
                {kycStatus === 'PENDING' 
                  ? 'KYC Verification Pending' 
                  : 'KYC Verification Required'}
              </h3>
              <p className={`text-sm mt-1 ${
                kycStatus === 'PENDING' ? 'text-yellow-700' : 'text-blue-700'
              }`}>
                {kycStatus === 'PENDING' 
                  ? 'Your KYC is being reviewed. You can save as draft or wait for approval to submit.' 
                  : 'Please complete KYC verification to post projects.'}
              </p>
              {kycStatus !== 'PENDING' && (
                <button
                  onClick={() => navigate('/kyc')}
                  className="text-sm font-medium text-blue-600 hover:text-blue-700 mt-2 underline"
                >
                  Complete KYC Now →
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      <Card className="w-full max-w-4xl border-none shadow-xl bg-card/50 backdrop-blur-sm">
        <CardHeader></CardHeader>
        <CardContent className="min-h-[400px] p-6 md:p-10">
            {currentStep === 1 && getQuestion('PRODUCT_TYPE') && (
                <StepB1 
                    question={getQuestion('PRODUCT_TYPE')!} 
                    value={productType}
                    onChange={setProductType}
                />
            )}
            {currentStep === 2 && getQuestion('INDUSTRY') && (
                <StepB2 
                    question={getQuestion('INDUSTRY')!}
                    value={industry}
                    onChange={setIndustry}
                />
            )}
            {currentStep === 3 && (
                <StepB3 
                    budget={budget}
                    setBudget={setBudget}
                    timeline={timeline}
                    setTimeline={setTimeline}
                />
            )}
            {currentStep === 4 && getQuestion('FEATURES') && (
                <StepB4 
                    question={getQuestion('FEATURES')!}
                    selectedValues={features}
                    onChange={setFeatures}
                />
            )}
            {currentStep === 5 && (
                <StepB5 
                    title={title}
                    setTitle={setTitle}
                    description={description}
                    setDescription={setDescription}
                    onFileUploaded={setFileUrl}
                />
            )}
        </CardContent>

        <CardFooter className="flex justify-between p-6 bg-muted/20 border-t rounded-b-xl">
            <Button 
                variant="outline" 
                onClick={handleBack} 
                disabled={currentStep === 1}
                className="w-32"
            >
                <ArrowLeft className="w-4 h-4 mr-2" /> Back
            </Button>
            
            {currentStep < totalSteps ? (
                <Button onClick={() => handleNext()} className="w-32" disabled={
                    // Basic validation
                    (currentStep === 1 && !productType) ||
                    (currentStep === 2 && !industry)
                }>
                    Next <ArrowRight className="w-4 h-4 ml-2" />
                </Button>
            ) : (
                <div className="flex gap-4">
                    <Button 
                        onClick={() => handleSubmit('draft')} 
                        disabled={submitting} 
                        variant="secondary"
                        className="w-32"
                    >
                        Save Draft
                    </Button>
                    <Button 
                        onClick={() => handleSubmit('marketplace')} 
                        disabled={submitting || !title || !description} 
                        className="w-40 bg-blue-600 hover:bg-blue-700"
                    >
                        Post to Market
                    </Button>
                    <Button 
                        onClick={() => handleSubmit('invite')} 
                        disabled={submitting || !title || !description} 
                        className="w-48 bg-green-600 hover:bg-green-700"
                    >
                        <Check className="w-4 h-4 mr-2" />
                        Find & Invite
                    </Button>
                </div>
            )}
        </CardFooter>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { Eye, Clock, CheckCircle, XCircle, AlertCircle } from 'lucide-react';
import { toast } from 'sonner';
import { apiClient } from '@/shared/api/client';
import { KYCVerificationModal } from '@/shared/components/figma/kycmodal';

interface KycVerification {
  id: string;
  fullNameOnDocument: string;
  documentNumber: string;
  documentType: string;
  dateOfBirth: string;
  documentFrontUrl: string;
  documentBackUrl: string;
  selfieUrl: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  rejectionReason?: string;
  createdAt: string;
  reviewedAt?: string;
  user: {
    id: string;
    email: string;
    fullName: string;
    role: string;
    avatarUrl?: string;
    profile?: {
      avatarUrl?: string;
    };
  };
  reviewer?: {
    fullName: string;
  };
}

export default function AdminKYCPage() {
  const [kycs, setKycs] = useState<KycVerification[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'ALL' | 'PENDING' | 'APPROVED' | 'REJECTED'>('PENDING');
  const [selectedKyc, setSelectedKyc] = useState<KycVerification | null>(null);
  const [showModal, setShowModal] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);

  const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3000';

  // Helper function to get full image URL
  const getImageUrl = (path: string) => {
    if (!path) return '';
    if (path.startsWith('http') || path.startsWith('data:image')) return path;
    return `${API_URL}${path}`;
  };

  useEffect(() => {
    fetchKycs();
  }, [filter]);

  const fetchKycs = async () => {
    try {
      setLoading(true);
      const statusParam = filter === 'ALL' ? '' : `?status=${filter}`;
      const response = await apiClient.get(`/kyc/admin/all${statusParam}`);
      
      // apiClient already unwraps response.data
      const data = response as { items: KycVerification[] };
      setKycs(data.items || []);
    } catch (error: any) {
      console.error('Error fetching KYCs:', error);
      console.error('Error response:', error.response);
      toast.error(error.response?.data?.message || 'Failed to load KYC verifications');
    } finally {
      setLoading(false);
    }
  };

  const openReview = async (kyc: KycVerification) => {
    setSelectedKyc(kyc);
    setShowModal(true);

    try {
      const response = await apiClient.get(`/kyc/admin/${kyc.id}/watermark`);
      setSelectedKyc(response as KycVerification);
    } catch (error: any) {
      console.error('Error loading KYC details:', error);
      toast.error(error.response?.data?.message || 'Failed to load KYC images');
    }
  };

  const closeModal = () => {
    setShowModal(false);
    setSelectedKyc(null);
  };

  const handleApprove = async (id: string) => {
    try {
      setActionLoading(true);
      await apiClient.patch(`/kyc/admin/${id}/approve`);
      toast.success('KYC approved successfully');
      fetchKycs();
      closeModal();
    } catch (error: any) {
      toast.error(error.response?.data?.message || 'Failed to approve KYC');
    } finally {
      setActionLoading(false);
    }
  };

  const handleReject = async (id: string, reason?: string) => {
    if (!reason?.trim()) {
      toast.error('Please provide a rejection reason');
      return;
    }

    try {
      setActionLoading(true);
      await apiClient.patch(`/kyc/admin/${id}/reject`, { rejectionReason: reason });
      toast.success('KYC rejected');
      fetchKycs();
      closeModal();
    } catch (error: any) {
      toast.error(error.response?.data?.message || 'Failed to reject KYC');
    } finally {
      setActionLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    const styles = {
      PENDING: 'bg-yellow-100 text-yellow-800',
      APPROVED: 'bg-green-100 text-green-800',
      REJECTED: 'bg-red-100 text-red-800',
    };

    const icons = {
      PENDING: <Clock className="w-4 h-4" />,
      APPROVED: <CheckCircle className="w-4 h-4" />,
      REJECTED: <XCircle className="w-4 h-4" />,
    };

    return (
      <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-sm font-medium ${styles[status as keyof typeof styles]}`}>
        {icons[status as keyof typeof icons]}
        {status}
      </span>
    );
  };

  const getRoleKey = (role: string): 'sme' | 'broker' | 'freelancer' => {
    const normalized = role.toLowerCase();
    if (normalized.includes('broker')) return 'broker';
    if (normalized.includes('freelancer')) return 'freelancer';
    if (normalized.includes('sme') || normalized.includes('client')) return 'sme';
    return 'sme';
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">KYC Verification Management</h1>
          <p className="text-gray-600 mt-2">Review and verify user identity documents</p>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-lg shadow mb-6 p-4">
          <div className="flex gap-2">
            {['ALL', 'PENDING', 'APPROVED', 'REJECTED'].map((status) => (
              <button
                key={status}
                onClick={() => setFilter(status as any)}
                className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                  filter === status
                    ? 'bg-blue-600 text-white'
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}
              >
                {status}
              </button>
            ))}
          </div>
        </div>

        {/* KYC List */}
        {loading ? (
          <div className="text-center py-12">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
          </div>
        ) : kycs.length === 0 ? (
          <div className="bg-white rounded-lg shadow p-12 text-center">
            <AlertCircle className="w-16 h-16 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-500">No KYC verifications found</p>
          </div>
        ) : (
          <div className="bg-white rounded-lg shadow overflow-hidden">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    User
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Document Info
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Submitted
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {kycs.map((kyc) => (
                  <tr key={kyc.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4">
                      <div>
                        <div className="text-sm font-medium text-gray-900">{kyc.user.fullName}</div>
                        <div className="text-sm text-gray-500">{kyc.user.email}</div>
                        <span className="text-xs text-gray-400">{kyc.user.role}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div>
                        <div className="text-sm font-medium text-gray-900">{kyc.fullNameOnDocument}</div>
                        <div className="text-sm text-gray-500">{kyc.documentType}: {kyc.documentNumber}</div>
                        <div className="text-xs text-gray-400">DOB: {format(new Date(kyc.dateOfBirth), 'dd/MM/yyyy')}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-500">
                      {format(new Date(kyc.createdAt), 'dd/MM/yyyy HH:mm')}
                    </td>
                    <td className="px-6 py-4">
                      {getStatusBadge(kyc.status)}
                    </td>
                    <td className="px-6 py-4 text-sm">
                      <button
                        onClick={() => openReview(kyc)}
                        className="text-blue-600 hover:text-blue-800 font-medium flex items-center gap-1"
                      >
                        <Eye className="w-4 h-4" />
                        Review
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Review Modal */}
        {selectedKyc && (
          <KYCVerificationModal
            isOpen={showModal}
            onClose={closeModal}
            kycData={{
              userId: selectedKyc.id,
              userName: selectedKyc.user.fullName,
              userEmail: selectedKyc.user.email,
              userRole: getRoleKey(selectedKyc.user.role),
              avatarImage: getImageUrl(
                selectedKyc.user.avatarUrl || selectedKyc.user.profile?.avatarUrl || ''
              ),
              idCardFront: getImageUrl(selectedKyc.documentFrontUrl),
              idCardBack: getImageUrl(selectedKyc.documentBackUrl),
              selfieImage: getImageUrl(selectedKyc.selfieUrl),
              submittedAt: format(new Date(selectedKyc.createdAt), 'dd/MM/yyyy HH:mm'),
              status: selectedKyc.status.toLowerCase() as 'pending' | 'approved' | 'rejected',
              rejectionReason: selectedKyc.rejectionReason,
            }}
            onApprove={(kycId) => {
              if (actionLoading) return;
              if (selectedKyc.status !== 'PENDING') {
                toast.info('This KYC has already been reviewed.');
                return;
              }
              handleApprove(kycId);
            }}
            onReject={(kycId, reason) => {
              if (actionLoading) return;
              if (selectedKyc.status !== 'PENDING') {
                toast.info('This KYC has already been reviewed.');
                return;
              }
              handleReject(kycId, reason);
            }}
          />
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Search, Ban, UserCheck, Key, Shield, AlertCircle, X } from 'lucide-react';
import { toast } from 'sonner';

interface User {
  id: string;
  email: string;
  fullName: string;
  role: string;
  phoneNumber?: string;
  isVerified: boolean;
  isBanned: boolean;
  banReason?: string;
  bannedAt?: string;
  currentTrustScore: number;
  totalProjectsFinished: number;
  totalDisputesLost: number;
  createdAt: string;
}

interface UserStats {
  total: number;
  banned: number;
  verified: number;
  byRole: Record<string, number>;
}

interface UserDetail extends User {
  kyc?: {
    id?: string;
    status?: string;
    documentFrontUrl?: string;
    documentBackUrl?: string;
    rejectionReason?: string;
    createdAt?: string;
    reviewedAt?: string;
  };
}

export default function AdminUsersPage() {
  const [users, setUsers] = useState<User[]>([]);
  const [stats, setStats] = useState<UserStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [detailUser, setDetailUser] = useState<UserDetail | null>(null);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [detailLoading, setDetailLoading] = useState(false);
  
  // Filters
  const [roleFilter, setRoleFilter] = useState<string>('');
  const [searchQuery, setSearchQuery] = useState('');
  const [banFilter, setBanFilter] = useState<string>('');
  
  // Pagination
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  
  // Modals
  const [showBanModal, setShowBanModal] = useState(false);
  const [showUnbanModal, setShowUnbanModal] = useState(false);
  const [showResetPasswordModal, setShowResetPasswordModal] = useState(false);
  const [banReason, setBanReason] = useState('');
  const [unbanReason, setUnbanReason] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [sendEmail, setSendEmail] = useState(true);

  const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3000';

  // Fetch users
  useEffect(() => {
    fetchUsers();
    fetchStats();
  }, [page, roleFilter, searchQuery, banFilter]);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams({
        page: page.toString(),
        limit: '20',
      });
      
      if (roleFilter) params.append('role', roleFilter);
      if (searchQuery) params.append('search', searchQuery);
      if (banFilter) params.append('isBanned', banFilter);

      const response = await fetch(`${API_URL}/users?${params}`, {
        credentials: 'include',
      });

      if (!response.ok) throw new Error('Failed to fetch users');

      const data = await response.json();
      setUsers(data.users);
      setTotalPages(data.totalPages);
    } catch (error: any) {
      toast.error(error.message || 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await fetch(`${API_URL}/users/admin/statistics`, {
        credentials: 'include',
      });

      if (!response.ok) throw new Error('Failed to fetch stats');

      const data = await response.json();
      setStats(data);
    } catch (error: any) {
      console.error('Failed to fetch stats:', error);
    }
  };

  const openUserDetail = async (user: User) => {
    try {
      setDetailLoading(true);
      setShowDetailModal(true);
      const response = await fetch(`${API_URL}/users/${user.id}`, {
        credentials: 'include',
      });

      if (!response.ok) throw new Error('Failed to load user detail');
      const data = await response.json();
      const baseDetail = data as UserDetail;

      if (baseDetail.kyc?.id) {
        try {
          const kycResponse = await fetch(
            `${API_URL}/kyc/admin/${baseDetail.kyc.id}/watermark`,
            { credentials: 'include' }
          );
          if (kycResponse.ok) {
            const kycData = await kycResponse.json();
            setDetailUser({
              ...baseDetail,
              kyc: {
                ...baseDetail.kyc,
                status: kycData.status,
                rejectionReason: kycData.rejectionReason,
                documentFrontUrl: kycData.documentFrontUrl,
                documentBackUrl: kycData.documentBackUrl,
              },
            });
          } else {
            setDetailUser(baseDetail);
          }
        } catch {
          setDetailUser(baseDetail);
        }
      } else {
        setDetailUser(baseDetail);
      }
    } catch (error: any) {
      toast.error(error.message || 'Failed to load user detail');
      setShowDetailModal(false);
    } finally {
      setDetailLoading(false);
    }
  };

  const closeUserDetail = () => {
    setShowDetailModal(false);
    setDetailUser(null);
  };

  const handleBanUser = async () => {
    if (!selectedUser || !banReason.trim()) {
      toast.error('Please provide a reason');
      return;
    }

    try {
      const response = await fetch(`${API_URL}/users/${selectedUser.id}/ban`, {
        method: 'PATCH',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ reason: banReason }),
      });

      if (!response.ok) throw new Error('Failed to ban user');

      toast.success('User banned successfully');
      setShowBanModal(false);
      setBanReason('');
      fetchUsers();
    } catch (error: any) {
      toast.error(error.message || 'Failed to ban user');
    }
  };

  const handleUnbanUser = async () => {
    if (!selectedUser || !unbanReason.trim()) {
      toast.error('Please provide a reason');
      return;
    }

    try {
      const response = await fetch(`${API_URL}/users/${selectedUser.id}/unban`, {
        method: 'PATCH',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ reason: unbanReason }),
      });

      if (!response.ok) throw new Error('Failed to unban user');

      toast.success('User unbanned successfully');
      setShowUnbanModal(false);
      setUnbanReason('');
      fetchUsers();
    } catch (error: any) {
      toast.error(error.message || 'Failed to unban user');
    }
  };

  const handleResetPassword = async () => {
    if (!selectedUser || !newPassword.trim()) {
      toast.error('Please provide a new password');
      return;
    }

    try {
      const response = await fetch(`${API_URL}/users/${selectedUser.id}/reset-password`, {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ newPassword, sendEmail }),
      });

      if (!response.ok) throw new Error('Failed to reset password');

      toast.success('Password reset successfully');
      setShowResetPasswordModal(false);
      setNewPassword('');
    } catch (error: any) {
      toast.error(error.message || 'Failed to reset password');
    }
  };

  const getRoleBadgeColor = (role: string) => {
    const colors: Record<string, string> = {
      ADMIN: 'bg-red-100 text-red-800',
      STAFF: 'bg-purple-100 text-purple-800',
      CLIENT: 'bg-blue-100 text-blue-800',
      CLIENT_SME: 'bg-cyan-100 text-cyan-800',
      FREELANCER: 'bg-green-100 text-green-800',
      BROKER: 'bg-yellow-100 text-yellow-800',
    };
    return colors[role] || 'bg-gray-100 text-gray-800';
  };

  const getStatusText = (user: User) => {
    if (user.isBanned) return 'Banned';
    return 'Active';
  };

  const getKycStatusText = (status?: string, isVerified?: boolean) => {
    if (status) return status;
    return isVerified ? 'APPROVED' : 'NOT_STARTED';
  };

  const getPermissionLabel = (role: string) => {
    if (role === 'ADMIN' || role === 'STAFF') return 'Admin privileges';
    return 'Standard user permissions';
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">User Management</h1>
          <p className="text-gray-600 mt-2">Manage users, ban/unban, reset passwords</p>
        </div>

        {/* Stats Cards */}
        {stats && (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
            <div className="bg-white p-4 rounded-lg shadow">
              <div className="text-sm text-gray-600">Total Users</div>
              <div className="text-2xl font-bold">{stats.total}</div>
            </div>
            <div className="bg-white p-4 rounded-lg shadow">
              <div className="text-sm text-gray-600">Verified</div>
              <div className="text-2xl font-bold text-green-600">{stats.verified}</div>
            </div>
            <div className="bg-white p-4 rounded-lg shadow">
              <div className="text-sm text-gray-600">Banned</div>
              <div className="text-2xl font-bold text-red-600">{stats.banned}</div>
            </div>
            <div className="bg-white p-4 rounded-lg shadow">
              <div className="text-sm text-gray-600">Freelancers</div>
              <div className="text-2xl font-bold text-blue-600">{stats.byRole.FREELANCER || 0}</div>
            </div>
          </div>
        )}

        {/* Filters */}
        <div className="bg-white p-4 rounded-lg shadow mb-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Search</label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
                <input
                  type="text"
                  placeholder="Email or name..."
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  value={searchQuery}
                  onChange={(e) => {
                    setSearchQuery(e.target.value);
                    setPage(1);
                  }}
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Role</label>
              <select
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                value={roleFilter}
                onChange={(e) => {
                  setRoleFilter(e.target.value);
                  setPage(1);
                }}
              >
                <option value="">All Roles</option>
                <option value="CLIENT">Client</option>
                <option value="CLIENT_SME">Client SME</option>
                <option value="FREELANCER">Freelancer</option>
                <option value="BROKER">Broker</option>
                <option value="STAFF">Staff</option>
                <option value="ADMIN">Admin</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Status</label>
              <select
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                value={banFilter}
                onChange={(e) => {
                  setBanFilter(e.target.value);
                  setPage(1);
                }}
              >
                <option value="">All Status</option>
                <option value="false">Active</option>
                <option value="true">Banned</option>
              </select>
            </div>
          </div>
        </div>

        {/* Users Table */}
        <div className="bg-white rounded-lg shadow overflow-hidden">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">User</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Role</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Trust Score</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Projects</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {loading ? (
                <tr>
                  <td colSpan={6} className="px-6 py-4 text-center text-gray-500">
                    Loading...
                  </td>
                </tr>
              ) : users.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-4 text-center text-gray-500">
                    No users found
                  </td>
                </tr>
              ) : (
                users.map((user) => (
                  <tr
                    key={user.id}
                    className="hover:bg-gray-50 cursor-pointer"
                    onClick={() => openUserDetail(user)}
                  >
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div>
                        <div className="font-medium text-gray-900">{user.fullName}</div>
                        <div className="text-sm text-gray-500">{user.email}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 py-1 text-xs font-semibold rounded-full ${getRoleBadgeColor(user.role)}`}>
                        {user.role}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <Shield className="w-4 h-4 text-yellow-500 mr-1" />
                        <span className="font-semibold">{Number(user.currentTrustScore).toFixed(2)}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {user.totalProjectsFinished} finished
                      {user.totalDisputesLost > 0 && (
                        <span className="ml-2 text-red-600">({user.totalDisputesLost} disputes)</span>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      {user.isBanned ? (
                        <div className="flex items-center text-red-600">
                          <AlertCircle className="w-4 h-4 mr-1" />
                          <span className="text-sm font-medium">Banned</span>
                        </div>
                      ) : (
                        <div className="flex items-center">
                          {user.isVerified && (
                            <UserCheck className="w-4 h-4 text-green-600 mr-1" />
                          )}
                          <span className="text-sm text-green-600">Active</span>
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          setSelectedUser(user);
                          setShowResetPasswordModal(true);
                        }}
                        className="text-blue-600 hover:text-blue-900 mr-3"
                        title="Reset Password"
                      >
                        <Key className="w-5 h-5 inline" />
                      </button>
                      
                      {user.isBanned ? (
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            setSelectedUser(user);
                            setShowUnbanModal(true);
                          }}
                          className="text-green-600 hover:text-green-900"
                          title="Unban User"
                        >
                          <UserCheck className="w-5 h-5 inline" />
                        </button>
                      ) : (
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            setSelectedUser(user);
                            setShowBanModal(true);
                          }}
                          className="text-red-600 hover:text-red-900"
                          title="Ban User"
                        >
                          <Ban className="w-5 h-5 inline" />
                        </button>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="bg-gray-50 px-6 py-4 flex items-center justify-between">
              <button
                onClick={() => setPage(Math.max(1, page - 1))}
                disabled={page === 1}
                className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 disabled:opacity-50"
              >
                Previous
              </button>
              <span className="text-sm text-gray-700">
                Page {page} of {totalPages}
              </span>
              <button
                onClick={() => setPage(Math.min(totalPages, page + 1))}
                disabled={page === totalPages}
                className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 disabled:opacity-50"
              >
                Next
              </button>
            </div>
          )}
        </div>

        {/* User Detail Modal */}
        {showDetailModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-6">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-5xl max-h-[90vh] overflow-y-auto">
              <div className="flex items-center justify-between px-6 py-4 border-b">
                <div>
                  <h3 className="text-xl font-semibold text-gray-900">User Details</h3>
                  <p className="text-sm text-gray-500">
                    {detailUser?.fullName || 'Loading user...'}
                  </p>
                </div>
                <button
                  onClick={closeUserDetail}
                  className="px-3 py-1.5 text-sm text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200"
                >
                  Close
                </button>
              </div>

              <div className="p-6">
                {detailLoading ? (
                  <div className="text-center text-gray-500 py-12">Loading details...</div>
                ) : detailUser ? (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Basic Info */}
                    <div className="bg-gray-50 rounded-lg p-4 border">
                      <h4 className="text-sm font-semibold text-gray-700 mb-3">Basic Info</h4>
                      <div className="space-y-2 text-sm">
                        <div><span className="text-gray-500">Name:</span> {detailUser.fullName}</div>
                        <div><span className="text-gray-500">Email:</span> {detailUser.email}</div>
                        <div><span className="text-gray-500">Phone:</span> {detailUser.phoneNumber || 'N/A'}</div>
                        <div>
                          <span className="text-gray-500">Created At:</span>{' '}
                          {detailUser.createdAt ? new Date(detailUser.createdAt).toLocaleString() : 'N/A'}
                        </div>
                      </div>
                    </div>

                    {/* KYC */}
                    <div className="bg-gray-50 rounded-lg p-4 border">
                      <div className="flex items-center justify-between mb-3">
                        <h4 className="text-sm font-semibold text-gray-700">KYC</h4>
                        <span
                          className={`px-2 py-1 text-xs font-semibold rounded-full ${
                            getKycStatusText(detailUser.kyc?.status, detailUser.isVerified) === 'APPROVED'
                              ? 'bg-green-100 text-green-700'
                              : getKycStatusText(detailUser.kyc?.status, detailUser.isVerified) === 'REJECTED'
                              ? 'bg-red-100 text-red-700'
                              : getKycStatusText(detailUser.kyc?.status, detailUser.isVerified) === 'PENDING'
                              ? 'bg-yellow-100 text-yellow-700'
                              : 'bg-gray-100 text-gray-700'
                          }`}
                        >
                          {getKycStatusText(detailUser.kyc?.status, detailUser.isVerified)}
                        </span>
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <div className="text-xs text-gray-500">ID Card Front</div>
                        <div className="text-xs text-gray-500">ID Card Back</div>
                        <div className="bg-white border rounded-md p-2 flex items-center justify-center min-h-[140px]">
                          {detailUser.kyc?.documentFrontUrl ? (
                            <img
                              src={detailUser.kyc.documentFrontUrl}
                              alt="ID Card Front"
                              className="max-h-32 object-contain"
                            />
                          ) : (
                            <span className="text-xs text-gray-400">No image</span>
                          )}
                        </div>
                        <div className="bg-white border rounded-md p-2 flex items-center justify-center min-h-[140px]">
                          {detailUser.kyc?.documentBackUrl ? (
                            <img
                              src={detailUser.kyc.documentBackUrl}
                              alt="ID Card Back"
                              className="max-h-32 object-contain"
                            />
                          ) : (
                            <span className="text-xs text-gray-400">No image</span>
                          )}
                        </div>
                        {detailUser.kyc?.rejectionReason && (
                          <div className="sm:col-span-2 text-xs text-red-600 bg-red-50 border border-red-100 rounded-md p-2">
                            Rejection Reason: {detailUser.kyc.rejectionReason}
                          </div>
                        )}
                      </div>
                    </div>

                    {/* Roles & Permissions */}
                    <div className="bg-gray-50 rounded-lg p-4 border">
                      <h4 className="text-sm font-semibold text-gray-700 mb-3">Roles & Permissions</h4>
                      <div className="space-y-2 text-sm">
                        <div>
                          <span className={`px-2 py-1 text-xs font-semibold rounded-full ${getRoleBadgeColor(detailUser.role)}`}>
                            {detailUser.role}
                          </span>
                        </div>
                        <div className="text-gray-600">{getPermissionLabel(detailUser.role)}</div>
                      </div>
                    </div>

                    {/* Trust Score Metrics */}
                    <div className="bg-gray-50 rounded-lg p-4 border">
                      <h4 className="text-sm font-semibold text-gray-700 mb-3">Trust Score Metrics</h4>
                      <div className="grid grid-cols-3 gap-4 text-sm">
                        <div>
                          <div className="text-gray-500">Trust Score</div>
                          <div className="font-semibold">{Number(detailUser.currentTrustScore).toFixed(2)}</div>
                        </div>
                        <div>
                          <div className="text-gray-500">Projects Completed</div>
                          <div className="font-semibold">{detailUser.totalProjectsFinished}</div>
                        </div>
                        <div>
                          <div className="text-gray-500">Disputes Lost</div>
                          <div className="font-semibold">{detailUser.totalDisputesLost}</div>
                        </div>
                      </div>
                    </div>

                    {/* Status Information */}
                    <div className="bg-gray-50 rounded-lg p-4 border lg:col-span-2">
                      <h4 className="text-sm font-semibold text-gray-700 mb-3">Status Information</h4>
                      <div className="text-sm">
                        <div>
                          <span className="text-gray-500">Account Status:</span>{' '}
                          <span className={detailUser.isBanned ? 'text-red-600 font-medium' : 'text-green-600 font-medium'}>
                            {getStatusText(detailUser)}
                          </span>
                        </div>
                        {detailUser.isBanned && detailUser.banReason && (
                          <div className="mt-2 text-red-600">
                            Ban Reason: {detailUser.banReason}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="text-center text-gray-500 py-12">No detail found</div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Ban Modal */}
        {showBanModal && selectedUser && (
          <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden animate-in fade-in zoom-in duration-200">
              {/* Header */}
              <div className="bg-gradient-to-r from-red-500 to-red-600 px-6 py-5">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg">
                      <Ban className="w-6 h-6 text-white" />
                    </div>
                    <h3 className="text-xl font-bold text-white">Ban User</h3>
                  </div>
                  <button
                    onClick={() => {
                      setShowBanModal(false);
                      setBanReason('');
                    }}
                    className="p-1 hover:bg-white/20 rounded-lg transition-colors"
                  >
                    <X className="w-5 h-5 text-white" />
                  </button>
                </div>
              </div>

              {/* Content */}
              <div className="p-6 space-y-5">
                <div className="bg-red-50 border border-red-100 rounded-xl p-4">
                  <div className="flex items-start gap-3">
                    <AlertCircle className="w-5 h-5 text-red-600 mt-0.5 flex-shrink-0" />
                    <div>
                      <p className="text-sm font-medium text-red-900">You are about to ban this user</p>
                      <p className="text-sm text-red-700 mt-1">
                        <strong>{selectedUser.fullName}</strong>
                        <span className="text-red-600"> ({selectedUser.email})</span>
                      </p>
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Reason for ban <span className="text-red-500">*</span>
                  </label>
                  <textarea
                    className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-red-500 focus:border-transparent transition-all resize-none"
                    placeholder="Enter the reason for banning this user..."
                    rows={4}
                    value={banReason}
                    onChange={(e) => setBanReason(e.target.value)}
                  />
                </div>
              </div>

              {/* Footer */}
              <div className="bg-gray-50 px-6 py-4 flex gap-3 justify-end">
                <button
                  onClick={() => {
                    setShowBanModal(false);
                    setBanReason('');
                  }}
                  className="px-5 py-2.5 text-gray-700 bg-white border border-gray-300 rounded-xl hover:bg-gray-50 transition-colors font-medium"
                >
                  Cancel
                </button>
                <button
                  onClick={handleBanUser}
                  className="px-5 py-2.5 bg-gradient-to-r from-red-500 to-red-600 text-white rounded-xl hover:from-red-600 hover:to-red-700 transition-all font-medium shadow-lg hover:shadow-xl"
                >
                  Ban User
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Unban Modal */}
        {showUnbanModal && selectedUser && (
          <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden animate-in fade-in zoom-in duration-200">
              {/* Header */}
              <div className="bg-gradient-to-r from-green-500 to-green-600 px-6 py-5">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg">
                      <UserCheck className="w-6 h-6 text-white" />
                    </div>
                    <h3 className="text-xl font-bold text-white">Unban User</h3>
                  </div>
                  <button
                    onClick={() => {
                      setShowUnbanModal(false);
                      setUnbanReason('');
                    }}
                    className="p-1 hover:bg-white/20 rounded-lg transition-colors"
                  >
                    <X className="w-5 h-5 text-white" />
                  </button>
                </div>
              </div>

              {/* Content */}
              <div className="p-6 space-y-5">
                <div className="bg-green-50 border border-green-100 rounded-xl p-4">
                  <div className="flex items-start gap-3">
                    <UserCheck className="w-5 h-5 text-green-600 mt-0.5 flex-shrink-0" />
                    <div>
                      <p className="text-sm font-medium text-green-900">Restore user access</p>
                      <p className="text-sm text-green-700 mt-1">
                        <strong>{selectedUser.fullName}</strong>
                        <span className="text-green-600"> ({selectedUser.email})</span>
                      </p>
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Reason for unban <span className="text-red-500">*</span>
                  </label>
                  <textarea
                    className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-green-500 focus:border-transparent transition-all resize-none"
                    placeholder="Enter the reason for unbanning this user..."
                    rows={4}
                    value={unbanReason}
                    onChange={(e) => setUnbanReason(e.target.value)}
                  />
                </div>
              </div>

              {/* Footer */}
              <div className="bg-gray-50 px-6 py-4 flex gap-3 justify-end">
                <button
                  onClick={() => {
                    setShowUnbanModal(false);
                    setUnbanReason('');
                  }}
                  className="px-5 py-2.5 text-gray-700 bg-white border border-gray-300 rounded-xl hover:bg-gray-50 transition-colors font-medium"
                >
                  Cancel
                </button>
                <button
                  onClick={handleUnbanUser}
                  className="px-5 py-2.5 bg-gradient-to-r from-green-500 to-green-600 text-white rounded-xl hover:from-green-600 hover:to-green-700 transition-all font-medium shadow-lg hover:shadow-xl"
                >
                  Unban User
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Reset Password Modal */}
        {showResetPasswordModal && selectedUser && (
          <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden animate-in fade-in zoom-in duration-200">
              {/* Header */}
              <div className="bg-gradient-to-r from-blue-500 to-blue-600 px-6 py-5">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg">
                      <Key className="w-6 h-6 text-white" />
                    </div>
                    <h3 className="text-xl font-bold text-white">Reset Password</h3>
                  </div>
                  <button
                    onClick={() => {
                      setShowResetPasswordModal(false);
                      setNewPassword('');
                    }}
                    className="p-1 hover:bg-white/20 rounded-lg transition-colors"
                  >
                    <X className="w-5 h-5 text-white" />
                  </button>
                </div>
              </div>

              {/* Content */}
              <div className="p-6 space-y-5">
                <div className="bg-blue-50 border border-blue-100 rounded-xl p-4">
                  <div className="flex items-start gap-3">
                    <Key className="w-5 h-5 text-blue-600 mt-0.5 flex-shrink-0" />
                    <div>
                      <p className="text-sm font-medium text-blue-900">Reset user password</p>
                      <p className="text-sm text-blue-700 mt-1">
                        <strong>{selectedUser.fullName}</strong>
                        <span className="text-blue-600"> ({selectedUser.email})</span>
                      </p>
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    New temporary password <span className="text-red-500">*</span>
                  </label>
                  <input
                    type="text"
                    className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
                    placeholder="Enter new temporary password..."
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                  />
                </div>

                <label className="flex items-center gap-3 p-3 bg-gray-50 rounded-xl cursor-pointer hover:bg-gray-100 transition-colors">
                  <input
                    type="checkbox"
                    checked={sendEmail}
                    onChange={(e) => setSendEmail(e.target.checked)}
                    className="w-4 h-4 text-blue-600 rounded focus:ring-2 focus:ring-blue-500"
                  />
                  <span className="text-sm font-medium text-gray-700">Send email notification to user</span>
                </label>
              </div>

              {/* Footer */}
              <div className="bg-gray-50 px-6 py-4 flex gap-3 justify-end">
                <button
                  onClick={() => {
                    setShowResetPasswordModal(false);
                    setNewPassword('');
                  }}
                  className="px-5 py-2.5 text-gray-700 bg-white border border-gray-300 rounded-xl hover:bg-gray-50 transition-colors font-medium"
                >
                  Cancel
                </button>
                <button
                  onClick={handleResetPassword}
                  className="px-5 py-2.5 bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-xl hover:from-blue-600 hover:to-blue-700 transition-all font-medium shadow-lg hover:shadow-xl"
                >
                  Reset Password
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

