﻿import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Briefcase, Search, Filter, DollarSign, Clock, MapPin, Star, TrendingUp, CheckCircle2, AlertCircle, Settings } from 'lucide-react';
import { Button } from '@/shared/components/ui/Button';
import { Input } from '@/shared/components/custom/input';
import { ROUTES, STORAGE_KEYS } from '@/constants';
import { FreelancerDashboardLayout } from '@/shared/components/layouts/freelancer/FreelancerDashboardLayout';
import { getStoredJson } from '@/shared/utils/storage';

interface Job {
  id: string;
  title: string;
  description: string;
  budget: number;
  duration: string;
  location: string;
  skills: string[];
  postedAt: string;
  client: {
    name: string;
    rating: number;
    completedProjects: number;
  };
}

interface DashboardStats {
  activeProjects: number;
  totalEarnings: number;
  completedProjects: number;
  profileViews: number;
}

export default function FreelancerDashboardPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedSkills, setSelectedSkills] = useState<string[]>([]);
  const [userSkills, setUserSkills] = useState<string[]>([]);
  
  // Mock data - Replace with API calls later
  const [stats] = useState<DashboardStats>({
    activeProjects: 2,
    totalEarnings: 15750,
    completedProjects: 12,
    profileViews: 234,
  });

  const [jobs] = useState<Job[]>([
    {
      id: '1',
      title: 'React Developer for E-commerce Platform',
      description: 'Looking for an experienced React developer to build a modern e-commerce platform with payment integration.',
      budget: 5000,
      duration: '2-3 months',
      location: 'Remote',
      skills: ['React', 'TypeScript', 'Node.js', 'PostgreSQL'],
      postedAt: '2 hours ago',
      client: {
        name: 'TechCorp Vietnam',
        rating: 4.8,
        completedProjects: 24,
      },
    },
    {
      id: '2',
      title: 'Full Stack Developer - CRM System',
      description: 'Need a full stack developer to customize and extend our existing CRM system with new features.',
      budget: 7500,
      duration: '3-4 months',
      location: 'Hybrid - Ho Chi Minh City',
      skills: ['React', 'Node.js', 'MongoDB', 'AWS'],
      postedAt: '1 day ago',
      client: {
        name: 'SmartBiz Solutions',
        rating: 4.9,
        completedProjects: 31,
      },
    },
    {
      id: '3',
      title: 'UI/UX Designer for Mobile App',
      description: 'Seeking a creative UI/UX designer to design a mobile app for food delivery service.',
      budget: 3000,
      duration: '1-2 months',
      location: 'Remote',
      skills: ['Figma', 'UI/UX Design', 'Mobile Design'],
      postedAt: '3 days ago',
      client: {
        name: 'FoodHub',
        rating: 4.5,
        completedProjects: 8,
      },
    },
  ]);

  useEffect(() => {
    // Load user skills from storage (session/local)
    const user = getStoredJson<{ skills?: string[] }>(STORAGE_KEYS.USER);
    if (user) {
      setUserSkills(user.skills || []);
    }
  }, []);

  const filteredJobs = jobs.filter(job => {
    const matchesSearch = job.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         job.description.toLowerCase().includes(searchQuery.toLowerCase());
    
    const matchesSkills = selectedSkills.length === 0 || 
                         selectedSkills.some(skill => job.skills.includes(skill));
    
    return matchesSearch && matchesSkills;
  });

  const handleCompleteProfile = () => {
    navigate(ROUTES.FREELANCER_ONBOARDING);
  };

  const isProfileIncomplete = userSkills.length === 0;

  return (
    <FreelancerDashboardLayout>
      <div className="w-full">
        {/* Profile Incomplete Banner */}
        {isProfileIncomplete && (
          <div className="bg-amber-50 border-b border-amber-200 mb-6">
            <div className="py-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <AlertCircle className="w-5 h-5 text-amber-600" />
                  <div>
                    <p className="text-sm font-medium text-amber-900">
                      Complete your profile to start receiving job offers
                    </p>
                    <p className="text-xs text-amber-700">
                      Add your skills, portfolio, and experience to unlock all features
                    </p>
                  </div>
                </div>
                <Button onClick={handleCompleteProfile} size="sm" variant="outline" className="border-amber-300 text-amber-700 hover:bg-amber-100">
                  Complete Profile
                </Button>
              </div>
            </div>
          </div>
        )}

        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Freelancer Dashboard</h1>
          <p className="text-gray-600">Find projects that match your skills and expertise</p>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <div className="bg-white rounded-lg shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium text-gray-600">Active Projects</span>
              <Briefcase className="w-5 h-5 text-blue-600" />
            </div>
            <div className="text-3xl font-bold text-gray-900">{stats.activeProjects}</div>
            <p className="text-xs text-green-600 mt-1 flex items-center gap-1">
              <TrendingUp className="w-3 h-3" />
              In progress
            </p>
          </div>

          <div className="bg-white rounded-lg shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium text-gray-600">Total Earnings</span>
              <DollarSign className="w-5 h-5 text-green-600" />
            </div>
            <div className="text-3xl font-bold text-gray-900">
              ${stats.totalEarnings.toLocaleString()}
            </div>
            <p className="text-xs text-gray-500 mt-1">This month: $2,450</p>
          </div>

          <div className="bg-white rounded-lg shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium text-gray-600">Completed</span>
              <CheckCircle2 className="w-5 h-5 text-purple-600" />
            </div>
            <div className="text-3xl font-bold text-gray-900">{stats.completedProjects}</div>
            <p className="text-xs text-gray-500 mt-1">100% success rate</p>
          </div>

          <div className="bg-white rounded-lg shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium text-gray-600">Profile Views</span>
              <TrendingUp className="w-5 h-5 text-orange-600" />
            </div>
            <div className="text-3xl font-bold text-gray-900">{stats.profileViews}</div>
            <p className="text-xs text-green-600 mt-1 flex items-center gap-1">
              <TrendingUp className="w-3 h-3" />
              +12% this week
            </p>
          </div>
        </div>

        {/* Search & Filters */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6 border border-gray-200">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
              <Input
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search for jobs..."
                className="pl-10"
              />
            </div>
            <Button variant="outline" className="md:w-auto">
              <Filter className="w-4 h-4 mr-2" />
              Filters
            </Button>
          </div>

          {/* Skill Filter Pills */}
          {userSkills.length > 0 && (
            <div className="mt-4 pt-4 border-t border-gray-200">
              <p className="text-sm font-medium text-gray-700 mb-2">Filter by your skills:</p>
              <div className="flex flex-wrap gap-2">
                {userSkills.map((skill) => (
                  <button
                    key={skill}
                    onClick={() => {
                      setSelectedSkills(prev =>
                        prev.includes(skill)
                          ? prev.filter(s => s !== skill)
                          : [...prev, skill]
                      );
                    }}
                    className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors ${
                      selectedSkills.includes(skill)
                        ? 'bg-blue-600 text-white'
                        : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                    }`}
                  >
                    {skill}
                  </button>
                ))}
                {selectedSkills.length > 0 && (
                  <button
                    onClick={() => setSelectedSkills([])}
                    className="px-3 py-1.5 rounded-full text-sm font-medium text-red-600 hover:bg-red-50"
                  >
                    Clear filters
                  </button>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Jobs List */}
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-semibold text-gray-900">
              Available Jobs ({filteredJobs.length})
            </h2>
            <Button variant="ghost" size="sm">
              <Settings className="w-4 h-4 mr-2" />
              Job Preferences
            </Button>
          </div>

          {filteredJobs.length === 0 ? (
            <div className="bg-white rounded-lg shadow-sm p-12 text-center border border-gray-200">
              <Briefcase className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No jobs found</h3>
              <p className="text-gray-600">Try adjusting your search or filters</p>
            </div>
          ) : (
            filteredJobs.map((job) => (
              <div
                key={job.id}
                className="bg-white rounded-lg shadow-sm p-6 border border-gray-200 hover:border-blue-300 hover:shadow-md transition-all cursor-pointer"
              >
                <div className="flex items-start justify-between mb-3">
                  <div className="flex-1">
                    <h3 className="text-lg font-semibold text-gray-900 mb-1">{job.title}</h3>
                    <div className="flex items-center gap-4 text-sm text-gray-600 mb-3">
                      <span className="flex items-center gap-1">
                        <DollarSign className="w-4 h-4" />
                        ${job.budget.toLocaleString()}
                      </span>
                      <span className="flex items-center gap-1">
                        <Clock className="w-4 h-4" />
                        {job.duration}
                      </span>
                      <span className="flex items-center gap-1">
                        <MapPin className="w-4 h-4" />
                        {job.location}
                      </span>
                    </div>
                  </div>
                  <span className="text-xs text-gray-500 whitespace-nowrap ml-4">{job.postedAt}</span>
                </div>

                <p className="text-gray-700 mb-4 line-clamp-2">{job.description}</p>

                {/* Skills */}
                <div className="flex flex-wrap gap-2 mb-4">
                  {job.skills.map((skill) => (
                    <span
                      key={skill}
                      className={`px-3 py-1 rounded-full text-xs font-medium ${
                        userSkills.includes(skill)
                          ? 'bg-green-100 text-green-700 border border-green-300'
                          : 'bg-gray-100 text-gray-700'
                      }`}
                    >
                      {skill}
                      {userSkills.includes(skill) && " ✓"}
                    </span>
                  ))}
                </div>

                {/* Client Info & CTA */}
                <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
                      <span className="text-sm font-semibold text-blue-600">
                        {job.client.name.charAt(0)}
                      </span>
                    </div>
                    <div>
                      <p className="text-sm font-medium text-gray-900">{job.client.name}</p>
                      <div className="flex items-center gap-2 text-xs text-gray-600">
                        <span className="flex items-center gap-1">
                          <Star className="w-3 h-3 fill-yellow-400 text-yellow-400" />
                          {job.client.rating}
                        </span>
                        <span>窶｢</span>
                        <span>{job.client.completedProjects} projects</span>
                      </div>
                    </div>
                  </div>
                  <Button size="sm">
                    View Details
                  </Button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </FreelancerDashboardLayout>
  );
}

﻿import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Briefcase, Plus, X, Link as LinkIcon, Award, Code, Save, Loader2, Upload, FileText } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/shared/components/ui/Button';
import { Input } from '@/shared/components/custom/input';
import { getProfile, updateProfile } from '@/features/auth/api';
import { ROUTES } from '@/constants';
import type { PortfolioLink } from '@/features/auth/types';



interface FreelancerProfile {
  skills: string[];
  portfolioLinks: PortfolioLink[];
  bio: string;
  companyName?: string;
  linkedinUrl?: string;
  cvUrl?: string;
}

export default function FreelancerOnboardingPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [profile, setProfile] = useState<FreelancerProfile>({
    skills: [],
    portfolioLinks: [],
    bio: '',
    companyName: '',
    linkedinUrl: '',
    cvUrl: '',
  });

  // Temporary states for adding new items
  const [newSkill, setNewSkill] = useState('');
  const [newPortfolio, setNewPortfolio] = useState<PortfolioLink>({ title: '', url: '' });
  const [cvFile, setCvFile] = useState<File | null>(null);
  const [cvPreview, setCvPreview] = useState<string>('');

  useEffect(() => {
    loadProfile();
  }, []);

  const loadProfile = async () => {
    try {
      setLoading(true);
      const response = await getProfile();
      // Safely access data, using optional chaining and type assertion if needed for the response structure
      // Assuming response has data property which contains the user profile
      const userData = (response as any).data || (response as any).data?.data || response;
      
      setProfile({
        skills: userData.skills || [],
        portfolioLinks: userData.portfolioLinks || [],
        bio: userData.bio || '',
        companyName: userData.companyName || '',
        linkedinUrl: userData.linkedinUrl || '',
        cvUrl: userData.cvUrl || '',
      });
      
      if (userData.cvUrl) {
        setCvPreview(userData.cvUrl);
      }
    } catch (error: any) {
      toast.error('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleAddSkill = () => {
    if (!newSkill.trim()) {
      toast.error('Please enter a skill');
      return;
    }

    if (profile.skills.includes(newSkill.trim())) {
      toast.error('This skill already exists');
      return;
    }

    setProfile(prev => ({
      ...prev,
      skills: [...prev.skills, newSkill.trim()],
    }));
    setNewSkill('');
    toast.success('Skill added');
  };

  const handleRemoveSkill = (index: number) => {
    setProfile(prev => ({
      ...prev,
      skills: prev.skills.filter((_, i) => i !== index),
    }));
    toast.success('Skill removed');
  };

  const handleAddPortfolio = () => {
    if (!newPortfolio.title.trim() || !newPortfolio.url.trim()) {
      toast.error('Please fill in both title and URL');
      return;
    }

    // Basic URL validation
    try {
      new URL(newPortfolio.url);
    } catch {
      toast.error('Please enter a valid URL');
      return;
    }

    setProfile(prev => ({
      ...prev,
      portfolioLinks: [...prev.portfolioLinks, { ...newPortfolio }],
    }));
    setNewPortfolio({ title: '', url: '' });
    toast.success('Portfolio link added');
  };

  const handleRemovePortfolio = (index: number) => {
    setProfile(prev => ({
      ...prev,
      portfolioLinks: prev.portfolioLinks.filter((_, i) => i !== index),
    }));
    toast.success('Portfolio link removed');
  };

  const handleCvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Accept PDF and images
    const allowedTypes = ['application/pdf', 'image/png', 'image/jpeg', 'image/jpg'];
    if (!allowedTypes.includes(file.type)) {
      toast.error('Please upload PDF, PNG, JPG, or JPEG file');
      return;
    }

    if (file.size > 5 * 1024 * 1024) {
      toast.error('File size must not exceed 5MB');
      return;
    }

    setCvFile(file);
    const reader = new FileReader();
    reader.onloadend = () => {
      setCvPreview(reader.result as string);
    };
    reader.readAsDataURL(file);
    toast.success('CV uploaded successfully');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (profile.skills.length === 0 && !profile.linkedinUrl && !cvFile && !profile.cvUrl) {
      toast.error('Please add skills, LinkedIn URL, or upload CV');
      return;
    }

    try {
      setSaving(true);

      const cvUrl = cvFile ? cvPreview : profile.cvUrl;

      await updateProfile({
        skills: profile.skills,
        portfolioLinks: profile.portfolioLinks,
        bio: profile.bio,
        companyName: profile.companyName,
        linkedinUrl: profile.linkedinUrl,
        cvUrl: cvUrl,
      });

      toast.success('Freelancer profile created successfully! Redirecting to dashboard...');
      
      // Redirect to dashboard after successful onboarding
      setTimeout(() => {
        navigate(ROUTES.FREELANCER_DASHBOARD);
      }, 1500);
    } catch (error: any) {
      const errorMessage = error.response?.data?.message || 'Failed to update profile';
      toast.error(errorMessage);
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4">
        {/* Header */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-blue-100 rounded-lg">
              <Briefcase className="w-6 h-6 text-blue-600" />
            </div>
            <h1 className="text-2xl font-bold text-gray-900">Freelancer Profile Setup</h1>
          </div>
          <p className="text-gray-600 ml-11">
            Complete your profile to start accepting projects. Add your skills, experience, and portfolio to showcase your expertise.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Bio Section */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center gap-2 mb-4">
              <Award className="w-5 h-5 text-gray-600" />
              <h2 className="text-lg font-semibold text-gray-900">Professional Bio</h2>
            </div>
            <textarea
              value={profile.bio}
              onChange={(e) => setProfile(prev => ({ ...prev, bio: e.target.value }))}
              placeholder="Describe your experience, expertise, and what makes you a great freelancer..."
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 min-h-[120px] resize-y"
            />
          </div>

          {/* Company Name (Optional) */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center gap-2 mb-4">
              <Briefcase className="w-5 h-5 text-gray-600" />
              <h2 className="text-lg font-semibold text-gray-900">Company Name (Optional)</h2>
            </div>
            <Input
              value={profile.companyName}
              onChange={(e) => setProfile(prev => ({ ...prev, companyName: e.target.value }))}
              placeholder="Enter your company name if applicable"
            />
          </div>

          {/* Skills Section */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center gap-2 mb-4">
              <Code className="w-5 h-5 text-gray-600" />
              <h2 className="text-lg font-semibold text-gray-900">Skills & Technologies</h2>
            </div>

            <p className="text-sm text-gray-600 mb-4">
              Add your skills manually, provide LinkedIn profile, or upload your CV
            </p>

            {/* LinkedIn URL */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                LinkedIn Profile URL (Optional)
              </label>
              <Input
                value={profile.linkedinUrl}
                onChange={(e) => setProfile(prev => ({ ...prev, linkedinUrl: e.target.value }))}
                placeholder="https://www.linkedin.com/in/your-profile"
                type="url"
              />
            </div>

            {/* CV Upload */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Upload CV/Resume (Optional - PDF, PNG, JPG)
              </label>
              <div className="flex items-center gap-3">
                <label className="flex-1">
                  <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 hover:border-blue-400 transition-colors cursor-pointer">
                    <div className="flex items-center justify-center gap-2 text-gray-600">
                      <Upload className="w-5 h-5" />
                      <span className="text-sm">
                        {cvFile ? cvFile.name : cvPreview ? 'CV uploaded - Click to change' : 'Click to upload CV'}
                      </span>
                    </div>
                  </div>
                  <input
                    type="file"
                    accept=".pdf,.png,.jpg,.jpeg"
                    onChange={handleCvUpload}
                    className="hidden"
                  />
                </label>
                {(cvFile || cvPreview) && (
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      setCvFile(null);
                      setCvPreview('');
                      setProfile(prev => ({ ...prev, cvUrl: '' }));
                      toast.success('CV removed');
                    }}
                  >
                    <X className="w-4 h-4" />
                  </Button>
                )}
              </div>
              {cvPreview && (
                <div className="mt-2 flex items-center gap-2 text-sm text-green-600">
                  <FileText className="w-4 h-4" />
                  <span>CV ready to upload</span>
                </div>
              )}
            </div>

            <div className="border-t border-gray-200 pt-4 mb-4">
              <p className="text-sm font-medium text-gray-700 mb-3">Or add skills manually:</p>
            </div>

            {/* Current Skills */}
            {profile.skills.length > 0 && (
              <div className="flex flex-wrap gap-2 mb-4">
                {profile.skills.map((skill, index) => (
                  <div
                    key={index}
                    className="inline-flex items-center gap-2 bg-blue-50 text-blue-700 px-3 py-1.5 rounded-full text-sm font-medium"
                  >
                    <span>{skill}</span>
                    <button
                      type="button"
                      onClick={() => handleRemoveSkill(index)}
                      className="hover:bg-blue-100 rounded-full p-0.5 transition-colors"
                    >
                      <X className="w-3.5 h-3.5" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            {/* Add New Skill */}
            <div className="flex items-center gap-2">
              <Input
                value={newSkill}
                onChange={(e) => setNewSkill(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddSkill())}
                placeholder="e.g., React, Node.js, Python, UI/UX Design..."
                className="flex-1"
              />
              <Button
                type="button"
                onClick={handleAddSkill}
                variant="outline"
                className="shrink-0 h-10"
              >
                <Plus className="w-4 h-4 mr-1" />
                Add Skill
              </Button>
            </div>
          </div>

          {/* Portfolio Section */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center gap-2 mb-4">
              <LinkIcon className="w-5 h-5 text-gray-600" />
              <h2 className="text-lg font-semibold text-gray-900">Portfolio Links</h2>
            </div>

            {/* Current Portfolio Links */}
            {profile.portfolioLinks.length > 0 && (
              <div className="space-y-3 mb-4">
                {profile.portfolioLinks.map((link, index) => (
                  <div
                    key={index}
                    className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg border border-gray-200"
                  >
                    <LinkIcon className="w-4 h-4 text-gray-400 shrink-0" />
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-gray-900 truncate">{link.title}</div>
                      <a
                        href={link.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-sm text-blue-600 hover:underline truncate block"
                      >
                        {link.url}
                      </a>
                    </div>
                    <button
                      type="button"
                      onClick={() => handleRemovePortfolio(index)}
                      className="shrink-0 p-1.5 hover:bg-red-50 rounded-lg text-red-600 transition-colors"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            {/* Add New Portfolio Link */}
            <div className="space-y-3">
              <Input
                value={newPortfolio.title}
                onChange={(e) => setNewPortfolio(prev => ({ ...prev, title: e.target.value }))}
                placeholder="Project title (e.g., E-commerce Website)"
              />
              <div className="flex items-center gap-2">
                <Input
                  value={newPortfolio.url}
                  onChange={(e) => setNewPortfolio(prev => ({ ...prev, url: e.target.value }))}
                  placeholder="https://github.com/username/project or live demo URL"
                  className="flex-1"
                />
                <Button
                  type="button"
                  onClick={handleAddPortfolio}
                  variant="outline"
                  className="shrink-0 h-10"
                >
                  <Plus className="w-4 h-4 mr-1" />
                  Add Link
                </Button>
              </div>
            </div>
          </div>

          {/* Submit Button */}
          <div className="flex justify-end gap-3 pt-4">
            <Button
              type="submit"
              disabled={saving || (profile.skills.length === 0 && !profile.linkedinUrl && !cvPreview)}
              className="min-w-[160px]"
            >
              {saving ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Saving...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4 mr-2" />
                  Save Profile
                </>
              )}
            </Button>
          </div>

          {/* Hint */}
          {profile.skills.length === 0 && !profile.linkedinUrl && !cvPreview && (
            <p className="text-sm text-amber-600 text-center bg-amber-50 p-3 rounded-lg border border-amber-200">
              笞・・Please add skills, LinkedIn URL, or upload your CV to enable your freelancer profile
            </p>
          )}
        </form>
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { AuthLayout } from '../shared/components/layouts/AuthLayout';
import { Input } from '../shared/components/custom/input';
import { Button } from '../shared/components/custom/Button';
import { toast } from 'sonner';
import { apiClient } from '@/shared/api/client';
import { ROUTES, STORAGE_KEYS } from '@/constants';
import { setStoredItem, setStoredJson } from '@/shared/utils/storage';

type UserRole = 'client' | 'broker' | 'freelancer';

export function GoogleCompletePage() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  
  const [formData, setFormData] = useState({
    email: searchParams.get('email') || '',
    fullName: searchParams.get('fullName') || '',
    picture: searchParams.get('picture') || '',
    role: '' as UserRole | '',
    phoneNumber: '',
  });
  
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Check if this is a new user
    if (!searchParams.get('isNewUser')) {
      navigate(ROUTES.LOGIN);
    }
  }, [searchParams, navigate]);

  const validatePhone = (phone: string): boolean => {
    const phoneRegex = /^0[3|5|7|8|9][0-9]{8}$/;
    return phoneRegex.test(phone);
  };

  const validateCorporateEmail = (email: string): boolean => {
    const freeEmailProviders = [
      'gmail.com', 'googlemail.com', 'yahoo.com', 'yahoo.co.uk',
      'hotmail.com', 'outlook.com', 'live.com', 'msn.com',
      'icloud.com', 'me.com', 'aol.com', 'mail.com',
      'protonmail.com', 'proton.me', 'zoho.com', 'yandex.com',
      'gmx.com', 'gmx.net', 'inbox.com', 'mail.ru'
    ];
    
    const domain = email.split('@')[1]?.toLowerCase();
    if (!domain) return false;
    return !freeEmailProviders.includes(domain);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: Record<string, string> = {};

    if (!formData.role) {
      newErrors.role = 'Please select your role';
    }

    if (formData.role === 'client' && !validateCorporateEmail(formData.email)) {
      newErrors.email = 'Business owners must use a corporate/organization email (not Gmail, Yahoo, Hotmail, etc.)';
    }

    if (!formData.phoneNumber) {
      newErrors.phoneNumber = 'Phone number is required';
    } else if (!validatePhone(formData.phoneNumber)) {
      newErrors.phoneNumber = 'Invalid phone number. Format: 0[3|5|7|8|9]xxxxxxxx';
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    setErrors({});
    setLoading(true);

    try {
      const response = await apiClient.post<{
        accessToken: string;
        refreshToken: string;
        user: any;
      }>('/auth/google/complete-signup', {
        email: formData.email,
        fullName: formData.fullName,
        phoneNumber: formData.phoneNumber,
        role: formData.role.toUpperCase(),
        picture: formData.picture,
      });

      // Tokens are now in httpOnly cookies (set by backend)
      // Only save user info to localStorage
      setStoredJson(STORAGE_KEYS.USER, response.user, true);

      toast.success('Account created successfully!');
      navigate(ROUTES.DASHBOARD);
    } catch (error: any) {
      const errorMessage = error.response?.data?.message || 'Failed to complete signup. Please try again.';
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const roleOptions = [
    { value: 'client', label: 'Client (SME Owner)', icon: '🏢' },
    { value: 'broker', label: 'Broker', icon: '💼' },
    { value: 'freelancer', label: 'Freelancer (Developer)', icon: '💻' },
  ];

  return (
    <AuthLayout title="Complete Your Profile">
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Profile Picture */}
        {formData.picture && (
          <div className="flex justify-center">
            <img 
              src={formData.picture} 
              alt="Profile" 
              className="w-20 h-20 rounded-full border-2 border-teal-500"
            />
          </div>
        )}

        {/* Email (Read-only) */}
        <Input
          id="email"
          label="Email"
          type="email"
          value={formData.email}
          disabled
          helperText="From your Google account"
        />

        {/* Full Name (Read-only) */}
        <Input
          id="fullName"
          label="Full Name"
          type="text"
          value={formData.fullName}
          disabled
          helperText="From your Google account"
        />

        {/* Role Selection */}
        <div>
          <label className="block text-sm font-medium mb-3" style={{ color: 'var(--auth-text)' }}>
            Select your role <span style={{ color: '#ef4444' }}>*</span>
          </label>
          <div className="grid gap-3">
            {roleOptions.map((option) => (
              <button
                key={option.value}
                type="button"
                onClick={() => {
                  setFormData({ ...formData, role: option.value as UserRole });
                  setErrors({ ...errors, role: '' });
                }}
                className={`flex items-center gap-3 p-4 rounded-lg border-2 transition-all ${
                  formData.role === option.value
                    ? 'border-teal-500 bg-teal-50'
                    : 'border-gray-200 hover:border-teal-300'
                }`}
              >
                <span className="text-2xl">{option.icon}</span>
                <span className="font-medium">{option.label}</span>
              </button>
            ))}
          </div>
          {errors.role && (
            <p className="mt-2 text-sm text-red-600">{errors.role}</p>
          )}
        </div>

        {/* Phone Number */}
        <Input
          id="phoneNumber"
          label="Phone Number"
          type="tel"
          placeholder="0987654321"
          value={formData.phoneNumber}
          onChange={(e) => {
            setFormData({ ...formData, phoneNumber: e.target.value });
            setErrors({ ...errors, phoneNumber: '' });
          }}
          error={errors.phoneNumber}
          helperText="Vietnam format: 0[3|5|7|8|9]xxxxxxxx"
          required
        />

        <Button 
          type="submit" 
          variant="primary" 
          className="w-full py-3 text-base font-medium justify-center"
          disabled={loading}
        >
          {loading ? 'Creating Account...' : 'Complete Sign Up'}
        </Button>
      </form>
    </AuthLayout>
  );
}

export default GoogleCompletePage;

import { useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { ROUTES, STORAGE_KEYS } from "@/constants";
import { toast } from "sonner";
import { setStoredItem } from "@/shared/utils/storage";

export function GoogleSuccessPage() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();

  useEffect(() => {
    // Backend OAuth now sets tokens in httpOnly cookies
    // Check if authentication was successful (backend should set a success flag or user data)
    const success = searchParams.get("success");
    const userData = searchParams.get("user");

    if (success === "true" && userData) {
      try {
        // Save user info to localStorage (tokens are in httpOnly cookies)
        const user = JSON.parse(decodeURIComponent(userData));
        setStoredItem(STORAGE_KEYS.USER, JSON.stringify(user), true);
        
        toast.success("Welcome back!");
        navigate(ROUTES.DASHBOARD);
      } catch (error) {
        toast.error("Authentication failed");
        navigate(ROUTES.LOGIN);
      }
    } else {
      toast.error("Authentication failed");
      navigate(ROUTES.LOGIN);
    }
  }, [searchParams, navigate]);

  return (
    <div className="min-h-screen flex items-center justify-center">
      <div className="text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-500 mx-auto mb-4"></div>
        <p className="text-gray-600">Signing you in...</p>
      </div>
    </div>
  );
}

export default GoogleSuccessPage;

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Upload, Camera, User, CheckCircle, ArrowLeft, ArrowRight, Loader2, XCircle } from 'lucide-react';
import { Button } from '@/shared/components/custom/Button';
import { Input } from '@/shared/components/custom/input';
import { toast } from 'sonner';
import { ROUTES, STORAGE_KEYS } from '@/constants';
import { getStoredJson } from '@/shared/utils';

interface KYCFormData {
  // Personal Information
  fullName: string;
  dateOfBirth: string;
  idNumber: string;
  address: string;
  
  // Identity Documents
  idCardFront: File | null;
  idCardBack: File | null;
  
  // Selfie
  selfiePhoto: File | null;
}

export default function KYCPage() {
  const navigate = useNavigate();

  const [currentStep, setCurrentStep] = useState(1);
  const [submissionStatus, setSubmissionStatus] = useState<'idle' | 'processing' | 'approved' | 'rejected'>('idle');
  const [rejectionReason, setRejectionReason] = useState('');
  const [formData, setFormData] = useState<KYCFormData>({
    fullName: '',
    dateOfBirth: '',
    idNumber: '',
    address: '',
    idCardFront: null,
    idCardBack: null,
    selfiePhoto: null,
  });
  const [previews, setPreviews] = useState({
    idCardFront: '',
    idCardBack: '',
    selfiePhoto: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(false);
  const baseUrl = import.meta.env.VITE_API_URL || 'http://localhost:3000';

  const steps = [
    { number: 1, title: 'Personal Info', icon: User },
    { number: 2, title: 'ID Verification', icon: Upload },
    { number: 3, title: 'Selfie', icon: Camera },
  ];

  const handleFileChange = (field: 'idCardFront' | 'idCardBack' | 'selfiePhoto', file: File | null) => {
    if (file) {
      // Validate file type
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, [field]: 'Please upload an image file' }));
        return;
      }
      
      // Validate file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        setErrors(prev => ({ ...prev, [field]: 'File size must be less than 5MB' }));
        return;
      }

      setFormData(prev => ({ ...prev, [field]: file }));
      
      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreviews(prev => ({ ...prev, [field]: reader.result as string }));
      };
      reader.readAsDataURL(file);
      
      // Clear error
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  };

  const handleDrop = (e: React.DragEvent, field: 'idCardFront' | 'idCardBack' | 'selfiePhoto') => {
    e.preventDefault();
    e.stopPropagation();
    
    const file = e.dataTransfer.files[0];
    if (file) {
      handleFileChange(field, file);
    }
  };

  const validateStep1 = (): boolean => {
    const newErrors: Record<string, string> = {};
    
    if (!formData.fullName.trim()) {
      newErrors.fullName = 'Full name is required';
    }
    
    if (!formData.dateOfBirth) {
      newErrors.dateOfBirth = 'Date of birth is required';
    } else {
      // Validate age (must be at least 18 years old)
      const dob = new Date(formData.dateOfBirth);
      const today = new Date();
      
      if (isNaN(dob.getTime())) {
        newErrors.dateOfBirth = 'Invalid date format';
      } else if (dob > today) {
        newErrors.dateOfBirth = 'Date of birth cannot be in the future';
      } else {
        // Calculate age
        let age = today.getFullYear() - dob.getFullYear();
        const monthDiff = today.getMonth() - dob.getMonth();
        
        if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < dob.getDate())) {
          age--;
        }
        
        if (age < 18) {
          newErrors.dateOfBirth = 'You must be at least 18 years old';
        } else if (age > 120) {
          newErrors.dateOfBirth = 'Please enter a valid date of birth';
        }
      }
    }
    
    if (!formData.idNumber.trim()) {
      newErrors.idNumber = 'ID number is required';
    } else if (!/^\d{9,12}$/.test(formData.idNumber.trim())) {
      newErrors.idNumber = 'Invalid ID number (9-12 digits)';
    }
    
    if (!formData.address.trim()) {
      newErrors.address = 'Address is required';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateStep2 = (): boolean => {
    const newErrors: Record<string, string> = {};
    
    if (!formData.idCardFront) {
      newErrors.idCardFront = 'Please upload the front of your ID card';
    }
    
    if (!formData.idCardBack) {
      newErrors.idCardBack = 'Please upload the back of your ID card';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateStep3 = (): boolean => {
    const newErrors: Record<string, string> = {};
    
    if (!formData.selfiePhoto) {
      newErrors.selfiePhoto = 'Please upload a selfie photo';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    let isValid = false;
    
    if (currentStep === 1) {
      isValid = validateStep1();
    } else if (currentStep === 2) {
      isValid = validateStep2();
    } else if (currentStep === 3) {
      isValid = validateStep3();
    }
    
    if (isValid && currentStep < 3) {
      setCurrentStep(prev => prev + 1);
    } else if (isValid && currentStep === 3) {
      handleSubmit();
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(prev => prev - 1);
    }
  };

  const handleSubmit = async () => {
    setLoading(true);
    
    try {
      // Create FormData for file upload
      const submitData = new FormData();
      submitData.append('fullNameOnDocument', formData.fullName);
      submitData.append('dateOfBirth', formData.dateOfBirth);
      submitData.append('documentNumber', formData.idNumber);
      submitData.append('documentType', 'CCCD');
      
      if (formData.idCardFront) {
        submitData.append('idCardFront', formData.idCardFront);
      }
      if (formData.idCardBack) {
        submitData.append('idCardBack', formData.idCardBack);
      }
      if (formData.selfiePhoto) {
        submitData.append('selfie', formData.selfiePhoto);
      }
      
      // Call KYC API
      const response = await fetch(`${baseUrl}/kyc`, {
        method: 'POST',
        credentials: 'include', // Send httpOnly cookies
        body: submitData,
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to submit KYC');
      }
      
      toast.success('KYC submitted successfully. Your documents are being processed.');
      setSubmissionStatus('processing');
    } catch (error: any) {
      toast.error(error.message || 'Unable to submit KYC. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const checkKycStatus = async () => {
    try {
      const response = await fetch(`${baseUrl}/kyc/me`, {
        credentials: 'include', // Send httpOnly cookies
      });

      if (!response.ok) return;
      const data = await response.json();
      const status = data.status;

      if (status === 'APPROVED') {
        setSubmissionStatus('approved');
        setRejectionReason('');
      } else if (status === 'REJECTED') {
        setSubmissionStatus('rejected');
        setRejectionReason(
          data.rejectionReason ||
            data.message ||
            'Your documents are not valid. Please check and resubmit.'
        );
      } else if (status === 'PENDING') {
        setSubmissionStatus('processing');
      }
    } catch (error) {
      // Silent failure for status check
    }
  };

  useEffect(() => {
    if (submissionStatus !== 'processing') return;

    checkKycStatus();
    const interval = setInterval(checkKycStatus, 5000);
    return () => clearInterval(interval);
  }, [submissionStatus]);

  const handleBackToDashboard = () => {
    // Get user role and navigate to appropriate dashboard
    const user = getStoredJson<{ role?: string }>(STORAGE_KEYS.USER);
    const role = user?.role?.toUpperCase();
    
    let dashboardRoute: string = ROUTES.CLIENT_DASHBOARD;
    
    if (role === 'FREELANCER') {
      dashboardRoute = ROUTES.FREELANCER_DASHBOARD;
    } else if (role === 'BROKER') {
      dashboardRoute = ROUTES.BROKER_DASHBOARD;
    } else if (role === 'ADMIN') {
      dashboardRoute = ROUTES.ADMIN_DASHBOARD;
    } else if (role === 'STAFF') {
      dashboardRoute = ROUTES.ADMIN_DASHBOARD; // Staff uses admin dashboard
    }
    
    navigate(dashboardRoute);
  };

  const handleRetry = () => {
    setSubmissionStatus('idle');
    setCurrentStep(1);
  };

  if (submissionStatus !== 'idle') {
    const isProcessing = submissionStatus === 'processing';
    const isApproved = submissionStatus === 'approved';
    const isRejected = submissionStatus === 'rejected';

    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50 py-12 px-4">
        <div className="max-w-2xl mx-auto">
          <div className="bg-white rounded-xl shadow-lg p-8 text-center">
            {isProcessing && (
              <>
                <div className="flex justify-center mb-6">
                  <div className="w-20 h-20 rounded-full bg-yellow-100 flex items-center justify-center">
                    <Loader2 className="w-10 h-10 text-yellow-600 animate-spin" />
                  </div>
                </div>
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Verification in progress</h1>
                <p className="text-gray-600">
                  We are reviewing your ID documents. Please wait a few minutes.
                </p>
                <div className="space-y-3 mt-6">
                  <Button onClick={handleBackToDashboard} className="w-full">
                    Back to dashboard
                  </Button>
                  <Button variant="outline" onClick={() => {
                    const user = getStoredJson<{ role?: string }>(STORAGE_KEYS.USER);
                    const role = user?.role?.toUpperCase();
                    if (role === 'FREELANCER') {
                      navigate(ROUTES.FREELANCER_KYC_STATUS);
                    } else if (role === 'BROKER') {
                      navigate(ROUTES.BROKER_KYC_STATUS);
                    } else {
                      navigate(ROUTES.CLIENT_KYC_STATUS);
                    }
                  }} className="w-full">
                    Check status
                  </Button>
                </div>
              </>
            )}

            {isApproved && (
              <>
                <div className="flex justify-center mb-6">
                  <div className="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center">
                    <CheckCircle className="w-10 h-10 text-green-600" />
                  </div>
                </div>
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Verification approved</h1>
                <p className="text-gray-600">
                  Your documents have been verified. You can return to your dashboard.
                </p>
                <div className="mt-6">
                  <Button onClick={handleBackToDashboard} className="w-full">
                    Back to dashboard
                  </Button>
                </div>
              </>
            )}

            {isRejected && (
              <>
                <div className="flex justify-center mb-6">
                  <div className="w-20 h-20 rounded-full bg-red-100 flex items-center justify-center">
                    <XCircle className="w-10 h-10 text-red-600" />
                  </div>
                </div>
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Verification failed</h1>
                <p className="text-gray-600">
                  {rejectionReason}
                </p>
                <div className="space-y-3 mt-6">
                  <Button onClick={handleRetry} className="w-full">
                    Re-enter information
                  </Button>
                  <Button variant="outline" onClick={handleBackToDashboard} className="w-full">
                    Back to dashboard
                  </Button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    );
  }

  const renderUploadBox = (
    field: 'idCardFront' | 'idCardBack' | 'selfiePhoto',
    label: string,
    icon: React.ReactNode
  ) => (
    <div>
      <label className="block text-sm font-medium text-gray-700 mb-2">
        {label} <span className="text-red-500">*</span>
      </label>
      
      <div
        onDragOver={handleDragOver}
        onDrop={(e) => handleDrop(e, field)}
        className={`relative border-2 border-dashed rounded-lg p-6 text-center transition-colors ${
          errors[field] ? 'border-red-300 bg-red-50' : 'border-gray-300 hover:border-blue-400 bg-gray-50'
        }`}
      >
        {previews[field] ? (
          <div className="space-y-3">
            <img
              src={previews[field]}
              alt={label}
              className="mx-auto max-h-48 rounded-lg object-contain"
            />
            <button
              type="button"
              onClick={() => {
                setFormData(prev => ({ ...prev, [field]: null }));
                setPreviews(prev => ({ ...prev, [field]: '' }));
              }}
              className="text-sm text-red-600 hover:text-red-700 font-medium"
            >
              Remove
            </button>
          </div>
        ) : (
          <label className="cursor-pointer">
            <input
              type="file"
              accept="image/*"
              className="hidden"
              onChange={(e) => handleFileChange(field, e.target.files?.[0] || null)}
            />
            <div className="flex flex-col items-center">
              <div className="text-gray-400 mb-3">{icon}</div>
              <p className="text-sm text-gray-600 mb-1">
                Click to upload or drag and drop
              </p>
              <p className="text-xs text-gray-500">
                PNG, JPG, JPEG (max 5MB)
              </p>
            </div>
          </label>
        )}
      </div>
      
      {errors[field] && (
        <p className="mt-2 text-sm text-red-600">{errors[field]}</p>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50 py-12 px-4">
      <div className="max-w-3xl mx-auto">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Identity Verification (KYC)
          </h1>
          <p className="text-gray-600">
            Please provide your information for identity verification
          </p>
        </div>

        {/* Progress Steps */}
        <div className="mb-8">
          <div className="flex items-center justify-between">
            {steps.map((step, index) => {
              const Icon = step.icon;
              const isActive = currentStep === step.number;
              const isCompleted = currentStep > step.number;
              
              return (
                <React.Fragment key={step.number}>
                  <div className="flex flex-col items-center flex-1">
                    <div
                      className={`w-12 h-12 rounded-full flex items-center justify-center mb-2 transition-colors ${
                        isCompleted
                          ? 'bg-green-500 text-white'
                          : isActive
                          ? 'bg-blue-600 text-white'
                          : 'bg-gray-200 text-gray-500'
                      }`}
                    >
                      {isCompleted ? (
                        <CheckCircle className="w-6 h-6" />
                      ) : (
                        <Icon className="w-6 h-6" />
                      )}
                    </div>
                    <p
                      className={`text-sm font-medium ${
                        isActive ? 'text-blue-600' : 'text-gray-500'
                      }`}
                    >
                      {step.title}
                    </p>
                  </div>
                  
                  {index < steps.length - 1 && (
                    <div
                      className={`flex-1 h-1 mx-2 transition-colors ${
                        currentStep > step.number ? 'bg-green-500' : 'bg-gray-200'
                      }`}
                    />
                  )}
                </React.Fragment>
              );
            })}
          </div>
        </div>

        {/* Form Card */}
        <div className="bg-white rounded-xl shadow-lg p-8">
          {/* Step 1: Personal Information */}
          {currentStep === 1 && (
            <div className="space-y-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Personal Information
              </h2>
              
              <Input
                id="fullName"
                label="Full Name (as shown on ID)"
                type="text"
                placeholder="Nguyen Van A"
                value={formData.fullName}
                onChange={(e) => setFormData(prev => ({ ...prev, fullName: e.target.value }))}
                error={errors.fullName}
                required
              />
              
              <Input
                id="dateOfBirth"
                label="Date of Birth"
                type="date"
                value={formData.dateOfBirth}
                onChange={(e) => setFormData(prev => ({ ...prev, dateOfBirth: e.target.value }))}
                error={errors.dateOfBirth}
                helperText="You must be at least 18 years old"
                required
                max={(() => {
                  // Max date: 18 years ago from today
                  const today = new Date();
                  today.setFullYear(today.getFullYear() - 18);
                  return today.toISOString().split('T')[0];
                })()}
                min={(() => {
                  // Min date: 120 years ago (reasonable max age)
                  const today = new Date();
                  today.setFullYear(today.getFullYear() - 120);
                  return today.toISOString().split('T')[0];
                })()}
              />
              
              <Input
                id="idNumber"
                label="ID Card Number (CCCD)"
                type="text"
                placeholder="001234567890"
                value={formData.idNumber}
                onChange={(e) => setFormData(prev => ({ ...prev, idNumber: e.target.value }))}
                error={errors.idNumber}
                helperText="Enter 9-12 digit ID number"
                required
              />
              
              <div>
                <label htmlFor="address" className="block text-sm font-medium text-gray-700 mb-2">
                  Address <span className="text-red-500">*</span>
                </label>
                <textarea
                  id="address"
                  rows={3}
                  className={`w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 ${
                    errors.address ? 'border-red-500' : 'border-gray-300'
                  }`}
                  placeholder="123 Street Name, Ward, District, City"
                  value={formData.address}
                  onChange={(e) => setFormData(prev => ({ ...prev, address: e.target.value }))}
                />
                {errors.address && (
                  <p className="mt-2 text-sm text-red-600">{errors.address}</p>
                )}
              </div>
            </div>
          )}

          {/* Step 2: ID Verification */}
          {currentStep === 2 && (
            <div className="space-y-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Upload ID Card Photos
              </h2>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {renderUploadBox(
                  'idCardFront',
                  'ID Card - Front Side',
                  <Upload className="w-12 h-12" />
                )}
                
                {renderUploadBox(
                  'idCardBack',
                  'ID Card - Back Side',
                  <Upload className="w-12 h-12" />
                )}
              </div>
              
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                <p className="text-sm text-blue-800">
                  <strong>Tips for better verification:</strong>
                </p>
                <ul className="list-disc list-inside text-sm text-blue-700 mt-2 space-y-1">
                  <li>Make sure the ID card is clearly visible</li>
                  <li>Avoid glare or shadows</li>
                  <li>All text should be readable</li>
                  <li>Photo should not be blurry</li>
                </ul>
              </div>
            </div>
          )}

          {/* Step 3: Selfie Verification */}
          {currentStep === 3 && (
            <div className="space-y-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Upload Selfie Photo
              </h2>
              
              {renderUploadBox(
                'selfiePhoto',
                'Selfie with ID Card',
                <Camera className="w-12 h-12" />
              )}
              
              <div className="bg-amber-50 border border-amber-200 rounded-lg p-4">
                <p className="text-sm text-amber-800">
                  <strong>Selfie requirements:</strong>
                </p>
                <ul className="list-disc list-inside text-sm text-amber-700 mt-2 space-y-1">
                  <li>Hold your ID card next to your face</li>
                  <li>Make sure your face is clearly visible</li>
                  <li>Good lighting (avoid too bright or too dark)</li>
                  <li>Look straight at the camera</li>
                  <li>Do not wear sunglasses or hat</li>
                </ul>
              </div>
            </div>
          )}

          {/* Navigation Buttons */}
          <div className="flex items-center justify-between mt-8 pt-6 border-t">
            <Button
              variant="outline"
              onClick={handleBack}
              disabled={currentStep === 1 || loading}
              className="flex items-center gap-2"
            >
              <ArrowLeft className="w-4 h-4" />
              Back
            </Button>
            
            <Button
              onClick={handleNext}
              disabled={loading}
              className="flex items-center gap-2"
            >
              {currentStep === 3 ? (
                loading ? 'Submitting...' : 'Submit'
              ) : (
                <>
                  Next
                  <ArrowRight className="w-4 h-4" />
                </>
              )}
            </Button>
          </div>
        </div>

        {/* Security Notice */}
        <div className="mt-6 text-center text-sm text-gray-500">
          <p>🔒 Your information is encrypted and securely stored</p>
        </div>
      </div>
    </div>
  );
}

﻿import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  CheckCircle,
  XCircle,
  Clock,
  ShieldCheck,
  AlertTriangle,
  ArrowRight,
  RefreshCw,
} from 'lucide-react';
import { Button } from '@/shared/components/custom/Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/Card';
import { Badge } from '@/shared/components/ui/badge';
import { Spinner } from '@/shared/components/ui';
import { ROUTES } from '@/constants';

type KYCStatus = 'NOT_SUBMITTED' | 'NOT_STARTED' | 'PENDING' | 'APPROVED' | 'REJECTED';

interface KYCData {
  status: KYCStatus;
  rejectionReason?: string;
  submittedAt?: string;
  reviewedAt?: string;
}

export default function KYCStatusPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [kycData, setKycData] = useState<KYCData | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const baseUrl = import.meta.env.VITE_API_URL || 'http://localhost:3000';

  const fetchKYCStatus = async (showRefreshing = false) => {
    try {
      if (showRefreshing) setRefreshing(true);
      
      const response = await fetch(`${baseUrl}/kyc/me`, {
        credentials: 'include',
      });

      if (response.status === 404) {
        // No KYC record found - not submitted yet
        setKycData({ status: 'NOT_SUBMITTED' });
        return;
      }

      if (!response.ok) {
        throw new Error('Failed to fetch KYC status');
      }

      const data = await response.json();
      setKycData({
        status: data.status,
        rejectionReason: data.rejectionReason,
        submittedAt: data.createdAt,
        reviewedAt: data.reviewedAt,
      });
    } catch (error) {
      setKycData({ status: 'NOT_SUBMITTED' });
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchKYCStatus();
  }, []);

  // Auto-refresh when pending
  useEffect(() => {
    if (kycData?.status !== 'PENDING') return;

    const interval = setInterval(() => fetchKYCStatus(), 10000);
    return () => clearInterval(interval);
  }, [kycData?.status]);

  const getStatusConfig = (status: KYCStatus) => {
    switch (status) {
      case 'APPROVED':
        return {
          icon: CheckCircle,
          color: 'text-green-600',
          bgColor: 'bg-green-50',
          borderColor: 'border-green-200',
          badgeVariant: 'default' as const,
          badgeClass: 'bg-green-100 text-green-800 hover:bg-green-100',
          title: 'Identity Verified',
          description: 'Your identity has been successfully verified. You have full access to all platform features.',
        };
      case 'PENDING':
        return {
          icon: Clock,
          color: 'text-yellow-600',
          bgColor: 'bg-yellow-50',
          borderColor: 'border-yellow-200',
          badgeVariant: 'secondary' as const,
          badgeClass: 'bg-yellow-100 text-yellow-800 hover:bg-yellow-100',
          title: 'Verification In Progress',
          description: 'Your documents are being reviewed. This usually takes 1-2 business days.',
        };
      case 'REJECTED':
        return {
          icon: XCircle,
          color: 'text-red-600',
          bgColor: 'bg-red-50',
          borderColor: 'border-red-200',
          badgeVariant: 'destructive' as const,
          badgeClass: 'bg-red-100 text-red-800 hover:bg-red-100',
          title: 'Verification Failed',
          description: 'Your identity verification was not successful. Please review the reason below and try again.',
        };
      case 'NOT_STARTED':
      default:
        return {
          icon: ShieldCheck,
          color: 'text-slate-600',
          bgColor: 'bg-slate-50',
          borderColor: 'border-slate-200',
          badgeVariant: 'outline' as const,
          badgeClass: 'bg-slate-100 text-slate-800 hover:bg-slate-100',
          title: 'Identity Not Verified',
          description: 'Complete identity verification to unlock all platform features and build trust with other users.',
        };
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Spinner size="lg" />
      </div>
    );
  }

  const status = kycData?.status || 'NOT_SUBMITTED';
  const isNotVerified = status === 'NOT_SUBMITTED' || status === 'NOT_STARTED';
  const config = getStatusConfig(status);
  const StatusIcon = config.icon;

  return (
    <div className="container mx-auto max-w-2xl py-8 px-4">
      <div className="mb-8">
        <h1 className="text-2xl font-bold tracking-tight">KYC Verification</h1>
        <p className="text-muted-foreground mt-1">
          Verify your identity to access all platform features
        </p>
      </div>

      {/* Status Card */}
      <Card className={`${config.borderColor} border-2`}>
        <CardHeader className={`${config.bgColor} rounded-t-lg`}>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className={`p-3 rounded-full ${config.bgColor}`}>
                <StatusIcon className={`h-8 w-8 ${config.color}`} />
              </div>
              <div>
                <CardTitle className="text-lg">{config.title}</CardTitle>
                <Badge className={config.badgeClass}>
                  {isNotVerified ? 'NOT_STARTED' : status}
                </Badge>
              </div>
            </div>
            {status === 'PENDING' && (
              <Button
                variant="outline"
                onClick={() => fetchKYCStatus(true)}
                disabled={refreshing}
              >
                <RefreshCw className={`h-4 w-4 ${refreshing ? 'animate-spin' : ''}`} />
              </Button>
            )}
          </div>
        </CardHeader>
        <CardContent className="pt-6">
          <p className="text-muted-foreground mb-6">{config.description}</p>

          {/* Rejection Reason */}
          {status === 'REJECTED' && kycData?.rejectionReason && (
            <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
              <div className="flex items-start gap-3">
                <AlertTriangle className="h-5 w-5 text-red-600 mt-0.5" />
                <div>
                  <p className="font-medium text-red-800">Reason for Rejection</p>
                  <p className="text-red-700 text-sm mt-1">{kycData.rejectionReason}</p>
                </div>
              </div>
            </div>
          )}

          {/* Submission Info */}
          {kycData?.submittedAt && !isNotVerified && (
            <div className="text-sm text-muted-foreground mb-6">
              <p>
                Submitted on:{' '}
                <span className="font-medium">
                  {new Date(kycData.submittedAt).toLocaleDateString('en-US', {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </span>
              </p>
              {kycData?.reviewedAt && status === 'APPROVED' && (
                <p className="mt-1">
                  Verified on:{' '}
                  <span className="font-medium">
                    {new Date(kycData.reviewedAt).toLocaleDateString('en-US', {
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit',
                    })}
                  </span>
                </p>
              )}
            </div>
          )}

          {/* Action Buttons */}
          {(isNotVerified || status === 'REJECTED') && (
            <Button
              onClick={() => navigate(ROUTES.KYC_VERIFICATION)}
              className="w-full bg-teal-600 hover:bg-teal-700"
            >
              {status === 'REJECTED' ? 'Resubmit Verification' : 'Start Verification'}
              <ArrowRight className="ml-2 h-4 w-4" />
            </Button>
          )}

          {status === 'PENDING' && (
            <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
              <div className="flex items-center gap-3">
                <Clock className="h-5 w-5 text-yellow-600 animate-pulse" />
                <p className="text-yellow-800 text-sm">
                  Please wait while we verify your documents. You'll be notified once the review is complete.
                </p>
              </div>
            </div>
          )}

          {status === 'APPROVED' && (
            <div className="bg-green-50 border border-green-200 rounded-lg p-4">
              <div className="flex items-center gap-3">
                <CheckCircle className="h-5 w-5 text-green-600" />
                <p className="text-green-800 text-sm">
                  You're all set! Your verified status helps build trust with other users on the platform.
                </p>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Benefits Section */}
      {isNotVerified && (
        <Card className="mt-6">
          <CardHeader>
            <CardTitle className="text-base">Why Verify Your Identity?</CardTitle>
            <CardDescription>Benefits of completing KYC verification</CardDescription>
          </CardHeader>
          <CardContent>
            <ul className="space-y-3">
              <li className="flex items-start gap-3">
                <CheckCircle className="h-5 w-5 text-green-600 mt-0.5" />
                <div>
                  <p className="font-medium">Unlock All Features</p>
                  <p className="text-sm text-muted-foreground">
                    Access project creation, bidding, and contract features
                  </p>
                </div>
              </li>
              <li className="flex items-start gap-3">
                <CheckCircle className="h-5 w-5 text-green-600 mt-0.5" />
                <div>
                  <p className="font-medium">Build Trust</p>
                  <p className="text-sm text-muted-foreground">
                    Verified badge increases your credibility with other users
                  </p>
                </div>
              </li>
              <li className="flex items-start gap-3">
                <CheckCircle className="h-5 w-5 text-green-600 mt-0.5" />
                <div>
                  <p className="font-medium">Secure Transactions</p>
                  <p className="text-sm text-muted-foreground">
                    Participate in secure financial transactions on the platform
                  </p>
                </div>
              </li>
            </ul>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Mail, Phone, MapPin, Edit2, Shield, ExternalLink, FileText, Download, ArrowLeft, Briefcase, X, TrendingUp, Trash2 } from 'lucide-react';
import { toast } from "sonner";
import { getProfile, updateProfile } from "@/features/auth/api";
import { STORAGE_KEYS } from "@/constants";
import { TrustScoreCard } from "@/features/trust-profile/components";
import type { BadgeType } from "@/features/trust-profile/types";
import { getStoredJson, setStoredJsonAuto } from "@/shared/utils/storage";
import { DeleteAccountModal } from "@/shared/components/auth/DeleteAccountModal";

interface UserProfile {
  id: string;
  email: string;
  fullName: string;
  phoneNumber: string;
  role: string;
  avatarUrl?: string;
  bio?: string;
  badge: BadgeType;
  isVerified: boolean;
  isEmailVerified?: boolean;
  currentTrustScore: number;
  skills?: string[];
  linkedinUrl?: string;
  cvUrl?: string;
  stats?: {
    finished: number;
    disputes: number;
    score: number;
  };
}

export default function ProfilePage() {
  const navigate = useNavigate();
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  const [formData, setFormData] = useState({
    fullName: "",
    phoneNumber: "",
    bio: "",
  });

  const [avatarPreview, setAvatarPreview] = useState<string>("");
  const [avatarFile, setAvatarFile] = useState<File | null>(null);

  useEffect(() => {
    loadProfile();
  }, []);

  const loadProfile = async () => {
    try {
      setLoading(true);
      const response = (await getProfile()) as any;
      const userData = response.data || response.data?.data;
      setProfile(userData);
      setFormData({
        fullName: userData.fullName || "",
        phoneNumber: userData.phoneNumber || "",
        bio: userData.bio || "",
      });
      setAvatarPreview(userData.avatarUrl || "");

      // Keep header avatar/name in sync with latest profile
      const user = getStoredJson<any>(STORAGE_KEYS.USER);
      if (user) {
        user.fullName = userData.fullName || user.fullName;
        user.avatarUrl = userData.avatarUrl || "";
        setStoredJsonAuto(STORAGE_KEYS.USER, user);
        window.dispatchEvent(new Event("userDataUpdated"));
      }
    } catch (error: any) {
      toast.error("Failed to load profile information");
    } finally {
      setLoading(false);
    }
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("image/")) {
      toast.error("Please select an image file");
      return;
    }

    if (file.size > 5 * 1024 * 1024) {
      toast.error("Image size must not exceed 5MB");
      return;
    }

    setAvatarFile(file);
    const reader = new FileReader();
    reader.onloadend = () => {
      setAvatarPreview(reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      setSaving(true);

      const avatarUrl = avatarFile ? avatarPreview : profile?.avatarUrl;

      // Warning about base64 - should use cloud storage in production
      if (avatarFile && avatarPreview.length > 100000) {
        toast.warning(
          "Large avatar size detected. Consider using cloud storage for production."
        );
      }

      await updateProfile({
        fullName: formData.fullName,
        phoneNumber: formData.phoneNumber,
        bio: formData.bio,
        avatarUrl,
      });

      toast.success("Profile updated successfully");
      setIsEditing(false);
      await loadProfile();

      // Update user data in storage to sync with Header
      const user = getStoredJson<any>(STORAGE_KEYS.USER);
      if (user) {
        user.fullName = formData.fullName;
        user.avatarUrl = avatarUrl;
        setStoredJsonAuto(STORAGE_KEYS.USER, user);

        // Dispatch custom event to notify Header of the change
        window.dispatchEvent(new Event("userDataUpdated"));
      }
    } catch (error: any) {
      const errorMessage =
        error.response?.data?.message || "Failed to update profile";
      toast.error(errorMessage);
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    setIsEditing(false);
    setFormData({
      fullName: profile?.fullName || "",
      phoneNumber: profile?.phoneNumber || "",
      bio: profile?.bio || "",
    });
    setAvatarPreview(profile?.avatarUrl || "");
    setAvatarFile(null);
  };

  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2);
  };

  const getRoleBadgeStyle = (role: string) => {
    const styles: Record<string, string> = {
      ADMIN: "bg-purple-100 text-purple-700",
      CLIENT: "bg-blue-100 text-blue-700",
      SME: "bg-blue-100 text-blue-700",
      FREELANCER: "bg-green-100 text-green-700",
      BROKER: "bg-orange-100 text-orange-700",
    };
    return styles[role?.toUpperCase()] || "bg-gray-100 text-gray-700";
  };

  const getRoleDisplayName = (role: string) => {
    const names: Record<string, string> = {
      ADMIN: "Administrator",
      CLIENT: "SME Client",
      SME: "SME Client",
      FREELANCER: "Freelancer",
      BROKER: "Broker",
    };
    return names[role?.toUpperCase()] || role;
  };

  const handleViewCV = () => {
    if (!profile?.cvUrl) return;
    
    try {
      // Convert base64 to blob for better browser compatibility
      const base64Data = profile.cvUrl.split(',')[1];
      const mimeType = profile.cvUrl.split(',')[0].split(':')[1].split(';')[0];
      
      const byteCharacters = atob(base64Data);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: mimeType });
      
      // Create object URL and open in new tab
      const blobUrl = URL.createObjectURL(blob);
      window.open(blobUrl, '_blank');
      
      // Clean up the URL after a delay
      setTimeout(() => URL.revokeObjectURL(blobUrl), 100);
    } catch (error) {
      toast.error('Failed to open CV. Try downloading instead.');
    }
  };

  const handleDownloadCV = () => {
    if (!profile?.cvUrl) return;
    
    try {
      // Convert base64 to blob
      const base64Data = profile.cvUrl.split(',')[1];
      const mimeType = profile.cvUrl.split(',')[0].split(':')[1].split(';')[0];
      
      // Determine file extension based on MIME type
      let extension = '.pdf';
      if (mimeType.includes('png')) extension = '.png';
      else if (mimeType.includes('jpeg') || mimeType.includes('jpg')) extension = '.jpg';
      
      const byteCharacters = atob(base64Data);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: mimeType });
      
      // Create download link
      const blobUrl = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `CV_${profile.fullName.replace(/\s+/g, '_')}${extension}`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      
      // Clean up
      setTimeout(() => URL.revokeObjectURL(blobUrl), 100);
      toast.success('CV downloaded successfully');
    } catch (error) {
      toast.error('Failed to download CV');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-lg">Loading...</div>
      </div>
    );
  }

  if (!profile) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-lg text-red-500">Profile not found</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8 px-4">
      {/* Back button */}
      <div className="max-w-7xl mx-auto mb-6">
        <button
          onClick={() => navigate(-1)}
          className="flex items-center gap-2 text-gray-600 hover:text-gray-900"
        >
          <ArrowLeft className="w-5 h-5" />
          Back
        </button>
      </div>

      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column - Profile Card */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-lg shadow-sm p-6 sticky top-8">
            {/* Avatar */}
            <div className="flex flex-col items-center">
              <div className="relative">
                <div className="w-40 h-40 rounded-full bg-blue-500 flex items-center justify-center text-white text-5xl font-bold border-4 border-white shadow-lg">
                  {avatarPreview ? (
                    <img
                      src={avatarPreview}
                      alt="Avatar"
                      className="w-full h-full rounded-full object-cover"
                    />
                  ) : (
                    getInitials(profile.fullName)
                  )}
                </div>

                {/* Camera icon for upload when editing */}
                {isEditing && (
                  <label
                    htmlFor="avatar-upload"
                    className="absolute bottom-2 right-2 bg-blue-600 text-white p-3 rounded-full cursor-pointer hover:bg-blue-700 shadow-lg transition-colors"
                  >
                    <Edit2 className="w-5 h-5" />
                    <input
                      id="avatar-upload"
                      type="file"
                      accept="image/*"
                      onChange={handleAvatarChange}
                      className="hidden"
                    />
                  </label>
                )}
              </div>

              {/* Name */}
              <h2 className="mt-4 text-2xl font-bold text-gray-900">
                {profile.fullName}
              </h2>

              {/* Role Badge */}
              <div
                className={`mt-2 px-4 py-1.5 rounded-full flex items-center gap-2 ${getRoleBadgeStyle(
                  profile.role
                )}`}
              >
                <Briefcase className="w-4 h-4" />
                <span className="font-medium">
                  {getRoleDisplayName(profile.role)}
                </span>
              </div>
            </div>

            {/* Contact Info */}
            <div className="mt-6 space-y-4">
              <div className="flex items-center gap-3 text-gray-600">
                <Mail className="w-5 h-5 flex-shrink-0" />
                <span className="text-sm break-all">{profile.email}</span>
              </div>

              <div className="flex items-center gap-3 text-gray-600">
                <Phone className="w-5 h-5 flex-shrink-0" />
                <span className="text-sm">
                  {profile.phoneNumber || "Not updated"}
                </span>
              </div>

              {profile.bio && (
                <div className="flex items-start gap-3 text-gray-600">
                  <MapPin className="w-5 h-5 flex-shrink-0 mt-0.5" />
                  <span className="text-sm">{profile.bio}</span>
                </div>
              )}
            </div>

            {/* Trust Score Card - Using TrustScoreCard component */}
            <div className="mt-6">
              <TrustScoreCard
                user={{
                  id: profile.id,
                  fullName: profile.fullName,
                  avatarUrl: profile.avatarUrl || "",
                  isVerified: profile.isVerified,
                  isEmailVerified: profile.isEmailVerified,
                  currentTrustScore: profile.currentTrustScore,
                  badge: profile.badge,
                  stats: profile.stats || {
                    finished: 0,
                    disputes: 0,
                    score: profile.currentTrustScore,
                  },
                }}
              />
            </div>

            {/* Edit Button */}
            {!isEditing && (
              <button
                onClick={() => setIsEditing(true)}
                className="w-full mt-6 bg-blue-600 hover:bg-blue-700 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
              >
                <Edit2 className="w-5 h-5" />
                Edit Profile
              </button>
            )}

            {/* Delete Account Button */}
            {!isEditing && (
              <button
                onClick={() => setShowDeleteModal(true)}
                className="w-full mt-3 bg-white hover:bg-red-50 text-red-600 border border-red-300 font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
              >
                <Trash2 className="w-5 h-5" />
                Delete Account
              </button>
            )}
          </div>
        </div>

        {/* Right Column - Profile Details Form */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-xl font-bold text-gray-900">
                Profile Details
              </h3>
              {isEditing && (
                <button
                  onClick={handleCancel}
                  className="text-gray-500 hover:text-gray-700"
                >
                  <X className="w-6 h-6" />
                </button>
              )}
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Full Name */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Full Name <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={formData.fullName}
                  onChange={(e) =>
                    setFormData({ ...formData, fullName: e.target.value })
                  }
                  disabled={!isEditing}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent disabled:bg-gray-50 disabled:text-gray-500"
                  required
                />
              </div>

              {/* Email Address */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Email Address <span className="text-red-500">*</span>
                </label>
                <input
                  type="email"
                  value={profile.email}
                  disabled
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg bg-gray-50 text-gray-500"
                />
              </div>

              {/* Phone Number */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Phone Number <span className="text-red-500">*</span>
                </label>
                <input
                  type="tel"
                  value={formData.phoneNumber}
                  onChange={(e) =>
                    setFormData({ ...formData, phoneNumber: e.target.value })
                  }
                  disabled={!isEditing}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent disabled:bg-gray-50 disabled:text-gray-500"
                />
              </div>

              {/* Business Information */}
              <div>
                <h4 className="text-lg font-bold text-gray-900 mb-4">
                  Business Information
                </h4>

                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Address / Bio
                </label>
                <textarea
                  value={formData.bio}
                  onChange={(e) =>
                    setFormData({ ...formData, bio: e.target.value })
                  }
                  disabled={!isEditing}
                  rows={4}
                  maxLength={500}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent disabled:bg-gray-50 disabled:text-gray-500"
                  placeholder="Enter address or business information..."
                />
                <p className="text-sm text-gray-500 mt-1">
                  {formData.bio.length}/500 ký tự
                </p>
              </div>

              {/* Account Stats - Thông tin thêm để fill chỗ trống */}
              <div className="border-t pt-6">
                <h4 className="text-lg font-bold text-gray-900 mb-4">
                  Account Information
                </h4>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-4 bg-blue-50 rounded-lg">
                    <div className="flex items-center gap-2 mb-1">
                      <TrendingUp className="w-4 h-4 text-blue-600" />
                      <span className="text-sm text-gray-600">
                        Account Type
                      </span>
                    </div>
                    <p className="text-lg font-bold text-gray-900">
                      {getRoleDisplayName(profile.role)}
                    </p>
                  </div>

                  <div className="p-4 bg-green-50 rounded-lg">
                    <div className="flex items-center gap-2 mb-1">
                      <Shield className="w-4 h-4 text-green-600" />
                      <span className="text-sm text-gray-600">
                        KYC Verification
                      </span>
                    </div>
                    <p className="text-lg font-bold text-gray-900">
                      {profile.isVerified ? "KYC Verified" : "KYC Unverified"}
                    </p>
                  </div>
                </div>
              </div>

              {/* Freelancer Documents - Only for Freelancer role */}
              {profile.role === 'FREELANCER' && (profile.cvUrl || profile.linkedinUrl || (profile.skills && profile.skills.length > 0)) && (
                <div className="border-t pt-6">
                  <h4 className="text-lg font-bold text-gray-900 mb-4">Professional Information</h4>
                  
                  {/* Skills */}
                  {profile.skills && profile.skills.length > 0 && (
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700 mb-2">Skills</label>
                      <div className="flex flex-wrap gap-2">
                        {profile.skills.map((skill, index) => (
                          <span
                            key={index}
                            className="px-3 py-1.5 bg-blue-50 text-blue-700 rounded-full text-sm font-medium"
                          >
                            {skill}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* LinkedIn */}
                  {profile.linkedinUrl && (
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700 mb-2">LinkedIn Profile</label>
                      <a
                        href={profile.linkedinUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 text-blue-600 hover:text-blue-700 hover:underline"
                      >
                        <ExternalLink className="w-4 h-4" />
                        View LinkedIn Profile
                      </a>
                    </div>
                  )}

                  {/* CV Document */}
                  {profile.cvUrl && (
                    <div className="p-4 bg-gray-50 rounded-lg border border-gray-200">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="p-3 bg-blue-100 rounded-lg">
                            <FileText className="w-6 h-6 text-blue-600" />
                          </div>
                          <div>
                            <p className="font-medium text-gray-900">Curriculum Vitae (CV)</p>
                            <p className="text-sm text-gray-600">Your professional resume</p>
                          </div>
                        </div>
                        <div className="flex gap-2">
                          <button
                            onClick={handleDownloadCV}
                            type="button"
                            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors"
                          >
                            <Download className="w-4 h-4" />
                            Download
                          </button>
                          <button
                            onClick={handleViewCV}
                            type="button"
                            className="flex items-center gap-2 px-4 py-2 border border-gray-300 hover:bg-gray-100 text-gray-700 rounded-lg transition-colors"
                          >
                            <ExternalLink className="w-4 h-4" />
                            View
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {/* Action Buttons */}
              {isEditing && (
                <div className="flex gap-3 pt-4">
                  <button
                    type="submit"
                    disabled={saving}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-medium py-3 rounded-lg transition-colors disabled:opacity-50"
                  >
                    {saving ? "Saving..." : "Save Changes"}
                  </button>
                  <button
                    type="button"
                    onClick={handleCancel}
                    disabled={saving}
                    className="flex-1 bg-gray-200 hover:bg-gray-300 text-gray-700 font-medium py-3 rounded-lg transition-colors"
                  >
                    Cancel
                  </button>
                </div>
              )}
            </form>
          </div>
        </div>
      </div>

      {/* Delete Account Modal */}
      <DeleteAccountModal
        isOpen={showDeleteModal}
        onClose={() => setShowDeleteModal(false)}
        userEmail={profile?.email || ''}
      />
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Input } from "../shared/components/custom/input";
import { Button } from "../shared/components/custom/Button";
// import { GoogleButton } from '../shared/components/auth/GoogleButton';
import { PasswordStrength } from "../shared/components/auth/PasswordStrength";
import { CaptchaInput } from "../shared/components/auth/CaptchaInput";
import { AuthLayout } from "../shared/components/layouts/AuthLayout";
import {
  Eye,
  EyeOff,
  ArrowLeft,
  ArrowRight,
  Building2,
  Store,
  Briefcase,
  Laptop,
  X,
} from "lucide-react";
import { toast } from "sonner";
import { ROUTES } from "@/constants";
import {
  signUp,
  getSkillDomains,
  getSkills,
  type SkillDomain,
  type Skill,
} from "@/features/auth";
import TermsOfService from "@/components/legal/TermsOfService";
import PrivacyPolicy from "@/components/legal/PrivacyPolicy";

interface SignUpPageProps {
  onNavigateToSignIn?: () => void;
  onSignUpSuccess?: () => void;
}

type UserRole = "client_large" | "client_small" | "broker" | "freelancer";

export function SignUpPage({
  onNavigateToSignIn,
  onSignUpSuccess,
}: SignUpPageProps = {}) {
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState(1); // 1: Role Selection, 2: Info Form, 3: Domain (Freelancer/Broker), 4: Skills (Freelancer/Broker)
  const [formData, setFormData] = useState({
    role: "" as UserRole | "",
    fullName: "",
    email: "",
    phoneNumber: "",
    password: "",
    confirmPassword: "",
    acceptTerms: false,
    acceptPrivacy: false,
    recaptchaToken: "",
    domains: [] as string[], // Domain IDs (UUIDs)
    skills: [] as string[], // Skill IDs (UUIDs)
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [showTermsModal, setShowTermsModal] = useState(false);
  const [showPrivacyModal, setShowPrivacyModal] = useState(false);

  // State for domains and skills from API
  const [availableDomains, setAvailableDomains] = useState<SkillDomain[]>([]);
  const [availableSkills, setAvailableSkills] = useState<Skill[]>([]);
  const [loadingDomains, setLoadingDomains] = useState(false);
  const [loadingSkills, setLoadingSkills] = useState(false);

  // Fetch domains when entering step 3
  useEffect(() => {
    if (currentStep === 3 && availableDomains?.length === 0) {
      setLoadingDomains(true);
      getSkillDomains()
        .then((domains) => {
          setAvailableDomains(domains || []);
        })
        .catch((err) => {
          toast.error("Failed to load domains");
          setAvailableDomains([]);
        })
        .finally(() => setLoadingDomains(false));
    }
  }, [currentStep]);

  // Fetch skills when entering step 4
  useEffect(() => {
    if (currentStep === 4 && availableSkills?.length === 0) {
      setLoadingSkills(true);
      const role = formData.role === "freelancer" ? "FREELANCER" : "BROKER";
      getSkills(role)
        .then((skills) => setAvailableSkills(skills || []))
        .catch((err) => {
          toast.error("Failed to load skills");
          setAvailableSkills([]);
        })
        .finally(() => setLoadingSkills(false));
    }
  }, [currentStep, formData.role]);

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateCorporateEmail = (email: string): boolean => {
    const freeEmailProviders = [
      "gmail.com",
      "googlemail.com",
      "yahoo.com",
      "yahoo.co.uk",
      "hotmail.com",
      "outlook.com",
      "live.com",
      "msn.com",
      "icloud.com",
      "me.com",
      "aol.com",
      "mail.com",
      "protonmail.com",
      "proton.me",
      "zoho.com",
      "yandex.com",
      "gmx.com",
      "gmx.net",
      "inbox.com",
      "mail.ru",
    ];

    const domain = email.split("@")[1]?.toLowerCase();
    if (!domain) return false;
    return !freeEmailProviders.includes(domain);
  };

  const validatePhone = (phone: string): boolean => {
    const phoneRegex = /^0[3|5|7|8|9][0-9]{8}$/;
    return phoneRegex.test(phone);
  };

  const passwordRequirements = {
    minLength: formData.password.length >= 8,
    hasLowerCase: /[a-z]/.test(formData.password),
    hasNumber: /[0-9]/.test(formData.password),
    hasSpecial: /[@$!%*?&]/.test(formData.password),
  };

  // Password is valid if it meets minimum length and at least 2 out of 3 character types (medium strength)
  const isPasswordValid =
    passwordRequirements.minLength &&
    [
      passwordRequirements.hasLowerCase,
      passwordRequirements.hasNumber,
      passwordRequirements.hasSpecial,
    ].filter(Boolean).length >= 2;

  // Check if Step 2 (Info Form) is valid
  const isStep2Valid = () => {
    if (!formData.fullName || formData.fullName.length < 2) return false;
    if (!formData.email || !validateEmail(formData.email)) return false;
    if (
      formData.role === "client_large" &&
      !validateCorporateEmail(formData.email)
    )
      return false;
    if (!formData.phoneNumber || !validatePhone(formData.phoneNumber))
      return false;
    if (!formData.password || !isPasswordValid) return false;
    if (
      !formData.confirmPassword ||
      formData.password !== formData.confirmPassword
    )
      return false;
    if (!formData.acceptTerms || !formData.acceptPrivacy) return false;
    if (!formData.recaptchaToken) return false;
    return true;
  };

  // Check if Step 3 (Domain Selection) is valid
  const isStep3Valid = () => {
    return formData.domains.length > 0;
  };

  // Check if Step 4 (Skill Selection) is valid
  const isStep4Valid = () => {
    return formData.skills.length > 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: Record<string, string> = {};

    // Validation
    if (!formData.role) {
      newErrors.role = "Please select your role";
    }

    if (!formData.fullName) {
      newErrors.fullName = "Full name is required";
    } else if (formData.fullName.length < 2) {
      newErrors.fullName = "Full name must be at least 2 characters";
    }

    if (!formData.email) {
      newErrors.email = "Email is required";
    } else if (!validateEmail(formData.email)) {
      newErrors.email = "Invalid email address";
    } else if (
      formData.role === "client_large" &&
      !validateCorporateEmail(formData.email)
    ) {
      newErrors.email =
        "Large SMEs must use a corporate/organization email (not Gmail, Yahoo, Hotmail, etc.)";
    }

    if (!formData.phoneNumber) {
      newErrors.phoneNumber = "Phone number is required";
    } else if (!validatePhone(formData.phoneNumber)) {
      newErrors.phoneNumber =
        "Invalid phone number. Format: 0[3|5|7|8|9]xxxxxxxx";
    }

    if (!formData.password) {
      newErrors.password = "Password is required";
    } else if (!isPasswordValid) {
      newErrors.password = "Password must meet all requirements";
    }

    if (!formData.confirmPassword) {
      newErrors.confirmPassword = "Please confirm your password";
    } else if (formData.password !== formData.confirmPassword) {
      newErrors.confirmPassword = "Passwords do not match";
    }

    if (!formData.acceptTerms) {
      newErrors.acceptTerms = "You must accept the Terms of Service";
    }

    if (!formData.acceptPrivacy) {
      newErrors.acceptPrivacy = "You must accept the Privacy Policy";
    }

    if (!formData.recaptchaToken) {
      newErrors.recaptcha = "Please complete the reCAPTCHA verification";
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    setErrors({});
    setLoading(true);

    try {
      // Map frontend roles to backend roles
      let backendRole;
      if (formData.role === "client_large") {
        backendRole = "CLIENT";
      } else if (formData.role === "client_small") {
        backendRole = "CLIENT_SME";
      } else {
        backendRole = formData.role.toUpperCase();
      }

      await signUp({
        email: formData.email,
        password: formData.password,
        fullName: formData.fullName,
        phoneNumber: formData.phoneNumber,
        role: backendRole as any,
        recaptchaToken: formData.recaptchaToken,
        domainIds: formData.domains.length > 0 ? formData.domains : undefined,
        skillIds: formData.skills.length > 0 ? formData.skills : undefined,
        acceptTerms: formData.acceptTerms,
        acceptPrivacy: formData.acceptPrivacy,
      });

      toast.success(
        "Đăng ký thành công. Vui lòng kiểm tra email để xác thực tài khoản.",
      );

      if (onSignUpSuccess) {
        onSignUpSuccess();
      } else {
        const pendingUrl = `${ROUTES.VERIFY_EMAIL}?email=${encodeURIComponent(formData.email)}`;
        navigate(pendingUrl);
      }
    } catch (error: any) {
      // Handle error message (could be string, array, or object)
      let errorMessage = "Failed to create account. Please try again.";

      if (error.response?.data?.message) {
        const msg = error.response.data.message;
        if (typeof msg === "string") {
          errorMessage = msg;
        } else if (Array.isArray(msg)) {
          errorMessage = msg.join(", ");
        } else if (typeof msg === "object") {
          errorMessage = JSON.stringify(msg);
        }
      }

      // Check if error is related to duplicate email
      if (
        typeof errorMessage === "string" &&
        errorMessage.toLowerCase().includes("email")
      ) {
        setErrors({ email: errorMessage });
      } else if (
        typeof errorMessage === "string" &&
        (errorMessage.toLowerCase().includes("captcha") ||
          errorMessage.toLowerCase().includes("recaptcha"))
      ) {
        setErrors({ recaptcha: errorMessage });
      } else if (
        typeof errorMessage === "string" &&
        errorMessage.toLowerCase().includes("terms")
      ) {
        setErrors({ acceptTerms: errorMessage });
      } else if (
        typeof errorMessage === "string" &&
        errorMessage.toLowerCase().includes("privacy")
      ) {
        setErrors({ acceptPrivacy: errorMessage });
      } else {
        setErrors({ acceptTerms: errorMessage });
      }

      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field: string, value: string | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => ({ ...prev, [field]: "" }));
    }
  };

  const getRoleLabel = (role: UserRole) => {
    switch (role) {
      case "client_large":
        return "Business Owner (Large SME)";
      case "client_small":
        return "Business Owner (Small SME/Individual)";
      case "broker":
        return "Broker (Project Consultant)";
      case "freelancer":
        return "Freelancer (Developer)";
    }
  };

  const getRoleDescription = (role: UserRole) => {
    switch (role) {
      case "client_large":
        return "I need software solutions for my established business (requires corporate email)";
      case "client_small":
        return "I need software solutions for my small business or personal project";
      case "broker":
        return "I help translate business needs into technical requirements";
      case "freelancer":
        return "I build software and deliver projects";
    }
  };

  const getRoleIcon = (role: UserRole) => {
    switch (role) {
      case "client_large":
        return Building2;
      case "client_small":
        return Store;
      case "broker":
        return Briefcase;
      case "freelancer":
        return Laptop;
    }
  };
  const handleRoleSelect = (role: UserRole) => {
    handleChange("role", role);
    // Auto-advance to next step after selecting role
    setTimeout(() => {
      setCurrentStep(2);
    }, 300);
  };

  const handleInfoFormNext = () => {
    // Validation for step 2
    const newErrors: Record<string, string> = {};

    if (!formData.fullName) newErrors.fullName = "Full name is required";

    if (!formData.email) {
      newErrors.email = "Email is required";
    } else if (!validateEmail(formData.email)) {
      newErrors.email = "Invalid email address";
    } else if (
      formData.role === "client_large" &&
      !validateCorporateEmail(formData.email)
    ) {
      newErrors.email =
        "Large SMEs must use a corporate/organization email (not Gmail, Yahoo, Hotmail, etc.)";
    }

    if (!formData.phoneNumber) {
      newErrors.phoneNumber = "Phone number is required";
    } else if (!validatePhone(formData.phoneNumber)) {
      newErrors.phoneNumber =
        "Invalid phone number. Format: 0[3|5|7|8|9]xxxxxxxx";
    }

    if (!formData.password) {
      newErrors.password = "Password is required";
    } else if (!isPasswordValid) {
      newErrors.password =
        "Password must be at least 8 characters with 2 of: lowercase, number, special character";
    }

    if (!formData.confirmPassword) {
      newErrors.confirmPassword = "Confirm password is required";
    } else if (formData.password !== formData.confirmPassword) {
      newErrors.confirmPassword = "Passwords do not match";
    }

    if (!formData.acceptTerms)
      newErrors.acceptTerms = "You must accept Terms of Service";
    if (!formData.acceptPrivacy)
      newErrors.acceptPrivacy = "You must accept Privacy Policy";
    if (!formData.recaptchaToken) newErrors.recaptcha = "Complete reCAPTCHA";

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    // If Freelancer or Broker → go to Domain selection (Step 3)
    if (formData.role === "freelancer" || formData.role === "broker") {
      setCurrentStep(3);
    } else {
      // Client roles → submit immediately
      handleSubmit(new Event("submit") as any);
    }
  };

  const handleDomainNext = () => {
    if (formData.domains.length === 0) {
      setErrors({ domains: "Please select at least one domain" });
      return;
    }
    setCurrentStep(4); // Go to Skills selection
  };

  const handleSkillsNext = () => {
    if (formData.skills.length === 0) {
      setErrors({ skills: "Please select at least one skill" });
      return;
    }
    // All steps completed → submit
    handleSubmit(new Event("submit") as any);
  };

  const toggleDomain = (domain: string) => {
    setFormData((prev) => ({
      ...prev,
      domains: prev.domains.includes(domain)
        ? prev.domains.filter((d) => d !== domain)
        : [...prev.domains, domain],
    }));
    if (errors.domains) setErrors((prev) => ({ ...prev, domains: "" }));
  };

  const toggleSkill = (skill: string) => {
    setFormData((prev) => ({
      ...prev,
      skills: prev.skills.includes(skill)
        ? prev.skills.filter((s) => s !== skill)
        : [...prev.skills, skill],
    }));
    if (errors.skills) setErrors((prev) => ({ ...prev, skills: "" }));
  };

  const handleBackToRoleSelection = () => {
    setCurrentStep(1);
  };

  // Animation variants
  const slideVariants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 300 : -300,
      opacity: 0,
    }),
    center: {
      x: 0,
      opacity: 1,
    },
    exit: (direction: number) => ({
      x: direction > 0 ? -300 : 300,
      opacity: 0,
    }),
  };

  const getStepTitle = () => {
    if (currentStep === 1) return "Choose Your Role";
    if (currentStep === 2) return "Complete Your Profile";
    if (currentStep === 3) return "Select Your Domains";
    if (currentStep === 4) return "Choose Your Skills";
    return "Sign Up";
  };

  const getStepSubtitle = () => {
    if (currentStep === 1) return "Tell us what brings you to our platform";
    if (currentStep === 2)
      return `You're signing up as ${formData.role ? getRoleLabel(formData.role) : "a user"}`;
    if (currentStep === 3) return "What industries/areas do you specialize in?";
    if (currentStep === 4) return "What technologies/skills do you work with?";
    return "";
  };

  const totalSteps =
    formData.role === "freelancer" || formData.role === "broker" ? 4 : 2;

  return (
    <AuthLayout title={getStepTitle()} subtitle={getStepSubtitle()}>
      {/* Progress Indicator */}
      <div style={{ marginBottom: "2rem" }}>
        {/* Progress bars */}
        <div style={{ display: "flex", gap: "0.5rem", marginBottom: "1rem" }}>
          {[...Array(totalSteps)].map((_, idx) => (
            <div
              key={idx}
              style={{
                flex: 1,
                height: "4px",
                borderRadius: "2px",
                backgroundColor:
                  currentStep > idx ? "#14b8a6" : "var(--auth-border)",
                transition: "background-color 0.3s ease",
              }}
            />
          ))}
        </div>

        {/* Step labels with numbers */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns:
              totalSteps === 4 ? "repeat(4, 1fr)" : "repeat(2, 1fr)",
            gap: "0.5rem",
          }}
        >
          {/* Step 1 */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: "0.25rem",
            }}
          >
            <div
              style={{
                width: "28px",
                height: "28px",
                borderRadius: "50%",
                backgroundColor:
                  currentStep === 1
                    ? "#14b8a6"
                    : currentStep > 1
                      ? "#14b8a6"
                      : "var(--auth-border)",
                color: currentStep >= 1 ? "white" : "var(--auth-text-muted)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: "0.75rem",
                fontWeight: 600,
                transition: "all 0.3s ease",
              }}
            >
              {currentStep > 1 ? "✓" : "1"}
            </div>
            <span
              style={{
                fontSize: "0.75rem",
                fontWeight: currentStep === 1 ? 600 : 400,
                color: currentStep === 1 ? "#14b8a6" : "var(--auth-text-muted)",
                textAlign: "center",
                transition: "all 0.3s ease",
              }}
            >
              Role
            </span>
          </div>

          {/* Step 2 */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: "0.25rem",
            }}
          >
            <div
              style={{
                width: "28px",
                height: "28px",
                borderRadius: "50%",
                backgroundColor:
                  currentStep === 2
                    ? "#14b8a6"
                    : currentStep > 2
                      ? "#14b8a6"
                      : "var(--auth-border)",
                color: currentStep >= 2 ? "white" : "var(--auth-text-muted)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: "0.75rem",
                fontWeight: 600,
                transition: "all 0.3s ease",
              }}
            >
              {currentStep > 2 ? "✓" : "2"}
            </div>
            <span
              style={{
                fontSize: "0.75rem",
                fontWeight: currentStep === 2 ? 600 : 400,
                color: currentStep === 2 ? "#14b8a6" : "var(--auth-text-muted)",
                textAlign: "center",
                transition: "all 0.3s ease",
              }}
            >
              Details
            </span>
          </div>

          {/* Step 3 (only for Freelancer/Broker) */}
          {totalSteps === 4 && (
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: "0.25rem",
              }}
            >
              <div
                style={{
                  width: "28px",
                  height: "28px",
                  borderRadius: "50%",
                  backgroundColor:
                    currentStep === 3
                      ? "#14b8a6"
                      : currentStep > 3
                        ? "#14b8a6"
                        : "var(--auth-border)",
                  color: currentStep >= 3 ? "white" : "var(--auth-text-muted)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: "0.75rem",
                  fontWeight: 600,
                  transition: "all 0.3s ease",
                }}
              >
                {currentStep > 3 ? "✓" : "3"}
              </div>
              <span
                style={{
                  fontSize: "0.75rem",
                  fontWeight: currentStep === 3 ? 600 : 400,
                  color:
                    currentStep === 3 ? "#14b8a6" : "var(--auth-text-muted)",
                  textAlign: "center",
                  transition: "all 0.3s ease",
                }}
              >
                Domains
              </span>
            </div>
          )}

          {/* Step 4 (only for Freelancer/Broker) */}
          {totalSteps === 4 && (
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: "0.25rem",
              }}
            >
              <div
                style={{
                  width: "28px",
                  height: "28px",
                  borderRadius: "50%",
                  backgroundColor:
                    currentStep === 4 ? "#14b8a6" : "var(--auth-border)",
                  color: currentStep === 4 ? "white" : "var(--auth-text-muted)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: "0.75rem",
                  fontWeight: 600,
                  transition: "all 0.3s ease",
                }}
              >
                4
              </div>
              <span
                style={{
                  fontSize: "0.75rem",
                  fontWeight: currentStep === 4 ? 600 : 400,
                  color:
                    currentStep === 4 ? "#14b8a6" : "var(--auth-text-muted)",
                  textAlign: "center",
                  transition: "all 0.3s ease",
                }}
              >
                Skills
              </span>
            </div>
          )}
        </div>
      </div>

      <form
        onSubmit={(e) => {
          e.preventDefault();
        }}
        className="space-y-6"
      >
        <AnimatePresence mode="wait" custom={currentStep}>
          {currentStep === 1 && (
            <motion.div
              key="step1"
              custom={1}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              transition={{
                x: { type: "spring", stiffness: 300, damping: 30 },
                opacity: { duration: 0.2 },
              }}
            >
              {/* Role Selection */}
              <div>
                <label
                  htmlFor="role"
                  style={{
                    display: "block",
                    marginBottom: "0.5rem",
                    fontSize: "0.875rem",
                    fontWeight: 500,
                    color: "var(--auth-text)",
                  }}
                >
                  I am a...{" "}
                  <span style={{ color: "var(--auth-error)" }}>*</span>
                </label>
                <div className="space-y-3">
                  {(
                    [
                      "client_large",
                      "client_small",
                      "broker",
                      "freelancer",
                    ] as UserRole[]
                  ).map((role) => (
                    <motion.button
                      key={role}
                      type="button"
                      onClick={() => handleRoleSelect(role)}
                      whileHover={{ scale: 1.02 }}
                      whileTap={{ scale: 0.98 }}
                      style={{
                        width: "100%",
                        padding: "1rem",
                        borderRadius: "8px",
                        border: `2px solid ${formData.role === role ? "var(--auth-primary)" : "var(--auth-border)"}`,
                        backgroundColor:
                          formData.role === role
                            ? "rgba(37, 99, 235, 0.05)"
                            : "var(--auth-input-bg)",
                        textAlign: "left",
                        cursor: "pointer",
                        transition: "all 0.2s ease",
                      }}
                      onMouseEnter={(e) => {
                        if (formData.role !== role) {
                          e.currentTarget.style.borderColor =
                            "var(--auth-primary)";
                          e.currentTarget.style.backgroundColor =
                            "rgba(37, 99, 235, 0.02)";
                        }
                      }}
                      onMouseLeave={(e) => {
                        if (formData.role !== role) {
                          e.currentTarget.style.borderColor =
                            "var(--auth-border)";
                          e.currentTarget.style.backgroundColor =
                            "var(--auth-input-bg)";
                        }
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: "0.75rem",
                        }}
                      >
                        <div
                          style={{
                            width: "48px",
                            height: "48px",
                            borderRadius: "12px",
                            backgroundColor:
                              formData.role === role
                                ? "var(--auth-primary)"
                                : "rgba(37, 99, 235, 0.1)",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            flexShrink: 0,
                            transition: "all 0.2s ease",
                          }}
                        >
                          {React.createElement(getRoleIcon(role), {
                            className: "w-6 h-6",
                            style: {
                              color:
                                formData.role === role
                                  ? "white"
                                  : "var(--auth-primary)",
                            },
                          })}
                        </div>
                        <div style={{ flex: 1 }}>
                          <div
                            style={{
                              fontWeight: 600,
                              color: "var(--auth-text)",
                              marginBottom: "0.25rem",
                            }}
                          >
                            {getRoleLabel(role)}
                          </div>
                          <div
                            style={{
                              fontSize: "0.875rem",
                              color: "var(--auth-text-muted)",
                            }}
                          >
                            {getRoleDescription(role)}
                          </div>
                        </div>
                        <ArrowRight
                          className="w-5 h-5"
                          style={{
                            color: "var(--auth-text-muted)",
                            opacity: formData.role === role ? 1 : 0.3,
                          }}
                        />
                      </div>
                    </motion.button>
                  ))}
                </div>
                {errors.role && (
                  <p
                    style={{
                      color: "var(--auth-error)",
                      fontSize: "0.875rem",
                      marginTop: "0.5rem",
                    }}
                  >
                    {errors.role}
                  </p>
                )}
              </div>

              <p
                className="text-center"
                style={{
                  color: "var(--auth-text-muted)",
                  fontSize: "0.875rem",
                  marginTop: "2rem",
                }}
              >
                Already have an account?{" "}
                <button
                  type="button"
                  onClick={() =>
                    onNavigateToSignIn
                      ? onNavigateToSignIn()
                      : navigate(ROUTES.LOGIN)
                  }
                  className="hover:underline"
                  style={{ color: "var(--auth-primary)", fontWeight: 500 }}
                >
                  Sign in
                </button>
              </p>
            </motion.div>
          )}

          {currentStep === 2 && (
            <motion.div
              key="step2"
              custom={2}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              transition={{
                x: { type: "spring", stiffness: 300, damping: 30 },
                opacity: { duration: 0.2 },
              }}
            >
              {/* Back Button */}
              <button
                type="button"
                onClick={handleBackToRoleSelection}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "0.5rem",
                  marginBottom: "1.5rem",
                  color: "var(--auth-primary)",
                  fontSize: "0.875rem",
                  fontWeight: 500,
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  padding: "0.5rem 0",
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.textDecoration = "underline")
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.textDecoration = "none")
                }
              >
                <ArrowLeft className="w-4 h-4" />
                Change role
              </button>

              <Input
                id="fullName"
                label="Full Name"
                type="text"
                placeholder="Enter your full name"
                value={formData.fullName}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  handleChange("fullName", e.target.value)
                }
                error={errors.fullName}
                required
              />

              <Input
                id="email"
                label="Email"
                type="email"
                placeholder={
                  formData.role === "client_large"
                    ? "company@yourbusiness.com"
                    : "Enter your email"
                }
                value={formData.email}
                onChange={(e) => handleChange("email", e.target.value)}
                error={errors.email}
                helperText={
                  formData.role === "client_large"
                    ? "Use your company/university email (e.g., name@company.com, student@university.edu)"
                    : undefined
                }
                required
              />

              <Input
                id="phoneNumber"
                label="Phone Number"
                type="tel"
                placeholder="0987654321"
                value={formData.phoneNumber}
                onChange={(e) => handleChange("phoneNumber", e.target.value)}
                error={errors.phoneNumber}
                required
              />

              <div>
                <div className="relative">
                  <Input
                    id="password"
                    label="Password"
                    type={showPassword ? "text" : "password"}
                    autoComplete="new-password"
                    placeholder="At least 8 characters with lowercase, number & special char"
                    value={formData.password}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                      handleChange("password", e.target.value)
                    }
                    error={errors.password}
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-11"
                    tabIndex={-1}
                  >
                    {showPassword ? (
                      <EyeOff
                        className="w-5 h-5"
                        style={{ color: "var(--auth-text-muted)" }}
                      />
                    ) : (
                      <Eye
                        className="w-5 h-5"
                        style={{ color: "var(--auth-text-muted)" }}
                      />
                    )}
                  </button>
                </div>
                <PasswordStrength password={formData.password} />
              </div>

              <div className="relative">
                <Input
                  id="confirmPassword"
                  label="Confirm password"
                  type={showConfirmPassword ? "text" : "password"}
                  autoComplete="new-password"
                  placeholder="Re-enter your password"
                  value={formData.confirmPassword}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    handleChange("confirmPassword", e.target.value)
                  }
                  error={errors.confirmPassword}
                  success={
                    !!(
                      formData.confirmPassword &&
                      formData.password === formData.confirmPassword &&
                      formData.confirmPassword.length >= 8
                    )
                  }
                />
                <button
                  type="button"
                  onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  className="absolute right-3 top-11"
                  tabIndex={-1}
                >
                  {showConfirmPassword ? (
                    <EyeOff
                      className="w-5 h-5"
                      style={{ color: "var(--auth-text-muted)" }}
                    />
                  ) : (
                    <Eye
                      className="w-5 h-5"
                      style={{ color: "var(--auth-text-muted)" }}
                    />
                  )}
                </button>
              </div>

              {/* CAPTCHA Input */}
              <CaptchaInput
                onChange={(token) =>
                  handleChange("recaptchaToken", token || "")
                }
                error={errors.recaptcha}
              />

              <div style={{ marginBottom: "1.2rem" }}>
                <label className="flex items-start gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={formData.acceptTerms && formData.acceptPrivacy}
                    onChange={(e) => {
                      const checked = e.target.checked;
                      handleChange("acceptTerms", checked);
                      handleChange("acceptPrivacy", checked);
                    }}
                    className="w-4 h-4 mt-0.5 rounded cursor-pointer"
                    style={{
                      accentColor: "#14b8a6",
                    }}
                  />
                  <span
                    style={{ color: "var(--auth-text)", fontSize: "0.875rem" }}
                  >
                    I accept the{" "}
                    <button
                      type="button"
                      onClick={(e) => {
                        e.preventDefault();
                        setShowTermsModal(true);
                      }}
                      className="hover:underline font-medium"
                      style={{ color: "#14b8a6" }}
                    >
                      Terms of Service
                    </button>
                    {" and "}
                    <button
                      type="button"
                      onClick={(e) => {
                        e.preventDefault();
                        setShowPrivacyModal(true);
                      }}
                      className="hover:underline font-medium"
                      style={{ color: "#14b8a6" }}
                    >
                      Privacy Policy
                    </button>
                  </span>
                </label>
                {(errors.acceptTerms || errors.acceptPrivacy) && (
                  <p
                    className="mt-1.5 text-sm"
                    style={{ color: "var(--auth-error)" }}
                  >
                    {errors.acceptTerms || errors.acceptPrivacy}
                  </p>
                )}
              </div>

              <Button
                type="button"
                onClick={handleInfoFormNext}
                variant="primary"
                className="w-full py-3 text-base font-medium justify-center"
                disabled={loading || !isStep2Valid()}
              >
                {formData.role === "freelancer" || formData.role === "broker"
                  ? "Next"
                  : loading
                    ? "Creating account..."
                    : "Create Account"}
              </Button>

              <p
                className="text-center"
                style={{
                  color: "var(--auth-text-muted)",
                  fontSize: "0.875rem",
                }}
              >
                Already have an account?{" "}
                <button
                  type="button"
                  onClick={() =>
                    onNavigateToSignIn
                      ? onNavigateToSignIn()
                      : navigate(ROUTES.LOGIN)
                  }
                  className="hover:underline"
                  style={{ color: "var(--auth-primary)", fontWeight: 500 }}
                >
                  Sign in
                </button>
              </p>
            </motion.div>
          )}

          {/* STEP 3: Domain Selection (Freelancer/Broker only) */}
          {currentStep === 3 && (
            <motion.div
              key="step3"
              custom={3}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              transition={{
                x: { type: "spring", stiffness: 300, damping: 30 },
                opacity: { duration: 0.2 },
              }}
            >
              <button
                type="button"
                onClick={() => setCurrentStep(2)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "0.5rem",
                  marginBottom: "1.5rem",
                  color: "var(--auth-primary)",
                  fontSize: "0.875rem",
                  fontWeight: 500,
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  padding: "0.5rem 0",
                }}
              >
                <ArrowLeft className="w-4 h-4" />
                Back to profile
              </button>

              <div className="space-y-4">
                <label
                  style={{
                    display: "block",
                    fontSize: "0.875rem",
                    fontWeight: 600,
                    color: "var(--auth-text)",
                    marginBottom: "1rem",
                  }}
                >
                  Select domains you work in (choose at least 1)
                </label>
                {loadingDomains ? (
                  <div
                    style={{
                      textAlign: "center",
                      padding: "2rem",
                      color: "var(--auth-text-muted)",
                    }}
                  >
                    Loading domains...
                  </div>
                ) : availableDomains && availableDomains.length > 0 ? (
                  <div
                    style={{
                      display: "grid",
                      gridTemplateColumns: "repeat(2, 1fr)",
                      gap: "0.75rem",
                    }}
                  >
                    {availableDomains.map((domain) => (
                      <button
                        key={domain.id}
                        type="button"
                        onClick={() => toggleDomain(domain.id)}
                        style={{
                          padding: "1rem",
                          border: `2px solid ${formData.domains.includes(domain.id) ? "var(--auth-primary)" : "var(--auth-border)"}`,
                          borderRadius: "12px",
                          backgroundColor: formData.domains.includes(domain.id)
                            ? "rgba(37, 99, 235, 0.05)"
                            : "var(--auth-input-bg)",
                          textAlign: "left",
                          cursor: "pointer",
                          transition: "all 0.2s ease",
                        }}
                      >
                        {domain.icon && (
                          <div
                            style={{
                              fontSize: "1.5rem",
                              marginBottom: "0.5rem",
                            }}
                          >
                            {domain.icon}
                          </div>
                        )}
                        <div
                          style={{
                            fontWeight: 600,
                            color: "var(--auth-text)",
                            fontSize: "0.875rem",
                          }}
                        >
                          {domain.name}
                        </div>
                        {domain.description && (
                          <div
                            style={{
                              fontSize: "0.75rem",
                              color: "var(--auth-text-muted)",
                              marginTop: "0.25rem",
                            }}
                          >
                            {domain.description}
                          </div>
                        )}
                      </button>
                    ))}
                  </div>
                ) : (
                  <div
                    style={{
                      textAlign: "center",
                      padding: "2rem",
                      color: "var(--auth-error)",
                    }}
                  >
                    <p>No domains available. Please contact administrator.</p>
                    <p
                      style={{
                        fontSize: "0.75rem",
                        marginTop: "0.5rem",
                        color: "var(--auth-text-muted)",
                      }}
                    >
                      Database may need to be seeded with domain data.
                    </p>
                  </div>
                )}
                {errors.domains && (
                  <p
                    style={{
                      color: "var(--auth-error)",
                      fontSize: "0.875rem",
                      marginTop: "0.5rem",
                    }}
                  >
                    {errors.domains}
                  </p>
                )}
              </div>

              <Button
                type="button"
                onClick={handleDomainNext}
                variant="primary"
                className="w-full py-3 text-base font-medium justify-center mt-6"
                disabled={!isStep3Valid()}
              >
                Next
              </Button>
            </motion.div>
          )}

          {/* STEP 4: Skills Selection (Freelancer/Broker only) */}
          {currentStep === 4 && (
            <motion.div
              key="step4"
              custom={4}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              transition={{
                x: { type: "spring", stiffness: 300, damping: 30 },
                opacity: { duration: 0.2 },
              }}
            >
              <button
                type="button"
                onClick={() => setCurrentStep(3)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "0.5rem",
                  marginBottom: "1.5rem",
                  color: "var(--auth-primary)",
                  fontSize: "0.875rem",
                  fontWeight: 500,
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  padding: "0.5rem 0",
                }}
              >
                <ArrowLeft className="w-4 h-4" />
                Back to domains
              </button>

              <div className="space-y-4">
                <label
                  style={{
                    display: "block",
                    fontSize: "0.875rem",
                    fontWeight: 600,
                    color: "var(--auth-text)",
                    marginBottom: "1rem",
                  }}
                >
                  Select your skills/technologies (choose at least 1)
                </label>
                {loadingSkills ? (
                  <div
                    style={{
                      textAlign: "center",
                      padding: "2rem",
                      color: "var(--auth-text-muted)",
                    }}
                  >
                    Loading skills...
                  </div>
                ) : (
                  <div
                    style={{ display: "flex", flexWrap: "wrap", gap: "0.5rem" }}
                  >
                    {availableSkills.map((skill) => (
                      <button
                        key={skill.id}
                        type="button"
                        onClick={() => toggleSkill(skill.id)}
                        style={{
                          padding: "0.5rem 1rem",
                          border: `2px solid ${formData.skills.includes(skill.id) ? "var(--auth-primary)" : "var(--auth-border)"}`,
                          borderRadius: "20px",
                          backgroundColor: formData.skills.includes(skill.id)
                            ? "var(--auth-primary)"
                            : "transparent",
                          color: formData.skills.includes(skill.id)
                            ? "white"
                            : "var(--auth-text)",
                          fontSize: "0.875rem",
                          fontWeight: 500,
                          cursor: "pointer",
                          transition: "all 0.2s ease",
                        }}
                      >
                        {skill.name}
                      </button>
                    ))}
                  </div>
                )}
                {errors.skills && (
                  <p
                    style={{
                      color: "var(--auth-error)",
                      fontSize: "0.875rem",
                      marginTop: "0.5rem",
                    }}
                  >
                    {errors.skills}
                  </p>
                )}
              </div>

              <Button
                type="button"
                onClick={handleSkillsNext}
                variant="primary"
                className="w-full py-3 text-base font-medium justify-center mt-6"
                disabled={loading || !isStep4Valid()}
              >
                {loading ? "Creating account..." : "Create Account"}
              </Button>
            </motion.div>
          )}
        </AnimatePresence>
      </form>

      {/* Terms of Service Modal */}
      {showTermsModal && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4"
          onClick={() => setShowTermsModal(false)}
        >
          <div
            className="bg-white rounded-lg max-w-4xl max-h-[90vh] overflow-y-auto relative"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => setShowTermsModal(false)}
              className="sticky top-4 right-4 float-right bg-gray-100 hover:bg-gray-200 rounded-full p-2 transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
            <TermsOfService />
          </div>
        </div>
      )}

      {/* Privacy Policy Modal */}
      {showPrivacyModal && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4"
          onClick={() => setShowPrivacyModal(false)}
        >
          <div
            className="bg-white rounded-lg max-w-4xl max-h-[90vh] overflow-y-auto relative"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => setShowPrivacyModal(false)}
              className="sticky top-4 right-4 float-right bg-gray-100 hover:bg-gray-200 rounded-full p-2 transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
            <PrivacyPolicy />
          </div>
        </div>
      )}
    </AuthLayout>
  );
}

export default SignUpPage;

import { useState, useEffect } from 'react';
import { AlertTriangle, X, Eye, EyeOff, Loader2, Shield, CheckCircle2, XCircle, ArrowLeft, Trash2 } from 'lucide-react';
import { toast } from 'sonner';
import { checkObligations, deleteAccount } from '@/features/auth/api';
import { STORAGE_KEYS, ROUTES } from '@/constants';
import { useNavigate } from 'react-router-dom';
import { removeStoredItem } from '@/shared/utils/storage';

interface DeleteAccountModalProps {
  isOpen: boolean;
  onClose: () => void;
  userEmail: string;
}

export function DeleteAccountModal({ isOpen, onClose, userEmail }: DeleteAccountModalProps) {
  const navigate = useNavigate();
  const [step, setStep] = useState<'warning' | 'confirm'>('warning');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [checking, setChecking] = useState(false);
  const [obligations, setObligations] = useState<{
    hasObligations: boolean;
    activeProjects: number;
    walletBalance: number;
  } | null>(null);

  useEffect(() => {
    if (isOpen) {
      // Reset state when modal opens
      setStep('warning');
      setPassword('');
      setShowPassword(false);
      setObligations(null);
      
      // Check for obligations when modal opens
      checkUserObligations();
    }
  }, [isOpen]);

  const checkUserObligations = async () => {
    try {
      setChecking(true);
      const result = await checkObligations();
      setObligations(result);
    } catch (error: any) {
      toast.error('Failed to check account obligations');
    } finally {
      setChecking(false);
    }
  };

  const handleProceedToConfirm = () => {
    if (obligations?.hasObligations) {
      toast.error('Please complete active projects and withdraw balance before deleting account');
      return;
    }
    setStep('confirm');
  };

  const handleDeleteAccount = async () => {
    if (!password.trim()) {
      toast.error('Please enter your password');
      return;
    }

    try {
      setLoading(true);
      await deleteAccount(password);

      // Clear local/session storage user snapshot
      removeStoredItem(STORAGE_KEYS.USER);
      window.dispatchEvent(new Event("userDataUpdated"));
      
      toast.success('Account has been deleted successfully');
      
      // Redirect to landing page
      navigate(ROUTES.LANDING, { replace: true });
    } catch (error: any) {
      console.error('Failed to delete account:', error);
      const errorMessage = error.response?.data?.message || 'Failed to delete account. Please try again.';
      toast.error(errorMessage);
