import React, { useRef, useState, useEffect } from 'react';

interface OTPInputProps {
  length?: number;
  value: string;
  onChange: (value: string) => void;
  error?: boolean;
}

export function OTPInput({ length = 6, value, onChange, error }: OTPInputProps) {
  const [otp, setOtp] = useState<string[]>(Array(length).fill(''));
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  useEffect(() => {
    const otpArray = value.split('').slice(0, length);
    setOtp([...otpArray, ...Array(length - otpArray.length).fill('')]);
  }, [value, length]);

  const handleChange = (index: number, digit: string) => {
    if (!/^\d*$/.test(digit)) return;

    const newOtp = [...otp];
    newOtp[index] = digit.slice(-1);
    setOtp(newOtp);
    onChange(newOtp.join(''));

    if (digit && index < length - 1) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    } else if (e.key === 'ArrowLeft' && index > 0) {
      inputRefs.current[index - 1]?.focus();
    } else if (e.key === 'ArrowRight' && index < length - 1) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    e.preventDefault();
    const pastedData = e.clipboardData.getData('text').replace(/\D/g, '');
    const newOtp = pastedData.split('').slice(0, length);
    const filledOtp = [...newOtp, ...Array(length - newOtp.length).fill('')];
    setOtp(filledOtp);
    onChange(newOtp.join(''));
    
    const nextIndex = Math.min(newOtp.length, length - 1);
    inputRefs.current[nextIndex]?.focus();
  };

  return (
    <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'center' }}>
      {otp.map((digit, index) => (
        <input
          key={index}
          ref={(el: HTMLInputElement | null) => { inputRefs.current[index] = el; }}
          type="text"
          inputMode="numeric"
          maxLength={1}
          value={digit}
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => handleChange(index, e.target.value)}
          onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => handleKeyDown(index, e)}
          onPaste={handlePaste}
          style={{
            width: '3rem',
            height: '3.5rem',
            textAlign: 'center',
            fontSize: '1.5rem',
            fontWeight: 600,
            borderRadius: '8px',
            border: `2px solid ${error ? 'var(--auth-error)' : digit ? 'var(--auth-primary)' : 'var(--auth-border)'}`,
            backgroundColor: 'var(--auth-input-bg)',
            color: 'var(--auth-text)',
            outline: 'none',
            transition: 'all 0.2s ease',
          }}
          onFocus={(e: React.FocusEvent<HTMLInputElement>) => {
            e.target.style.borderColor = error ? 'var(--auth-error)' : 'var(--auth-primary)';
            e.target.style.boxShadow = error 
              ? '0 0 0 3px rgba(239, 68, 68, 0.1)'
              : '0 0 0 3px rgba(37, 99, 235, 0.1)';
          }}
          onBlur={(e: React.FocusEvent<HTMLInputElement>) => {
            e.target.style.borderColor = error ? 'var(--auth-error)' : digit ? 'var(--auth-primary)' : 'var(--auth-border)';
            e.target.style.boxShadow = 'none';
          }}
        />
      ))}
    </div>
  );
}

﻿import { useNavigate } from 'react-router-dom';
import { ShieldX, ArrowRight, Clock, AlertTriangle } from 'lucide-react';
import { Button } from '@/shared/components/custom/Button';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/Card';
import { ROUTES } from '@/constants';

interface KYCBlockerProps {
  kycStatus: string | null;
  role: 'client' | 'freelancer' | 'broker';
  action: string; // e.g., "create project requests", "apply to projects", "accept invitations"
}

/**
 * KYC Blocker Component
 * Shows a full-page block when user hasn't completed KYC verification
 */
export function KYCBlocker({ kycStatus, role, action }: KYCBlockerProps) {
  const navigate = useNavigate();

  const getKycStatusRoute = () => {
    switch (role) {
      case 'client':
        return ROUTES.CLIENT_KYC_STATUS || '/client/kyc-status';
      case 'freelancer':
        return ROUTES.FREELANCER_KYC_STATUS || '/freelancer/kyc-status';
      case 'broker':
        return ROUTES.BROKER_KYC_STATUS || '/broker/kyc-status';
      default:
        return '/kyc';
    }
  };

  const isPending = kycStatus === 'PENDING';
  const isRejected = kycStatus === 'REJECTED';

  return (
    <div className="min-h-[60vh] flex items-center justify-center p-4">
      <Card className="max-w-md w-full border-2 border-slate-200">
        <CardHeader className={`text-center pb-4 ${isPending ? 'bg-yellow-50' : 'bg-slate-50'}`}>
          <div className={`mx-auto w-16 h-16 rounded-full flex items-center justify-center mb-4 ${
            isPending ? 'bg-yellow-100' : isRejected ? 'bg-red-100' : 'bg-slate-100'
          }`}>
            {isPending ? (
              <Clock className="w-8 h-8 text-yellow-600" />
            ) : isRejected ? (
              <AlertTriangle className="w-8 h-8 text-red-600" />
            ) : (
              <ShieldX className="w-8 h-8 text-slate-600" />
            )}
          </div>
          <CardTitle className={`text-xl ${
            isPending ? 'text-yellow-800' : isRejected ? 'text-red-800' : 'text-slate-800'
          }`}>
            {isPending
              ? 'KYC Verification Pending'
              : isRejected
              ? 'KYC Verification Failed'
              : 'KYC Verification Required'}
          </CardTitle>
        </CardHeader>
        <CardContent className="pt-6 text-center space-y-4">
          <p className="text-muted-foreground">
            {isPending ? (
              <>
                Your identity verification is being reviewed. Please wait for approval before you can <strong>{action}</strong>.
                This usually takes 1-2 business days.
              </>
            ) : isRejected ? (
              <>
                Your KYC verification was not successful. Please resubmit your documents to <strong>{action}</strong>.
              </>
            ) : (
              <>
                To <strong>{action}</strong>, you need to verify your identity first.
                This helps us maintain a secure and trusted platform.
              </>
            )}
          </p>

          <div className="space-y-3 pt-4">
            {!isPending && (
              <Button
                onClick={() => navigate(ROUTES.KYC_VERIFICATION || '/kyc')}
                className="w-full"
              >
                {isRejected ? 'Resubmit Verification' : 'Start Verification'}
                <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            )}
            
            <Button
              variant="outline"
              onClick={() => navigate(getKycStatusRoute())}
              className="w-full"
            >
              {isPending ? 'Check Status' : 'View KYC Status'}
            </Button>
          </div>

          {isPending && (
            <p className="text-sm text-yellow-700 bg-yellow-50 rounded-lg p-3 mt-4">
              庁 <strong>Tip:</strong> You'll be notified once your verification is complete.
            </p>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

/**
 * Hook to check KYC status
 */
export function useKYCStatus() {
  const baseUrl = import.meta.env.VITE_API_URL || 'http://localhost:3000';

  const checkKycStatus = async (): Promise<string> => {
    try {
      const response = await fetch(`${baseUrl}/kyc/me`, {
        credentials: 'include',
      });
      
      // Handle non-200 responses (401, 403, 500, etc.)
      if (!response.ok) {
        return 'NOT_STARTED';
      }
      
      const data = await response.json();
      // Server returns 'NOT_STARTED' when no KYC exists
      return data.status || 'NOT_STARTED';
    } catch (error) {
      console.error('Error checking KYC status:', error);
      return 'NOT_STARTED';
    }
  };

  return { checkKycStatus };
}

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "../ui/dropdown-menu";
import { Avatar, AvatarFallback, AvatarImage } from "../ui/avatar";
import { LogOut, User, Settings } from "lucide-react";
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { ROUTES, STORAGE_KEYS } from "@/constants";
import { getStoredJson, removeStoredItem } from "@/shared/utils/storage";
import { signOut } from "@/features/auth";

export function UserNav() {
  const navigate = useNavigate();
  const [user, setUser] = useState<{
    name: string;
    email: string;
    initials: string;
    role?: string;
  }>({
    name: "User",
    email: "",
    initials: "U",
  });

  useEffect(() => {
    const userData = getStoredJson<{
      fullName?: string;
      email?: string;
      role?: string;
    }>(STORAGE_KEYS.USER);
    if (userData) {
      setUser({
        name: userData.fullName || "User",
        email: userData.email || "",
        initials: (userData.fullName || "U").charAt(0).toUpperCase(),
        role: userData.role,
      });
    }
  }, []);

  const handleProfileClick = () => {
    // Navigate based on role or to a generic profile path
    if (user.role === "ADMIN") navigate(ROUTES.ADMIN_PROFILE);
    else if (user.role === "STAFF")
      navigate(ROUTES.ADMIN_PROFILE); // Staff shares admin profile view often or separate
    else navigate(ROUTES.CLIENT_PROFILE); // Fallback
  };

  const handleLogout = async () => {
    try {
      await signOut();
    } catch (error) {
      console.error('Logout error:', error);
    }

    // Clear user info from localStorage
    removeStoredItem(STORAGE_KEYS.USER);
    window.dispatchEvent(new Event("userDataUpdated"));
    navigate(ROUTES.LOGIN);
  };

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button className="relative h-8 w-8 rounded-full focus:outline-none focus:ring-2 focus:ring-teal-500 focus:ring-offset-2">
          <Avatar className="h-8 w-8 transition-opacity hover:opacity-90">
            <AvatarImage src="/avatars/01.png" alt={user.name} />
            <AvatarFallback className="bg-slate-900 text-white font-medium">
              {user.initials}
            </AvatarFallback>
          </Avatar>
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent className="w-56" align="end" forceMount>
        <DropdownMenuLabel className="font-normal">
          <div className="flex flex-col space-y-1">
            <p className="text-sm font-medium leading-none">{user.name}</p>
            <p className="text-xs leading-none text-muted-foreground">
              {user.email}
            </p>
          </div>
        </DropdownMenuLabel>
        <DropdownMenuSeparator />
        <DropdownMenuGroup>
          <DropdownMenuItem
            onClick={handleProfileClick}
            className="cursor-pointer"
          >
            <User className="mr-2 h-4 w-4" />
            <span>Profile</span>
          </DropdownMenuItem>
          <DropdownMenuItem className="cursor-pointer">
            <Settings className="mr-2 h-4 w-4" />
            <span>Settings</span>
          </DropdownMenuItem>
        </DropdownMenuGroup>
        <DropdownMenuSeparator />
        <DropdownMenuItem
          onClick={handleLogout}
          className="text-red-600 cursor-pointer"
        >
          <LogOut className="mr-2 h-4 w-4" />
          <span>Log out</span>
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

